export const componentTypeMap = {
    'TextBox': FAWInput,
    'Date': FAWInput,
    'DropDownList': FAWSelect,
    'RadioButtonList': FAWRadioGroup,
    'CheckBoxList': FAWCheckboxGroup,
    'Label': FAWTypography,
    'MultiInput': FAWTextarea,
    'DropDownMultiSelect': FAWMultiSelect,
    'DataGridEntry': FAWAgGrid,
    'CustomValueSelector': FAWSelect,
    'Attachment': LiveformUpload,
    'SelfIdentification': FAWInput,
    'CountrySelect': RegionCountrySelect,
    'KeyPersonnel': KeyPersonnel,
    'PSACompany': PSACompany,
    'ScormQuestionEditor': ScormCourse,
    'MatrixQuestion': FAWAgGrid,
    'Relationship': FAWInput,
    'ACL': FAWTypography,
    'Button': FAWButton,
    'FormLogin': FAWTypography,
    'FormLoginPage': FAWTypography,
    'CustomFields': FAWInput
};

export const normalizeTypeName = (type) => {
    if (!type || typeof type !== 'string') return type;
    const trimmed = type.trim();

    const aliasMap = {
        TextBoxItemType: 'TextBox',
        DropDownListItemType: 'DropDownList',
        RadioButtonListItemType: 'RadioButtonList',
        CheckBoxListItemType: 'CheckBoxList',
        DropDownMultiSelectItemType: 'DropDownMultiSelect',
        DataGridEntryItemType: 'DataGridEntry',
        CustomValueSelectorItemType: 'CustomValueSelector',
        AttachmentItemType: 'Attachment',
        SelfIdentificationItemType: 'SelfIdentification',
        ScormQuestionEditorItemType: 'ScormQuestionEditor',
        LabelItemType: 'Label',
        MultiSelectItemType: 'CheckBoxList'
    };

    if (aliasMap[trimmed]) return aliasMap[trimmed];

    if (trimmed.endsWith('ItemType')) {
        return trimmed.substring(0, trimmed.length - 'ItemType'.length);
    }

    return trimmed;
};

export const validateFormItem = (item) => {
    if (!item || typeof item !== 'object') {
        console.warn('⚠️ Invalid form item (not an object):', item);
        return false;
    }
    if (!item.Type || typeof item.Type !== 'string') {
        console.warn('⚠️ Form item missing Type property:', item);
        return false;
    }
    return true;
};
