

import { createValidationEngine, ErrorTypes, Severity } from './validationEngine.js';

// ============================================================================
// VALIDATION HELPERS FACTORY
// ============================================================================

/**
 * Creates validation helpers using the validation engine
 * @param {Object} config - Configuration object
 * @returns {Object} Validation helpers
 */
export const createValidationHelpers = (config = {}) => {
    const {
        formItems = [],
        answers = {},
        visibilityState = {},
        setFieldErrors = () => {},
        allFileData = {},
        validationMethods = {},
        getLatestAnswers = () => answers,
        options = {}
    } = config;


    // Create validation engine
    const validationEngine = createValidationEngine({
        formItems,
        answers,
        visibilityState,
        options
    });

    // ============================================================================
    // UTILITY FUNCTIONS
    // ============================================================================


    // ============================================================================
    // CORE VALIDATION METHODS
    // ============================================================================

    /**
     * Validates all form answers using the new engine
     * @returns {Array} Array of error messages
     */
    const validateAnswers = async (constructedFormItems = null) => {
        try {
            const formItemsToValidate = constructedFormItems || formItems;
            const latestAnswers = getLatestAnswers();

            validationEngine.clearErrors();
            validationEngine.clearCache();
            setFieldErrors({});

            const formResult = validationEngine.validateForm({
                formItems: formItemsToValidate,
                answers: latestAnswers,
                visibilityState
            });

            const errorManager = validationEngine.getErrors();
            const fieldErrors = {};

            Object.entries(errorManager.fieldErrors).forEach(([fieldName, errors]) => {
                if (errors.length > 0) {
                    fieldErrors[fieldName] = errors[0].message;
                }
            });

            setFieldErrors(fieldErrors);

            const tableDataErrors = await validateTableData();
            const attachmentErrors = await validateAttachments();
            await validateScormCompletion(formItemsToValidate);
            const generalErrors = await checkForValidationErrors();

            const allErrors = validationEngine.formatErrors();

            const businessRuleErrors = [
                ...tableDataErrors.map(errorObj => {
                    if (typeof errorObj === 'string') {
                        return { field: 'tableData', message: errorObj, type: 'business_rule' };
                    } else {
                        return { field: errorObj.field || 'tableData', message: errorObj.message, type: 'business_rule' };
                    }
                }),
                ...attachmentErrors.map(msg => ({ field: 'attachments', message: msg, type: 'business_rule' })),
                ...generalErrors.map(msg => ({ field: 'general', message: msg, type: 'business_rule' }))
            ];

            const allStructuredErrors = [...allErrors, ...businessRuleErrors];
            const uniqueErrors = [];
            const seenErrors = new Set();

            allStructuredErrors.forEach(error => {
                const errorKey = `${error.field}:${error.message}`;
                if (!seenErrors.has(errorKey)) {
                    seenErrors.add(errorKey);
                    uniqueErrors.push(error);
                }
            });

            return uniqueErrors;

        } catch (error) {
            return [{ field: 'system', message: `Validation error: ${error.message}`, type: 'system_error' }];
        }
    };




    /**
     * Validates attachments using registered validation methods (direct approach)
     * Uses the same pattern as KeyPersonnel, PSACompany, CountrySelect
     * @returns {Promise<Array>} Promise resolving to array of error messages
     */
    const validateAttachments = async () => {
        try {
            const errors = [];

            // Check for registered attachment validation methods
            const checkAttachmentValidationMethods = (items) => {
                if (!Array.isArray(items)) {
                    return;
                }
                let hasFile = false;
                items.forEach(item => {
                    hasFile = false;
                    if (item.Type === 'AttachmentItemType' ||
                        item.Name?.toLowerCase().includes('attachment') ||
                        item.Text?.toLowerCase().includes('attachment')) {
                        const itemName = item.Name;
                        if (validationMethods[itemName] && typeof validationMethods[itemName] === 'function') {
                            try {
                                const validationResult = validationMethods[itemName]();
                                if (validationResult) {
                                    errors.push(validationResult);
                                }
                            } catch (error) {
                                errors.push(`Validation error for ${item.HtmlStrippedText || item.Name}: ${error.message}`);
                            }
                        } else if (item.Required === 'true' || item.Required === true) {

                            const fileDataKey = `questionnaireViewer_${itemName}`;
                            const uploadedFiles = allFileData?.[fileDataKey] || [];
                            if (uploadedFiles.length > 0) {
                                uploadedFiles.forEach(file => {
                                    if (file && file.description && file.description.includes(itemName)) {
                                        hasFile = true;
                                    }
                                });
                            } else {
                                const message = `Required attachment '${item.HtmlStrippedText || item.Name}' is not provided.`;
                                errors.push(message);
                            }

                            if (!hasFile) {
                                const message = `Required attachment '${item.HtmlStrippedText || item.Name}' is not provided.`;
                                errors.push(message);
                            }
                        }
                    }

                    // Check nested form items
                    if (item.FormItems && Array.isArray(item.FormItems)) {
                        checkAttachmentValidationMethods(item.FormItems);
                    }
                });
            };

            if (!Array.isArray(formItems)) {
                return [];
            }

            checkAttachmentValidationMethods(formItems);


            // Update field errors for UI
            if (errors.length > 0) {
                const fieldErrors = {};
                errors.forEach(error => {
                    if (error.metadata?.field) {
                        fieldErrors[error.metadata.field] = error.message;
                    }
                });
                setFieldErrors(prev => ({ ...prev, ...fieldErrors }));
            }

            const errorMessages = errors.map(error => error.message);

            return errorMessages;

        } catch (error) {
            return [`Attachment validation error: ${error.message}`];
        }
    };

    /**
     * Validates SCORM completion using the validation engine business rule
     * Errors are added to the error manager and will be picked up by formatErrors()
     * @param {Array} latestFormItems - The latest form items (from constructed payload)
     * @returns {Promise<void>}
     */
    const validateScormCompletion = async (latestFormItems = null) => {
        try {
            const itemsToValidate = latestFormItems || formItems;
            const latestAnswers = getLatestAnswers();

            // Execute SCORM completion business rule
            // Errors are automatically added to the validation engine's error manager
            validationEngine.validateBusinessRules({
                formItems: itemsToValidate,
                answers: latestAnswers,
                rules: ['scormCompletion'],
                visibilityState
            });

        } catch (error) {
            console.error('SCORM completion validation error:', error);
        }
    };

    /**
     * Validates table data for PSACompany, KeyPersonnel, and CountrySelect
     * Uses registered validation methods directly (no business rule engine)
     * @returns {Promise<Array>} Promise resolving to array of error messages
     */
    const validateTableData = async () => {
        try {
            const errors = [];

            // Validate KeyPersonnel
            if (validationMethods.validateKeyPersonnel && typeof validationMethods.validateKeyPersonnel === 'function') {
                try {
                    const keyPersonnelResult = validationMethods.validateKeyPersonnel();
                    if (keyPersonnelResult) {
                        errors.push(keyPersonnelResult);
                    }
                } catch (error) {
                    errors.push(`KeyPersonnel validation error: ${error.message}`);
                }
            }

            // Validate PSACompany
            if (validationMethods.validatePSACompany && typeof validationMethods.validatePSACompany === 'function') {
                try {
                    const psaCompanyResult = validationMethods.validatePSACompany();
                    if (psaCompanyResult) {
                        errors.push(psaCompanyResult);
                    }
                } catch (error) {
                    errors.push(`PSACompany validation error: ${error.message}`);
                }
            }

            // Validate CountrySelect
            if (validationMethods.validateCountrySelect && typeof validationMethods.validateCountrySelect === 'function') {
                try {
                    const countrySelectResult = validationMethods.validateCountrySelect();
                    if (countrySelectResult) {
                        errors.push(countrySelectResult);
                    }
                } catch (error) {
                    errors.push(`CountrySelect validation error: ${error.message}`);
                }
            }

            return errors;

        } catch (error) {
            return [`Table data validation error: ${error.message}`];
        }
    };

    /**
     * Checks for general validation errors (replaces legacy CheckForValidationErrors)
     * @returns {Promise<Array>} Promise resolving to array of error messages
     */
    const checkForValidationErrors = async () => {
        try {
            // Ensure formItems is an array
            if (!Array.isArray(formItems)) {
                return [];
            }

            // Check for highlighted items (validation errors from server)
            const highlightedErrors = [];
            const processFormItems = (items) => {
                if (!Array.isArray(items)) {
                    return;
                }
                items.forEach(formItem => {
                    if (formItem.Highlight === true) {
                        const errorMessage = formItem.ValidationMessage ||
                            `Validation error for question '${formItem.HtmlStrippedText || formItem.Name}'`;
                        highlightedErrors.push(errorMessage);
                    }

                    if (formItem.FormItems && Array.isArray(formItem.FormItems)) {
                        processFormItems(formItem.FormItems);
                    }
                });
            };

            processFormItems(formItems);

            return highlightedErrors;

        } catch (error) {
            return [`General validation error: ${error.message}`];
        }
    };


    // ============================================================================
    // ADVANCED VALIDATION METHODS
    // ============================================================================





    // ============================================================================
    // VALIDATION METHOD REGISTRATION
    // ============================================================================

    /**
     * Registers a validation method for a specific component type
     * @param {string} componentType - The component type (KeyPersonnel, PSACompany, CountrySelect)
     * @param {Function} validationMethod - The validation method function
     */
    const registerValidationMethod = (componentType, validationMethod) => {
        if (typeof validationMethod !== 'function') {
            console.error(`Invalid validation method for ${componentType}: must be a function`);
            return;
        }

        switch (componentType) {
            case 'KeyPersonnel':
                validationMethods.validateKeyPersonnel = validationMethod;
                break;
            case 'PSACompany':
                validationMethods.validatePSACompany = validationMethod;
                break;
            case 'CountrySelect':
            case 'RegionCountrySelect':
                validationMethods.validateCountrySelect = validationMethod;
                break;
            default:
                console.warn(`Unknown component type for validation method registration: ${componentType}`);
        }

    };

    // ============================================================================
    // RETURN VALIDATION HELPERS
    // ============================================================================

    return {
        validateAnswers,
        validateAttachments,
        validateScormCompletion,
        validateTableData,
        checkForValidationErrors,
        registerValidationMethod,
        validationEngine
    };
};
// ============================================================================
// EXPORTS
// ============================================================================

export default createValidationHelpers;

