import { QuestionnaireService } from '../services/QuestionnaireService';
import { safeGetAnswer, safeGetAnswerArray } from '../utils/htmlParser';
import { scrollToMainErrorBox } from './scrollToError';

/**
 * Helper function to get user-friendly field display name
 */
export const getFieldDisplayName = (fieldName, formItems) => {
    if (!fieldName || fieldName === 'Unknown Field') {
        return 'Unknown Field';
    }
    
    // Special cases for business rule fields
    const businessRuleNames = {
        'ownership': 'Ownership Percentage',
        'attachments': 'File Attachments',
        'scorm': 'SCORM Completion',
        'general': 'General Validation',
        'system': 'System Error',
        'tableData': 'Table Data',
        'keyPersonnel': 'Key Personnel',
        'psaCompany': 'PSA Company',
        'countrySelect': 'Country Select'
    };
    
    if (businessRuleNames[fieldName]) {
        return businessRuleNames[fieldName];
    }
    
    // Find the field in form items to get the display text
    const formItem = formItems.find(item => item.Name === fieldName);
    if (formItem && formItem.HtmlStrippedText) {
        return formItem.HtmlStrippedText;
    }
    if (formItem && formItem.Text) {
        return formItem.Text;
    }
    
    // Fallback to field name with proper formatting
    return fieldName.replace(/([A-Z])/g, ' $1').replace(/^./, str => str.toUpperCase()).trim();
};

export const createFormActions = ({
    answerId,
    formData,
    language,
    answers,
    setIsSaving,
    setIsSubmitting,
    setIsValidating,
    setSaveStatus,
    setIsExporting,
    setShowExportModal,
    validateAnswers,
    validateLegacyChecks,
    fieldErrors,
    dependencyMap,
    formItems,
    handleDependencyChange,
    questionnaireVersionId,
    responseContainerId,
    showSubmitConfirmation,
    showToast,
    allFileData
}) => {


    const saveAllAnswers = async (skipRedirect = false) => {
        setIsSaving(true);
        
        // Clear any previous error alerts immediately when user clicks save
        setSaveStatus({ message: '', type: '', errors: [] });
        
        showToast?.({ message: 'Saving all answers...', type: 'info', duration: 30000 });
        
        try {
            // STEP 1: Construct payload first
            const completeFormItems = constructPayload();
            
            
            
            const response = await QuestionnaireService.saveAllAnswers(answerId, responseContainerId, completeFormItems, language);
            
            if (response?.success) {
                if (response?.redirectUrl && !skipRedirect) {
                    showToast?.({ message: 'All answers saved successfully! Redirecting...', type: 'success', duration: 30000 });
                    // Show success toast for 2 seconds before redirecting
                    setTimeout(() => {
                        window.location.href = response.redirectUrl;
                    }, 2000);
                } else if (response?.redirectUrl && skipRedirect) {
                    // Save successful but skip redirect (e.g., for export)
                    showToast?.({ message: 'All answers saved successfully!', type: 'success', duration: 5000 });
                } else {
                    // No redirect URL - show retry options
                    showToast?.({ 
                        message: 'Save completed but no redirect URL provided. Would you like to retry?', 
                        type: 'warning',
                        duration: 0, // Don't auto-close
                        actions: [
                            {
                                label: 'Cancel',
                                variant: 'secondary',
                                onClick: () => {
                                    showToast?.({ message: '', type: 'info', open: false });
                                }
                            },
                            {
                                label: 'Retry',
                                variant: 'primary',
                                onClick: () => {
                                    showToast?.({ message: '', type: 'info', open: false });
                                    // Retry the save operation
                                    saveAllAnswers();
                                }
                            }
                        ],
                        persistent: true
                    });
                }
            } else {
                // Handle save failure with cancel and retry options
                const errorMessage = response?.error || 'Batch save failed';
                
                // If skipRedirect is true (called from export), throw error to stop export
                if (skipRedirect) {
                    setIsSaving(false);
                    throw new Error(errorMessage);
                }
                
                // Otherwise show error toast with retry options (normal save flow)
                showToast?.({ 
                    message: `Failed to save form: ${errorMessage}`, 
                    type: 'error',
                    duration: 0, // Don't auto-close
                    actions: [
                        {
                            label: 'Cancel',
                            variant: 'secondary',
                            onClick: () => {
                                showToast?.({ message: '', type: 'info', open: false });
                            }
                        },
                        {
                            label: 'Retry',
                            variant: 'primary',
                            onClick: () => {
                                showToast?.({ message: '', type: 'info', open: false });
                                // Retry the save operation
                                saveAllAnswers();
                            }
                        }
                    ],
                    persistent: true
                });
                return; // Exit early to avoid the catch block
            }
        } catch (error) {
            // If skipRedirect is true (called from export), re-throw error to stop export
            if (skipRedirect) {
                setIsSaving(false);
                throw error;
            }
            
            // Otherwise show error toast with retry option (normal save flow)
            showToast?.({ 
                message: `Failed to save form: ${error.message}`, 
                type: 'error',
                duration: 0, // Don't auto-close
                actions: [
                    {
                        label: 'Cancel',
                        variant: 'secondary',
                        onClick: () => {
                            showToast?.({ message: '', type: 'info', open: false });
                        }
                    },
                    {
                        label: 'Retry',
                        variant: 'primary',
                        onClick: () => {
                            showToast?.({ message: '', type: 'info', open: false });
                            // Retry the save operation
                            saveAllAnswers();
                        }
                    }
                ],
                persistent: true
            });
        } finally {
            setIsSaving(false);
        }
    };

    const showConfirmation = (message = 'Are you sure you want to submit this questionnaire?') => {
        if (showSubmitConfirmation) {
            showSubmitConfirmation(message);
        }
    };

    const handleSubmit = async () => {
        try {
            // Show Material-UI confirmation dialog - validation will happen in performSubmit
            // showConfirmation('Are you sure you want to submit this questionnaire?'); // Disabled per request
            // Directly perform submit when confirmation is skipped
            await performSubmit();
        } catch (error) {
            // Show error toast with cancel and retry options
            showToast?.({ 
                message: `Submit failed: ${error.message}`, 
                type: 'error',
                duration: 0, // Don't auto-close
                actions: [
                    {
                        label: 'Cancel',
                        variant: 'secondary',
                        onClick: () => {
                            showToast?.({ message: '', type: 'info', open: false });
                        }
                    },
                    {
                        label: 'Retry',
                        variant: 'primary',
                        onClick: () => {
                            showToast?.({ message: '', type: 'info', open: false });
                            // Retry the submit operation
                            handleSubmit();
                        }
                    }
                ],
                persistent: true
            });
        }
    };

    const performSubmit = async () => {
        try {
            // Show validation loader
            setIsValidating(true);
            
            // Clear any previous error alerts immediately when user clicks submit
            setSaveStatus({ message: '', type: '', errors: [] });
            
            // STEP 1: Construct payload first
            const completeFormItems = constructPayload();
            
            
            // STEP 3: Validate form data using constructed payload (has latest answers)
            const validationErrors = await validateAnswers(completeFormItems);
            
            // Clear validation loader after validation completes
            setIsValidating(false);
            if (validationErrors.length > 0) {
                // Format errors as key-value pairs for better display
                const errorDetails = validationErrors.map(error => {
                    const fieldDisplayName = getFieldDisplayName(error.field, formItems);
                    return `<span class="field-name">• ${fieldDisplayName}:</span> <span class="error-message">${error.message}</span>`;
                }).join('<br/>');
                
                // Create structured error data for clickable errors
                const structuredErrors = validationErrors.map(error => {
                    const fieldDisplayName = getFieldDisplayName(error.field, formItems);
                    return {
                        field: error.field || null,
                        message: `${fieldDisplayName}: ${error.message}`,
                        type: error.type
                    };
                });
                
                setSaveStatus({ 
                    message: `Validation Errors:\n${errorDetails}`, 
                    type: 'error',
                    errors: structuredErrors // Add structured errors for scroll-to functionality
                });
                
                // Scroll to the main error box after a short delay to ensure it's rendered
                setTimeout(() => {
                    scrollToMainErrorBox();
                }, 100);
                
                setIsSubmitting(false);
                return;
            }
            
            // Start submission process
            setIsSubmitting(true);
            showToast?.({ message: 'Submitting form...', type: 'info', duration: 30000 });
            const response = await QuestionnaireService.submitQuestionnaire(answerId, responseContainerId, questionnaireVersionId, completeFormItems, language);
            
            
            if (response?.success) {
                // Clear any previous error alerts
                setSaveStatus({ message: '', type: '', errors: [] });
                
                if (response?.redirectUrl) {
                    showToast?.({ message: 'Form submitted successfully! Redirecting...', type: 'success', duration: 30000 });
                    // Show success toast for 2 seconds before redirecting
                    setTimeout(() => {
                        window.location.href = response.redirectUrl;
                    }, 2000);
                } else {
                    // No redirect URL - show retry options
                    showToast?.({ 
                        message: 'Submit completed but no redirect URL provided. Would you like to retry?', 
                        type: 'warning',
                        duration: 0, // Don't auto-close
                        actions: [
                            {
                                label: 'Cancel',
                                variant: 'secondary',
                                onClick: () => {
                                    showToast?.({ message: '', type: 'info', open: false });
                                }
                            },
                            {
                                label: 'Retry',
                                variant: 'primary',
                                onClick: () => {
                                    showToast?.({ message: '', type: 'info', open: false });
                                    // Retry the submit operation
                                    performSubmit();
                                }
                            }
                        ],
                        persistent: true
                    });
                }
            } else {
                // Handle backend validation errors or submission failure
                if (response?.validationErrors && response.validationErrors.length > 0) {
                    // Backend validation errors - format and display them
                    const errorDetails = response.validationErrors.map(error => {
                        const fieldDisplayName = getFieldDisplayName(error.field, formItems);
                        return `<span class="field-name">• ${fieldDisplayName}:</span> <span class="error-message">${error.message}</span>`;
                    }).join('<br/>');
                    
                    // Create structured error data for clickable errors
                    const structuredErrors = response.validationErrors.map(error => {
                        const fieldDisplayName = getFieldDisplayName(error.field, formItems);
                        return {
                            field: error.field || null,
                            message: `${fieldDisplayName}: ${error.message}`,
                            type: error.type || 'backend'
                        };
                    });
                    
                    setSaveStatus({ 
                        message: `Backend Validation Errors:<br/>${errorDetails}`, 
                        type: 'error',
                        errors: structuredErrors // Add structured errors for scroll-to functionality
                    });
                    
                    // Scroll to the main error box after a short delay to ensure it's rendered
                    setTimeout(() => {
                        scrollToMainErrorBox();
                    }, 100);
                } else {
                    // System error - show retry options
                    const errorMessage = response?.error || 'Submission failed';
                    showToast?.({ 
                        message: `Failed to submit form: ${errorMessage}`, 
                        type: 'error',
                        duration: 0, // Don't auto-close
                        actions: [
                            {
                                label: 'Cancel',
                                variant: 'secondary',
                                onClick: () => {
                                    showToast?.({ message: '', type: 'info', open: false });
                                }
                            },
                            {
                                label: 'Retry',
                                variant: 'primary',
                                onClick: () => {
                                    showToast?.({ message: '', type: 'info', open: false });
                                    // Retry the submit operation
                                    performSubmit();
                                }
                            }
                        ],
                        persistent: true
                    });
                }
                setIsSubmitting(false);
                return; // Exit early to avoid the catch block
            }
        } catch (error) {
            // Check for session expired specifically
            if (error.response?.status === 401 || 
                error.response?.status === 403 || 
                error.message?.toLowerCase().includes('session') ||
                error.message?.toLowerCase().includes('unauthorized')) {
                showToast?.({ 
                    message: 'Session expired. Please refresh the page and try again.', 
                    type: 'error',
                    duration: 0, // Don't auto-close
                    actions: [
                        {
                            label: 'Cancel',
                            variant: 'secondary',
                            onClick: () => {
                                showToast?.({ message: '', type: 'info', open: false });
                            }
                        },
                        {
                            label: 'Refresh Page',
                            variant: 'primary',
                            onClick: () => {
                                window.location.reload();
                            }
                        }
                    ],
                    persistent: true
                });
            } else {
                // Show error toast with retry option for other errors
                showToast?.({ 
                    message: `Failed to submit form: ${error.message}`, 
                    type: 'error',
                    duration: 0, // Don't auto-close
                    actions: [
                        {
                            label: 'Cancel',
                            variant: 'secondary',
                            onClick: () => {
                                showToast?.({ message: '', type: 'info', open: false });
                            }
                        },
                        {
                            label: 'Retry',
                            variant: 'primary',
                            onClick: () => {
                                showToast?.({ message: '', type: 'info', open: false });
                                // Retry the submit operation
                                performSubmit();
                            }
                        }
                    ],
                    persistent: true
                });
            }
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleExportForm = async () => {
        setIsExporting(true);
        try {
            // Save form first before exporting (skip redirect)
            showToast?.({ message: 'Saving form before export...', type: 'info', duration: 30000 });
            await saveAllAnswers(true); // Pass true to skip redirect
            
            if (!questionnaireVersionId || questionnaireVersionId === "0" || !responseContainerId || responseContainerId === "0") {
                throw new Error('Missing required context data for export. Please refresh the page and try again.');
            }

            const previewQueryString = `Report=PreviewPdf&QVId=${questionnaireVersionId}&QAId=${answerId}&RcId=${responseContainerId}`;
            const encryptedQueryString = await QuestionnaireService.encryptQueryString(previewQueryString);
            const generatePreviewPdfUrl = `/Webform/Research/DownloadForm.aspx?${encryptedQueryString}`;
            window.open(window.location.origin + generatePreviewPdfUrl);
            showToast?.({ message: 'Form export initiated', type: 'info', duration: 30000 });
        } catch (error) {
            showToast?.({ 
                message: `Failed to export form: ${error.message}`, 
                type: 'error',
                duration: 0, // Don't auto-close
                actions: [
                    {
                        label: 'Cancel',
                        variant: 'secondary',
                        onClick: () => {
                            showToast?.({ message: '', type: 'info', open: false });
                        }
                    },
                    {
                        label: 'Retry',
                        variant: 'primary',
                        onClick: () => {
                            showToast?.({ message: '', type: 'info', open: false });
                            // Retry the export operation
                            handleExportForm();
                        }
                    }
                ],
                persistent: true
            });
        } finally {
            setIsExporting(false);
        }
    };

    const handleExportBlankForm = () => {
        setShowExportModal(true);
    };

    const handleExportBlankFormConfirm = async (includeAnswers = false) => {
        setShowExportModal(false);
        setIsExporting(true);

        try {
            if (!questionnaireVersionId || questionnaireVersionId === "0") {
                throw new Error('Missing questionnaire version ID for export. Please refresh the page and try again.');
            }

            let previewQueryString;

            if (includeAnswers) {
                // Save form first before exporting with answers (skip redirect)
                showToast?.({ message: 'Saving form before export...', type: 'info', duration: 30000 });
                await saveAllAnswers(true); // Pass true to skip redirect
                
                if (!responseContainerId || responseContainerId === "0") {
                    throw new Error('Missing response container ID for export with answers. Please refresh the page and try again.');
                }
                previewQueryString = `Report=PreviewPdf&QVId=${questionnaireVersionId}&QAId=${answerId}&RcId=${responseContainerId}`;
            } else {
                // Export blank form without answers - no saving needed
                previewQueryString = `Report=GeneratePdf&QVId=${questionnaireVersionId}&answers=false`;
            }

            const encryptedQueryString = await QuestionnaireService.encryptQueryString(previewQueryString);
            const generatePreviewPdfUrl = `/Webform/Research/DownloadForm.aspx?${encryptedQueryString}`;
            window.open(window.location.origin + generatePreviewPdfUrl);
            showToast?.({
                message: `Form export initiated (${includeAnswers ? 'with' : 'without'} answers)`,
                type: 'info',
                duration: 30000
            });
        } catch (error) {
            showToast?.({ 
                message: `Failed to export form: ${error.message}`, 
                type: 'error',
                duration: 0, // Don't auto-close
                actions: [
                    {
                        label: 'Cancel',
                        variant: 'secondary',
                        onClick: () => {
                            showToast?.({ message: '', type: 'info', open: false });
                        }
                    },
                    {
                        label: 'Retry',
                        variant: 'primary',
                        onClick: () => {
                            showToast?.({ message: '', type: 'info', open: false });
                            // Retry the blank form export operation
                            handleExportBlankFormConfirm(includeAnswers);
                        }
                    }
                ],
                persistent: true
            });
        } finally {
            setIsExporting(false);
        }
    };

    // Build complete form structure for validation and submission
    const constructPayload = () => {
        Object.keys(dependencyMap).forEach(parentName => {
            const parentValue = answers[parentName] || safeGetAnswer({ Name: parentName }, '', answers);
            handleDependencyChange(parentName, parentValue);
        });

        // Recursive function to process FormItems and their nested children
        const processFormItem = (item) => {
            const itemName = item.Name?.trim();
            if (!itemName) return null;

            // Get current answer value for this item
            // CRITICAL: For submit to work, we must read from item.Answers array (updated by FormRenderer)
            // The answers state object may be stale, but item.Answers is always current
            let currentValue;
            if (item.Type === 'CheckBoxList' || item.Type === 'DropDownMultiSelect') {
                // For multi-select, read from item.Answers array first (source of truth)
                if (item.Answers && Array.isArray(item.Answers) && item.Answers.length > 0) {
                    // Extract non-deleted values from Answers array
                    currentValue = item.Answers
                        .filter(ans => ans && !ans.Deleted && ans.Selected !== false)
                        .map(ans => ans.Answer || ans.Value || '')
                        .filter(val => val !== null && val !== undefined && val !== '');
                } else {
                    // Fallback to answers state if no Answers array
                    const directAnswer = answers[itemName];
                    currentValue = Array.isArray(directAnswer) ? directAnswer : safeGetAnswerArray(item, ',', answers);
                }
            } else {
                // For single-select, read from item.Answers array first
                if (item.Answers && Array.isArray(item.Answers) && item.Answers.length > 0) {
                    const firstAnswer = item.Answers.find(ans => ans && !ans.Deleted);
                    currentValue = firstAnswer ? (firstAnswer.Answer || firstAnswer.Value || '') : (answers[itemName] || safeGetAnswer(item, '', answers));
                } else {
                    currentValue = answers[itemName] || safeGetAnswer(item, '', answers);
                }
            }
            
            // For file uploads, get latest data from centralized file data
            if (item.Type === 'AttachmentItemType' || item.Type === 'Attachment' || item.Name?.toLowerCase().includes('attachment')) {
                // Get latest file data from centralized source
                const latestFiles = allFileData?.[itemName];
                if (latestFiles && latestFiles.length > 0) {
                    currentValue = latestFiles; // Use latest files from API
                }
            }
            
            // Build Answers array with current value, preserving existing answer IDs
            const answersArray = [];
            
            if (currentValue !== null && currentValue !== undefined && currentValue !== '') {
                // Check if this item already has existing answers with IDs
                const existingAnswers = item.Answers || [];
                
                // Handle multi-select fields (DropDownMultiSelect, CheckBoxList) - create multiple Answer objects
                // Backend will create separate database records for each selected value.
                // Each Answer object preserves its existing ID for proper update/delete tracking.
                // Marked as Deleted=true if unselected, Deleted=false if newly added or still selected.
                if ((item.Type === 'DropDownMultiSelect' || item.Type === 'CheckBoxList') && Array.isArray(currentValue)) {
                    // Normalize current values to strings
                    const selectedValues = currentValue
                        .filter(val => val !== null && val !== undefined && val !== '')
                        .map(val => String(val));
                    
                    // Process all existing answers to handle deletions
                    existingAnswers.forEach((existingAnswer) => {
                        if (existingAnswer && !existingAnswer.Deleted) {
                            const answerValue = String(existingAnswer.Answer || existingAnswer.Value || '');
                            const isSelected = selectedValues.includes(answerValue);
                            
                            answersArray.push({
                                Id: existingAnswer.Id || 0,
                                Answer: answerValue,
                                Value: answerValue,
                                Selected: isSelected,
                                Deleted: !isSelected // Mark as deleted if not in selected values
                            });
                        }
                    });
                    
                    // Add new answers for values that don't have existing answers
                    selectedValues.forEach((val) => {
                        const hasExistingAnswer = existingAnswers.some(
                            ans => ans && !ans.Deleted && (String(ans.Answer || ans.Value || '') === val)
                        );
                        if (!hasExistingAnswer) {
                            answersArray.push({
                                Id: 0, // New answer
                                Answer: val,
                                Value: val,
                                Selected: true,
                                Deleted: false
                            });
                        }
                    });
                } 
                else {
                    // Single value fields or non-array values
                    const existingAnswer = existingAnswers.find(ans => ans && !ans.Deleted);
                    
                    // Legacy behavior - send filenames as strings (not file objects)
                    let answerValue = currentValue;
                    if (item.Type === 'AttachmentItemType' || item.Type === 'Attachment' || item.Name?.toLowerCase().includes('attachment')) {
                        // For attachments, backend expects simple string filenames (legacy behavior)
                        if (Array.isArray(currentValue)) {
                            // Multiple files - join filenames with comma separator
                            const fileNames = currentValue
                                .filter(file => file && file.name)
                                .map(file => file.name);
                            answerValue = fileNames.join(',');
                        } else if (typeof currentValue === 'object' && currentValue.name) {
                            // Single file object - extract filename only
                            answerValue = currentValue.name;
                        } else if (typeof currentValue === 'string') {
                            // Already a string filename
                            answerValue = currentValue;
                        } else {
                            // Fallback - convert to string
                            answerValue = String(currentValue);
                        }
                    }
                    
                    answersArray.push({
                        Id: existingAnswer ? existingAnswer.Id : 0, // Preserve existing ID or use 0 for new
                        Answer: String(answerValue), // Ensure it's always a string for backend compatibility (backend expects string)
                        Selected: true,
                        Deleted: false
                    });
                }
            }

            // Process nested FormItems recursively
            let processedFormItems = [];
            if (item.FormItems && Array.isArray(item.FormItems)) {
                processedFormItems = item.FormItems
                    .map(nestedItem => processFormItem(nestedItem))
                    .filter(processedItem => processedItem !== null);
            }

            // Return complete form item with all properties including nested FormItems
            return {
                ...item, // All form item properties (Type, Required, ParentName, etc.)
                Name: itemName,
                NameRaw: item.NameRaw || itemName, // Include NameRaw for backend to use original name without language suffix
                Answers: answersArray, // Include Answers array with current values and preserved IDs
                FormItems: processedFormItems // Include processed nested FormItems with their answers
            };
        };

        // Build complete form structure with all properties
        const completeFormItems = formItems
            .map(item => processFormItem(item))
            .filter(item => item !== null);

        return completeFormItems;
    };


    return {
        saveAllAnswers,
        handleSubmit,
        performSubmit,
        handleExportForm,
        handleExportBlankForm,
        handleExportBlankFormConfirm,
        constructPayload
    };
};
