import React, { useEffect, useState } from "react";
import axios from "axios";
import Nav from "react-bootstrap/Nav";
import Navbar from "react-bootstrap/Navbar";
import Scrollspy from "react-scrollspy";
import { displayText, defaultGeneralInfo, defaultQuestionText } from "../../constants/index";

import "./questionnaireHeader.css";

function QuestionnaireHeader(props) {
  const [headers, setHeaders] = useState([]);
   const [headerIds, setHeaderIds] = useState([]);
   const [displayCodes, setDisplayCodes] = useState([]);
   const [currentLanguage, setCurrentLanguage] = useState("");

  useEffect(() => {
    // FIX: Wait for pageHeaders to be rendered, then query only within the current React tree
    const timeout = setTimeout(() => {
      const atlasContainer = document.getElementById('atlasFormRendererContainer');
      const elems = atlasContainer 
        ? atlasContainer.querySelectorAll("[id*='pageHeader']")
        : [];

      const toRender = [];
      const headIds = [];

     const fetchDisplayCodes = async () => {
        try {
          const { data } = await axios.get(`/Questionnaire/GetDisplayCodes`);
          setDisplayCodes(data);
        } catch (error) {
          console.error('Error fetching display codes:', error);
        }
     };

     const fetchCurrentLanguage = async () => {
        try {
          const { data } = await axios.get('/Questionnaire/GetCurrentLanguage');
          setCurrentLanguage(data.language);
        } catch (error) {
          console.error('Error fetching current language:', error);
        }
     }

    elems.forEach((node, index) => {
      
      headIds.push(node.id);
      toRender.push(
        <Nav.Item key={node.id}>
          <Nav.Link
            href={`#${node.id}`}
            onClick={event => scrollToElem(event, node)}
          >
            {node.textContent}
          </Nav.Link>
        </Nav.Item>
      );
    });

     fetchCurrentLanguage();
     fetchDisplayCodes();
    setHeaders(toRender);
    setHeaderIds(headIds);
    }, 100); // Wait 100ms for form items to render
    
    return () => clearTimeout(timeout);
  }, []);

   const findGeneralInfo = (id) => {
      if (displayCodes) {
         const dispCode = displayCodes.find(x => x.Id === id);
         const result = dispCode ? dispCode.Description : defaultGeneralInfo[id];
         return result;
      }

      const result = defaultGeneralInfo[id];
      return result;
   }

   const findText = id => {
      if (displayCodes) {
         const dispCode = displayCodes.find(x => x.Id === id);
         const result = dispCode ? dispCode.Label : defaultQuestionText[id];
         return result;
      }

      const result = displayText[id];
      return result;
   };



  const scrollToElem = (event, elem) => {
    event.preventDefault();

    elem.scrollIntoView({
      behavior: "smooth",
      block: "center"
    });
  };

  return (
    <Navbar bg="dark" variant="dark" expand="lg" fixed="top">
      <Navbar.Toggle aria-controls="responsive-navbar-nav" />
      <Navbar.Collapse>
        <Nav activeKey={null}>
          {headerIds.length > 0 ? (
            <Scrollspy
              className="navbar-nav"
              items={headerIds}
              currentClassName="active"
              componentTag={"div"}
            >
              {headers}
            </Scrollspy>
          ) : null}
        </Nav>
      </Navbar.Collapse>
    </Navbar>
  );
}

QuestionnaireHeader.propTypes = {};

export default QuestionnaireHeader;
