import axios from 'axios';
import axiosClient from '../../../../Helpers/FetchCsrfToken';

/**
 * Service class for managing questionnaire operations including
 * answer submission, file attachments, and session management
 */
export class QuestionnaireService {
    /**
     * Saves a single answer for a questionnaire item
     * @param {number} questionnaireAnswerId - The questionnaire answer ID
     * @param {string} itemName - The name of the item being answered
     * @param {any} value - The answer value (can be string, number, boolean, or array for multi-select)
     * @param {string} language - The language code
     * @returns {Promise<{success: boolean, data: any}>} Response with success status and data
     */
    static async saveAnswer(questionnaireAnswerId, itemName, value, language) {
        await this.keepSessionAlive();

        try {
            const response = await axiosClient.post('/Questionnaire/SaveAnswer', {
                questionnaireAnswerId,
                name: itemName,
                value: value,
                language: language
            });
            
            if (response.data?.success) {
                return { success: true, data: response.data };
            } else {
                throw new Error(response.data?.error || 'Save failed');
            }
        } catch (error) {
            throw error;
        }
    }

    /**
     * Saves all answers for a questionnaire in a single batch operation
     * @param {number} questionnaireAnswerId - The questionnaire answer ID
     * @param {number} responseContainerId - The response container ID
     * @param {Array} directFormItems - Array of form items to save
     * @param {string} language - The language code
     * @returns {Promise<{success: boolean, data: any, redirectUrl: string}>} Response with success status, data, and redirect URL
     */
    static async saveAllAnswers(questionnaireAnswerId, responseContainerId, directFormItems, language) {
        // Keep session alive before save operation
        await this.keepSessionAlive();
        
        const response = await axiosClient.post('/Questionnaire/SaveAllAnswers', {
            questionnaireAnswerId: questionnaireAnswerId,
            responseContainerId: responseContainerId,
            formItems: directFormItems,
            language: language
        });
        
        if (response.data?.success) {
            return { 
                success: true, 
                data: response.data,
                redirectUrl: response.data.redirectUrl  // Add redirectUrl at top level
            };
        } else {
            throw new Error(response.data?.error || 'Batch save failed');
        }
    }

    /**
     * Submits a completed questionnaire
     * @param {number} questionnaireAnswerId - The questionnaire answer ID
     * @param {number} responseContainerId - The response container ID
     * @param {number} questionnaireVersionId - The questionnaire version ID
     * @param {Array} completeFormItems - Array of all completed form items
     * @param {string} language - The language code
     * @returns {Promise<{success: boolean, data: any, redirectUrl: string}>} Response with success status, data, and redirect URL
     */
    static async submitQuestionnaire(questionnaireAnswerId, responseContainerId, questionnaireVersionId, completeFormItems, language) {
        try {
            await this.keepSessionAlive();
            
            const response = await axiosClient.post('/Questionnaire/SubmitQuestionnaire', {
                questionnaireAnswerId: questionnaireAnswerId,
                responseContainerId: responseContainerId,
                questionnaireVersionId: questionnaireVersionId,
                formItems: completeFormItems,
                language: language
            });
            
            if (response.data?.success) {
                return { 
                    success: true, 
                    data: response.data,
                    redirectUrl: response.data?.redirectUrl 
                };
            } else {
                throw new Error(response.data?.error || 'Submit failed');
            }
        } catch (error) {
            throw error;
        }
    }

    static async encryptQueryString(queryString) {
        try {
            const response = await axiosClient.post('/Questionnaire/EncryptQueryString', {
                queryString: queryString
            });
            
            if (response.data?.success) {
                return response.data.encryptedString;
            } else {
                return queryString;
            }
        } catch (error) {
            return queryString;
        }
    }

    static async reloadFormAfterExport(questionnaireAnswerId, questionnaireVersionId) {
        try {
            await axiosClient.post('/Questionnaire/ReloadFormAfterExport', {
                questionnaireAnswerId: questionnaireAnswerId,
                questionnaireVersionId: questionnaireVersionId
            });
            
        } catch (error) {
            window.location.reload();
        }
    }

    static async keepSessionAlive() {
        try {
            // Call the same endpoint that the legacy keepAlive function uses
            await axios.get('/User/GetUISettingJson');
        } catch (error) {
            // Don't throw error - session keep-alive is non-critical and shouldn't block the main operation
            // Silently fail to avoid disrupting user workflow
        }
    }

    /**
     * Retrieves all attachments for the current response container
     * @returns {Promise<{success: boolean, data: any}>} Response with success status and attachment data
     */
    static async getAllAttachmentsForCurrentResponseContainer() {
        try {
            const response = await axiosClient.post('/Attachment/GetAllAttachmentsForCurrentResponseContainer', {}, {
                headers: {
                    'Content-Type': 'application/json; charset=utf-8',
                }
            });
            
            if (response.data) {
                return { success: true, data: response.data };
            } else {
                throw new Error('Failed to fetch attachments');
            }
        } catch (error) {
            throw new Error(`Failed to fetch attachments: ${error.message || 'Unknown error'}`);
        }
    }

    /**
     * Uploads attachment files for a questionnaire item
     * @param {number} questionnaireAnswerId - The questionnaire answer ID
     * @param {number} responseContainerId - The response container ID
     * @param {string} itemName - The name of the item the attachment belongs to
     * @param {File[]} files - Array of files to upload
     * @param {Object} options - Optional parameters including onProgress callback and description
     * @returns {Promise<{success: boolean, message: string, files: Array}>} Upload result with file details
     */
    static async uploadAttachment(questionnaireAnswerId, responseContainerId, itemName, files, options = {}) {
        try {
            const { onProgress, description } = options;
            const formData = new FormData();
            
            // Add form parameters to match UploadViewModel structure
            formData.append('Name', itemName);
            
            // CRITICAL: The backend automatically prepends "Attached to {itemName}" when description is empty
            // If user provides description, backend appends it as: "Attached to {itemName} - {description}"
            // So we should send empty string when no user description, not add "Attached to" ourselves
            const hasUserDescription = typeof description === 'string' && description.trim().length > 0;
            const standardizedDescription = hasUserDescription ? description : '';
            formData.append('Description', standardizedDescription);
            
            // Add files with the correct parameter name expected by UploadViewModel
            for (let i = 0; i < files.length; i++) {
                formData.append('Files', files[i]);
            }
            
            const response = await axiosClient.post('/Attachment/UploadAttachment', formData, {
                headers: {
                    'Content-Type': 'multipart/form-data',
                },
                onUploadProgress: (progressEvent) => {
                    if (onProgress && progressEvent.total) {
                        const percentCompleted = Math.round((progressEvent.loaded * 100) / progressEvent.total);
                        onProgress(percentCompleted);
                    }
                },
                timeout: options.timeout || 120000
            });
            
            if (response.status === 200 && response.data && response.data.result) {
                const result = response.data.result;
                const uploadedFiles = (result.list || []).map(att => ({
                    id: att.Id,
                    filename: att.Name,
                    name: att.Name,
                    size: att.Size,
                    uploaded: true
                }));
                const rejectedMessage = (result.errors || []).length > 0
                    ? (result.errors || []).map(err => `${err.Name}: ${err.FailureReason}`).join(', ')
                    : null;
                // Partial success: at least one file uploaded; eligible files accepted, ineligible skipped
                const hasUploadedFiles = uploadedFiles.length > 0;
                return {
                    success: hasUploadedFiles,
                    data: response.data,
                    message: rejectedMessage == null
                        ? `${uploadedFiles.length} file${uploadedFiles.length !== 1 ? 's' : ''} uploaded successfully`
                        : rejectedMessage,
                    rejectedMessage: rejectedMessage || null,
                    files: uploadedFiles
                };
            } else {
                throw new Error('Upload failed');
            }
        } catch (error) {
            throw new Error(`File upload failed: ${error.message || 'Unknown error'}`);
        }
    }

    /**
     * Deletes an attachment by ID
     * @param {number} attachmentId - The ID of the attachment to delete
     * @returns {Promise<{success: boolean, data: any}>} Response with success status and data
     */
    static async deleteAttachment(attachmentId) {
        try {
            const response = await axiosClient.post('/Attachment/DeleteAttachment', {
                attachmentId: attachmentId
            });
            
            if (response.data && response.data.success === true) {
                return { success: true, data: response.data };
            } else {
                throw new Error(response.data?.error || response.data?.message || 'Delete failed');
            }
        } catch (error) {
            throw new Error(`Failed to delete attachment: ${error.message || 'Unknown error'}`);
        }
    }

    static async getFileUploadView() {
        try {
            const response = await axios.get('/Attachment/GetFileUploadView');
            
            if (response.data) {
                return { success: true, data: response.data };
            } else {
                throw new Error('Failed to get file upload view');
            }
        } catch (error) {
            throw new Error(`Failed to get file upload view: ${error.message || 'Unknown error'}`);
        }
    }

    /**
     * Retrieves tenant-specific attachment configuration including validation rules
     * @returns {Promise<{success: boolean, data: any}>} Response with attachment configuration
     */
    static async getAttachmentConfig() {
        try {
            const response = await axios.get('/Attachment/GetAttachmentConfig');
            
            if (response.data && response.data.success) {
                return { success: true, data: response.data.data };
            } else {
                throw new Error('Failed to get attachment configuration');
            }
        } catch (error) {
            throw new Error(`Failed to get attachment configuration: ${error.message || 'Unknown error'}`);
        }
    }

    /**
     * Validates a file against tenant-specific rules (async version)
     * @param {File} file - The file to validate
     * @param {Object} options - Optional validation parameters
     * @returns {Promise<{isValid: boolean, errors: Array<string>}>} Validation result
     */
    static async validateFile(file, options = {}) {
        const errors = [];
        
        // Basic file check
        if (!file || !file.name) {
            errors.push("Invalid file");
            return {
                isValid: false,
                errors: errors
            };
        }
        
        try {
            // Get tenant-specific configuration
            const configResponse = await this.getAttachmentConfig();
            const config = configResponse.data;
            
            // Check file extension (uses tenant-specific permitted extensions)
            const fileExtension = file.name.split('.').pop().toLowerCase();
            if (!config.extensions.includes(fileExtension)) {
                errors.push(`Only the following file extensions are accepted: ${config.extensions.join(", ")}.`);
            }
            
            // Check file name length (uses tenant-specific max length)
            const fileNameWithoutExtension = file.name.substring(0, file.name.lastIndexOf('.'));
            if (fileNameWithoutExtension.length > config.maxFileNameLength) {
                errors.push(`Your file name exceeds ${config.maxFileNameLength} characters`);
            }
            
            // Check file size (uses tenant-specific max size)
            const maxSizeBytes = config.maxMB * 1024 * 1024;
            if (file.size > maxSizeBytes) {
                errors.push(`There is a max file upload size of ${config.maxMB} megabytes.`);
            }
            
        } catch (error) {
            // If we can't get tenant config, let server handle validation
            console.warn('Could not fetch tenant configuration for client-side validation:', error);
            return {
                isValid: true, // Let server validate
                errors: []
            };
        }
        
        return {
            isValid: errors.length === 0,
            errors: errors
        };
    }

    /**
     * Validates a file synchronously using provided configuration
     * @param {File} file - The file to validate
     * @param {Object} config - Validation configuration (extensions, maxFileNameLength, maxMB)
     * @returns {{isValid: boolean, errors: Array<string>}} Validation result
     */
    static validateFileSync(file, config = null) {
        const errors = [];
        
        // Basic file check
        if (!file || !file.name) {
            errors.push("Invalid file");
            return {
                isValid: false,
                errors: errors
            };
        }
        
        // If no config provided, let server handle validation
        if (!config) {
            return {
                isValid: true, // Let server validate
                errors: []
            };
        }
        
        // Check file extension
        const fileExtension = file.name.split('.').pop().toLowerCase();
        if (!config.extensions.includes(fileExtension)) {
            errors.push(`Only the following file extensions are accepted: ${config.extensions.join(", ")}.`);
        }
        
        // Check file name length
        const fileNameWithoutExtension = file.name.substring(0, file.name.lastIndexOf('.'));
        if (fileNameWithoutExtension.length > config.maxFileNameLength) {
            errors.push(`Your file name exceeds ${config.maxFileNameLength} characters`);
        }
        
        // Check file size
        const maxSizeBytes = config.maxMB * 1024 * 1024;
        if (file.size > maxSizeBytes) {
            errors.push(`There is a max file upload size of ${config.maxMB} megabytes.`);
        }
        
        return {
            isValid: errors.length === 0,
            errors: errors
        };
    }

    /**
     * Partitions files into valid and invalid sets using provided config.
     * Used when user selects mixed eligible/ineligible files so eligible ones can still be uploaded.
     * @param {File[]} files - Files to validate
     * @param {Object} config - Validation configuration (extensions, maxFileNameLength, maxMB)
     * @returns {{ validFiles: File[], validationErrors: string[] }}
     */
    static partitionFilesByValidation(files, config = null) {
        const validFiles = [];
        const validationErrors = [];

        if (!files || files.length === 0) {
            return { validFiles, validationErrors };
        }

        if (!config) {
            return { validFiles: Array.isArray(files) ? [...files] : [], validationErrors };
        }

        for (const file of files) {
            const validation = this.validateFileSync(file, config);
            if (validation.isValid) {
                validFiles.push(file);
            } else {
                validation.errors.forEach(err => validationErrors.push(`${file.name}: ${err}`));
            }
        }

        return { validFiles, validationErrors };
    }
}
