/**
 * Utility function to detect if a form item is a date field based on its text property.
 * This centralizes the date field detection logic to ensure consistency across the application.
 * 
 * @param {Object} item - The form item to check
 * @param {string} item.Text - The text/label of the form item
 * @returns {boolean} - True if the item is detected as a date field
 */
export const isDateField = (item) => {
    if (!item || !item.Text) {
        return false;
    }

    return item.Text.includes('Date') && (
        item.Text.includes('YYYY-MM-DD') ||
        item.Text.includes('(Date)') ||
        item.Text.toLowerCase().includes('registration date') ||
        item.Text.toLowerCase().includes('incorporation date') ||
        item.Text.toLowerCase().includes('birth date') ||
        item.Text.toLowerCase().includes('effective date')
    );
};
