import React, { useMemo } from "react";
import Badge from "react-bootstrap/Badge";

const RoleBadges = ({ values, percentage, roles }) => {
  return (
    <React.Fragment>
      {values.map(role => {
        return (
          <Badge key={role} variant="primary" className="p-2 mx-1">
            {roles.find(x => x.value === role).label}
            {role === "Owner" && !isNaN(percentage) && (
              <Badge variant="light" className="mx-1">
                {`${percentage}%`}
              </Badge>
            )}
          </Badge>
        );
      })}
    </React.Fragment>
  );
};

export default RoleBadges;
