import React, { useState, useEffect } from "react";
import PropTypes from "prop-types";
import { Box, Grid, FormControlLabel, Stack } from "@mui/material";
import FAWButton from "../../../component-widget/FAWButton";
import FAWCheckbox from "../../../component-widget/FAWCheckbox";
import { selectionType, displayText, defaultQuestionText, defaultGeneralInfo } from "./constants";

function CountryTab({
  region,
  answers,
  updateAnswers,
  handleSelectionToggle,
   editting,
  translations
}) {
  const [countries, setCountries] = useState(region.countries);
  useEffect(() => {
    setCountries(region.countries);
  }, [region]);

  const handleCountryChange = (event) => {
    const countryCode = event.target.id;
    updateAnswers(countryCode);
  };

   const findLabel = id => {
      if (translations) {
         const message = translations.find(x => x.Id === id);
         return message ? message.Label : defaultQuestionText[id];
      }

      return defaultQuestionText[id];
   }

   const findDescription = id => {
      if (translations) {
         const message = translations.find(x => x.Id === id);
         return message ? message.Description : defaultGeneralInfo[id];
      }

      return defaultGeneralInfo[id];
   }

  const invertSelections = () => {
    countries.map(country =>
      handleCountryChange({ target: { id: country.countryCode } })
    );
  };

  const selectAll = () => {
    handleSelectionToggle(selectionType.SELECT_ALL, countries);
  };

  const deselectAll = () => {
    handleSelectionToggle(selectionType.DESELECT_ALL, countries);
  };

  return (
    <Box>
      {editting && (
        <Box sx={{ py: 2 }}>
          <Stack direction="row" spacing={2}>
            <FAWButton variant="outlined" color="primary" onClick={invertSelections}>
              {findLabel(displayText.Invert)}
            </FAWButton>
            <FAWButton variant="outlined" color="primary" onClick={selectAll}>
              {findLabel(displayText.SelectAll)}
            </FAWButton>
            <FAWButton variant="outlined" color="primary" onClick={deselectAll}>
              {findLabel(displayText.DeselectAll)}
            </FAWButton>
          </Stack>
        </Box>
      )}
      <Box sx={{ pb: 2 }}>
        <Grid container spacing={1}>
          {countries.map(({ countryCode, display }) => (
            <Grid item xs={12} sm={6} md={4} key={countryCode}>
              <Box sx={{ p: 1 }}>
                <FormControlLabel
                  control={
                    <FAWCheckbox
                      id={countryCode}
                      checked={answers.some(
                        e => e.Value === countryCode && !e.MarkForDelete
                      )}
                      onChange={handleCountryChange}
                      disabled={!editting}
                    />
                  }
                  label={display}
                  sx={{ 
                    width: '100%',
                    '& .MuiFormControlLabel-label': {
                      fontSize: '14px'
                    }
                  }}
                />
              </Box>
            </Grid>
          ))}
        </Grid>
      </Box>
    </Box>
  );
}

CountryTab.propTypes = {
  region: PropTypes.object
};

export default CountryTab;
