import { useCallback } from 'react';

export const useDependencyManagement = (dependencyMap, visibilityState, setVisibilityState, onDependencyChange) => {
    
    const handleDependencyChange = useCallback((parentName, newValue) => {
        // Normalize parentName by taking part before '_' to match dependency map key
        // e.g., "bPublicTrade_HI" -> "bPublicTrade"
        const normalizedParentName = parentName.split('_')[0];
        if (!dependencyMap[normalizedParentName]) {
            return;
        }

        const children = dependencyMap[normalizedParentName];
        const newVisibility = {...visibilityState};
        
        children.forEach(({ childName, parentValue }) => {
            const shouldShow = newValue === parentValue;
            newVisibility[childName] = shouldShow;
        });
        
        setVisibilityState(newVisibility);
        
        if (onDependencyChange) {
            onDependencyChange(parentName, newValue, newVisibility);
        }
    }, [dependencyMap, visibilityState, setVisibilityState, onDependencyChange]);

    const buildDependencyMap = useCallback((items) => {
        const depMap = {};
        const initialVisibility = {};

        const processItemsForDependencies = (itemList, parentItem = null) => {
            itemList.forEach((item, index) => {
                try {
                    let isDependent = false;
                    if (item.ParentName && item.ParentValue !== undefined) {
                        const parentName = item.ParentName.trim();
                        const parentValue = typeof item.ParentValue === 'string' ? item.ParentValue.trim() : item.ParentValue;
                        
                        if (!depMap[parentName]) {
                            depMap[parentName] = [];
                        }
                        depMap[parentName].push({
                            childName: item.Name.trim(),
                            parentValue: parentValue,
                            childIndex: index
                        });
                        isDependent = true;
                    }

                    if (item.Name) {
                        const itemName = item.Name.trim();
                        initialVisibility[itemName] = !isDependent;
                        if (isDependent) {
                        }
                    }

                    if (item.FormItems && Array.isArray(item.FormItems)) {
                        processItemsForDependencies(item.FormItems, item);
                    }
                } catch (itemError) {
                    console.error('Error processing form item:', item?.Name || index, itemError);
                }
            });
        };

        processItemsForDependencies(items);

        return { depMap, initialVisibility };
    }, []);

    return {
        handleDependencyChange,
        buildDependencyMap
    };
};
