import React, { useState, useCallback, useEffect } from "react";
import { 
  Box, 
  Button, 
  Typography, 
  FormHelperText, 
  List, 
  ListItem, 
  ListItemText, 
  IconButton, 
  CircularProgress,
  TextField,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions
} from "@mui/material";
import DeleteIcon from '@mui/icons-material/Delete';
import CloseIcon from '@mui/icons-material/Close';
import { QuestionnaireService } from './questionnaire-preview/services/QuestionnaireService';
import FAWToast from './FAWToast';
import FAWConfirmDialogue from './FAWConfirmDialogue';
import FAWAlert from './FAWAlert';
import FAWTooltip from './FAWTooltip';
import RequiredIndicator from './RequiredIndicator';
import FAWTypography from './FAWTypography';
import { colors } from "../../utils/designTokens";

const LiveformUpload = React.forwardRef(({ 
  onChange, 
  label = "Choose Files", 
  helperText,
  error,
  accept = "*/*", 
  multiple = false, 
  sx = {}, 
  id,
  name,
  value = [],  // Existing files (array)
  readOnly = false,
  questionnaireAnswerId, // Required for file upload
  responseContainerId, // Required for file upload
  itemName, // Required for file upload
  onFileDataRefresh, // Function to refresh all file data
  registerValidationMethod, // Function to register validation method
  required = false, // Whether attachment is required
  validationMessage, // Custom validation message
  ...rest 
}, ref) => {
  const [uploadedFiles, setUploadedFiles] = useState([]);
  const [uploading, setUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [fileToDelete, setFileToDelete] = useState(null);
  const [toast, setToast] = useState({ open: false, message: '', type: 'info', duration: 3000 });
  const [validationRules, setValidationRules] = useState(null);
  const [validationErrors, setValidationErrors] = useState([]);
  const [showValidationAlert, setShowValidationAlert] = useState(false);
  const [description, setDescription] = useState('');
  const [descriptionCharCount, setDescriptionCharCount] = useState(0);
  const [uploadModalOpen, setUploadModalOpen] = useState(false);
  const [selectedFilesForUpload, setSelectedFilesForUpload] = useState([]);
  const [fileInputKey, setFileInputKey] = useState(Date.now()); // For resetting file input
  const uniqueId = id || name || `liveform-upload-${Date.now()}`;
  
  // Show toast function
  const showToast = useCallback((toastData) => {
    setToast({
      open: true,
      message: toastData.message,
      type: toastData.type || 'info',
      duration: toastData.duration || 3000
    });
  }, []);

  // Fetch validation rules from backend
  const fetchValidationRules = useCallback(async () => {
    try {
      const response = await QuestionnaireService.getAttachmentConfig();
      if (response.success) {
        setValidationRules(response.data);
      } else {
        console.warn('LiveformUpload: Failed to fetch attachment validation rules - server will handle validation');
        // Don't set validation rules - let server handle validation
      }
    } catch (error) {
      console.warn('LiveformUpload: Could not fetch attachment validation rules - server will handle validation:', error);
      // Don't set validation rules - let server handle validation
    }
  }, []);

  // Fetch validation rules once on component mount
  useEffect(() => {
    fetchValidationRules();
  }, []); // Empty dependency array - only run once on mount
  
  // Validation method: Check if attachment has uploaded files
  const validateAttachment = useCallback(() => {
    if (required && (!uploadedFiles || uploadedFiles.length === 0)) {
      const message = validationMessage || `Required attachment '${label}' is not provided.`;
      return message;
    }
    
    return null; // No error
  }, [required, uploadedFiles, validationMessage, label, itemName]);
  
  // Register validation method with validation system on mount
  useEffect(() => {
    if (registerValidationMethod && itemName) {
      registerValidationMethod(itemName, validateAttachment);
    }
  }, [registerValidationMethod, itemName, validateAttachment, required, uploadedFiles.length]);
  
  // Use only uploaded files (from centralized data)
  const displayFiles = uploadedFiles;

  // Create a ref object to expose methods to parent
  const componentRef = React.useRef();
  
  // Forward the ref to componentRef for parent access
  React.useImperativeHandle(ref, () => ({
    // Expose method to get latest file data for form submission
    getLatestFiles: () => uploadedFiles
  }));
  

  // Use file data from props instead of fetching
  React.useEffect(() => {
    // Always prioritize value prop if it has data
    if (value && Array.isArray(value)) {
      if (value.length > 0) {
        setUploadedFiles(value);
      } else {
        // Value prop is explicitly empty array - clear uploadedFiles
        setUploadedFiles([]);
      }
    }
    // If value is undefined or null, keep current state (don't clear)
  }, [value, itemName]);


  // Enhanced file upload with progress tracking
  const handleFileUpload = useCallback(async (files) => {
    if (!questionnaireAnswerId || !itemName) {
      const errorMsg = 'Missing required upload parameters';
      console.error('[LiveformUpload] Upload failed:', errorMsg);
      return;
    }

    try {
      setUploading(true);
      setUploadProgress(0);
      
      // Enhanced upload with progress tracking
      const uploadResponse = await QuestionnaireService.uploadAttachment(
        questionnaireAnswerId,
        responseContainerId,
        itemName,
        files,
        {
          onProgress: (progress) => {
            setUploadProgress(progress);
          },
          description: description // Pass description to the service
        }
      );
      
      // Partial success: at least one file uploaded (eligible accepted, ineligible skipped)
      const hasUploadedFiles = uploadResponse.files && uploadResponse.files.length > 0;
      if (uploadResponse.success || hasUploadedFiles) {

        // Clear description after upload
        setDescription('');
        setDescriptionCharCount(0);

        const uploadedFileObjects = uploadResponse.files.map(file => ({
          name: file.filename,
          size: file.size,
          id: file.id,
          uploaded: true,
          isExisting: false
        }));

        setUploadedFiles(prev => {
          const next = [...prev, ...uploadedFileObjects];
          if (typeof onChange === 'function') {
            onChange(next);
          }
          return next;
        });

        showToast({
          message: `File${uploadedFileObjects.length > 1 ? 's' : ''} uploaded successfully!`,
          type: 'success',
          duration: 3000
        });

        if (typeof onFileDataRefresh === 'function') {
          onFileDataRefresh();
        }
      } else {
        // No files uploaded (all rejected or server error)
        const errorMessage = uploadResponse.message || uploadResponse.error || 'Upload failed';
        showToast({
          message: errorMessage,
          type: 'error',
          duration: 30000
        });
        return;
      }
    } catch (error) {
      
      // Keep existing files unchanged on upload failure
      
      // Provide more specific error messages
      let errorMessage = 'Upload failed';
      if (error.message.includes('timeout')) {
        errorMessage = 'Upload timed out. Please try again with a smaller file or check your connection.';
      } else if (error.message.includes('ECONNABORTED')) {
        errorMessage = 'Connection was aborted. Please check your internet connection and try again.';
      } else if (error.response?.status === 413) {
        errorMessage = 'File too large. Please select a smaller file.';
      } else if (error.response?.status === 415) {
        errorMessage = 'File type not supported. Please select a different file type.';
      } else if (error.message) {
        errorMessage = error.message;
      }
      
      // Show error toast
      showToast({
        message: errorMessage,
        type: 'error',
        duration: 5000
      });
      
    } finally {
      setUploading(false);
      setUploadProgress(0);
    }
  }, [questionnaireAnswerId, responseContainerId, itemName, multiple, uploadedFiles, onChange, onFileDataRefresh, description]);

  const handleChange = (e) => {
    if (readOnly || uploading) return; // Prevent uploads while already uploading
    
    const newFiles = Array.from(e.target.files || []);
    
    if (newFiles.length === 0) return;
    
    // Clear previous validation errors
    setValidationErrors([]);
    setShowValidationAlert(false);
    
    // Only do client-side validation if we have cached validation rules
    if (validationRules) {
      const { validFiles, validationErrors: fileValidationErrors } =
        QuestionnaireService.partitionFilesByValidation(newFiles, validationRules);

      // When all files are ineligible: show errors and do not proceed
      if (validFiles.length === 0) {
        setValidationErrors(fileValidationErrors);
        setShowValidationAlert(true);
        e.target.value = '';
        setFileInputKey(Date.now());
        return;
      }

      // At least one eligible file: store only valid files for upload and show errors for rejected ones
      setSelectedFilesForUpload(validFiles);
      if (fileValidationErrors.length > 0) {
        setValidationErrors(fileValidationErrors);
        setShowValidationAlert(true);
      }
      e.target.value = '';
    } else {
      // No cached validation rules - store files for display
      setSelectedFilesForUpload(newFiles);
    }
    
    // Don't reset file input here - will reset after upload or cancel
  };
  
  // Handle modal upload button click
  const handleModalUpload = async () => {
    if (selectedFilesForUpload.length > 0) {
      await handleFileUpload(selectedFilesForUpload);
      setUploadModalOpen(false);
      setSelectedFilesForUpload([]);
      setFileInputKey(Date.now()); // Reset file input
    }
  };
  
  // Handle modal cancel
  const handleModalCancel = () => {
    setUploadModalOpen(false);
    setSelectedFilesForUpload([]);
    setDescription('');
    setDescriptionCharCount(0);
    setFileInputKey(Date.now()); // Reset file input
  };

  // Handle removing files (matches legacy behavior exactly)
  const handleRemove = (index) => {
    if (readOnly) return;
    
    const fileToRemove = displayFiles[index];
    
    // Only allow deletion of uploaded files
    if (fileToRemove.uploaded || fileToRemove.isExisting) {
      setFileToDelete({ file: fileToRemove, index });
      setDeleteConfirmOpen(true);
    }
  };

  // Confirm delete action (matches legacy continue-action click)
  const confirmDelete = () => {
    if (!fileToDelete) return;
    
    const { file, index } = fileToDelete;
    
    // Only delete uploaded files via API
    if (file.uploaded || file.isExisting) {
      deleteUploadedFile(file);
    }
    
    // Close dialog
    setDeleteConfirmOpen(false);
    setFileToDelete(null);
  };

  // Cancel delete action (matches legacy terminate-action click)
  const cancelDelete = () => {
    setDeleteConfirmOpen(false);
    setFileToDelete(null);
  };

  // Delete uploaded file via API (matches legacy deleteAttachment function exactly)
  const deleteUploadedFile = async (fileToRemove) => {
    try {
      // Call the delete attachment API endpoint using centralized service
      const response = await QuestionnaireService.deleteAttachment(fileToRemove.id || fileToRemove.attachmentId);

      if (response.success) {
        // Show success toast
        showToast({
          message: `File "${fileToRemove.name}" deleted successfully!`,
          type: 'success',
          duration: 3000
        });
        
        // Refresh all file data after deletion (this will update the UI)
        if (typeof onFileDataRefresh === 'function') {
          onFileDataRefresh();
        }
        
        // Also update local state immediately for better UX
        setUploadedFiles(prev => {
          const updated = prev.filter(f => f.id !== (fileToRemove.id || fileToRemove.attachmentId));
          return updated;
        });
        
        // Notify parent component with updated file list
        if (typeof onChange === "function") {
          const updatedFiles = uploadedFiles.filter(f => f.id !== (fileToRemove.id || fileToRemove.attachmentId));
          onChange(updatedFiles);
        }
      } else {
        throw new Error('Failed to delete file');
      }
    } catch (error) {
      // Show error toast
      showToast({
        message: `Failed to delete file: ${error.message || 'Unknown error'}`,
        type: 'error',
        duration: 5000
      });
    }
  };

  // Files are uploaded immediately when selected
  // Expose methods to parent component
  React.useImperativeHandle(componentRef, () => ({
    uploadFiles: () => ({ success: true, message: 'Files are uploaded immediately when selected' }),
    hasUploadedFiles: () => {
      // Check if there are any uploaded files
      return displayFiles.length > 0;
    }
  }), [displayFiles]);



  // Generate dynamic accept attribute based on validation rules
  const dynamicAccept = React.useMemo(() => {
    if (validationRules && validationRules.extensions && validationRules.extensions.length > 0) {
      return validationRules.extensions.map(ext => `.${ext}`).join(',');
    }
    return accept; // Fallback to original accept prop
  }, [validationRules, accept]);

  // Get helper text from form system
  const formHelperText = helperText || '';

  // Determine if we should show error state
  const hasErrors = error || validationErrors.length > 0;

  return (
    <Box sx={{ width: '100%', ...sx }}>
      {/* Show helper text from form system */}
      {formHelperText && (
        <FormHelperText 
          error={!!error} 
          sx={{ 
            marginBottom: 2, 
            color: 'text.primary',
            display: 'inline-flex',
            alignItems: 'baseline',
            '&.Mui-error': {
              color: 'text.primary'
            },
            '&.MuiFormHelperText-root': {
              color: 'text.primary'
            }
          }}
        >
          {formHelperText}
          <RequiredIndicator required={required} />
        </FormHelperText>
      )}
      
      {!readOnly && (
        <Box sx={{ 
          display: 'flex', 
          alignItems: 'center', 
          gap: 1,
          border: hasErrors ? `1px solid ${colors.status.error}` : `1px solid ${colors.ui.border.static}`,
          borderRadius: '4px',
          padding: '8px 12px',
          backgroundColor: colors.background.default,
          '&:hover': {
            borderColor: hasErrors ? colors.status.error : colors.type.tertiary
          }
        }}>
          <Button
            variant="outlined"
            size="small"
            disabled={uploading}
            onClick={() => setUploadModalOpen(true)}
            sx={{
              textTransform: 'none',
              fontSize: '14px',
              padding: '6px 12px',
              borderColor: colors.ui.border.static,
              color: colors.type.secondary,
              backgroundColor: colors.background.secondary,
              display: 'flex',
              justifyContent: 'center',
              alignItems: 'center',
              textAlign: 'center',
              width: '100%',
              '&:hover': {
                borderColor: colors.type.tertiary,
                backgroundColor: colors.background.tertiary
              },
              '&:disabled': {
                opacity: 0.6
              }
            }}
          >
            {uploading ? (
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                <CircularProgress size={16} />
                <Typography variant="body2">
                  Uploading... {uploadProgress > 0 && `${uploadProgress}%`}
                </Typography>
              </Box>
            ) : (
              label
            )}
          </Button>
        </Box>
      )}
      
      {/* List of uploaded files in table format */}
      {displayFiles.length > 0 && (
        <Box sx={{ mt: 2 }}>
          <Box sx={{ 
            display: 'grid', 
            gridTemplateColumns: '1fr auto auto',
            gap: 1,
            borderBottom: `2px solid ${colors.ui.border.static}`,
            borderBottomWidth: '2px',
            borderBottomStyle: 'solid',
            borderBottomColor: colors.ui.border.static,
            pb: 1,
            mb: 1
          }}>
            <Typography variant="body2" sx={{ fontWeight: 600, fontSize: '14px' }}>
              Name
            </Typography>
            <Typography variant="body2" sx={{ fontWeight: 600, fontSize: '14px', minWidth: '100px' }}>
              Size
            </Typography>
            <Typography variant="body2" sx={{ fontWeight: 600, fontSize: '14px', textAlign: 'center', minWidth: '80px' }}>
              Actions
            </Typography>
          </Box>
          
       
          
          <Box sx={{ maxHeight: 300, overflow: 'auto' }}>
            {displayFiles.map((file, index) => (
              <Box 
                key={index}
                sx={{ 
                  display: 'grid', 
                  gridTemplateColumns: '1fr auto auto',
                  gap: 1,
                  py: 1,
                  borderBottom: index < displayFiles.length - 1 ? `1px solid ${colors.ui.border.static}` : 'none',
                  alignItems: 'center'
                }}
              >
                <Typography variant="body2" sx={{ fontSize: '14px', wordBreak: 'break-word' }}>
                  {typeof file === 'string' ? file : (file.name || 'Unknown file')}
                </Typography>
                
                <Typography variant="body2" sx={{ fontSize: '14px', color: colors.type.secondary,  minWidth: '100px' }}>
                  {file.size ? `${(file.size / 1024).toFixed(2)} KB` : ''}
                </Typography>
                
                <Box sx={{ textAlign: 'center', minWidth: '80px' }}>
                  {!readOnly && (file.uploaded || file.isExisting) && (
                    <IconButton 
                      onClick={() => handleRemove(index)}
                      size="small"
                      sx={{ 
                        color: colors.status.error,
                        '&:hover': {
                          backgroundColor: colors.status.error + '15'
                        }
                      }}
                      title="Delete file"
                    >
                      <DeleteIcon fontSize="small" />
                    </IconButton>
                  )}
                </Box>
              </Box>
            ))}
          </Box>
        </Box>
      )}
      {displayFiles.length === 0 && (
        <Typography variant="body2" sx={{ mt: 1, color: colors.type.secondary }}>
          No files uploaded
        </Typography>
      )}
      
      {/* Show validation errors as dismissible alert */}
      {showValidationAlert && validationErrors.length > 0 && (
        <FAWAlert 
          severity="error" 
          message={validationErrors.join('\n')}
          onClose={() => setShowValidationAlert(false)}
          sx={{ marginTop: 1, marginBottom: 1 }}
        />
      )}

      {/* Delete Confirmation Dialog using FAWConfirmDialogue */}
      <FAWConfirmDialogue
        open={deleteConfirmOpen}
        onClose={cancelDelete}
        onConfirm={confirmDelete}
        variant="delete"
        title="Confirm File Deletion"
        message={`Are you sure you want to delete the file "${fileToDelete?.file?.name || ''}"?`}
        description=""
      />
      
      {/* FAWToast for file operation feedback */}
      <FAWToast 
        open={toast.open} 
        message={toast.message} 
        type={toast.type}
        duration={toast.duration}
        onClose={() => setToast(prev => ({ ...prev, open: false }))} 
      />
      
      {/* Upload Modal Dialog with Description Field */}
      <Dialog 
        open={uploadModalOpen} 
        onClose={handleModalCancel}
        maxWidth="sm"
        fullWidth
      >
        <DialogTitle sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', pb: 1 }}>
          <Typography variant="h6" sx={{ fontWeight: 600, fontSize: '18px' }}>
            Upload Attachment
          </Typography>
          <IconButton 
            aria-label="close" 
            onClick={handleModalCancel} 
            size="small" 
            disabled={uploading}
          >
            <CloseIcon fontSize="small" />
          </IconButton>
        </DialogTitle>
        
        <DialogContent sx={{ pt: 2 }}>
          {/* File Selection Area - Simple Browse Button */}
          <Box sx={{ mb: 3 }}>
            <Box sx={{ 
              display: 'flex', 
              alignItems: 'center', 
              gap: 1,
              border: `1px solid ${colors.ui.border.static}`,
              borderRadius: '4px',
              padding: '10px 14px',
              backgroundColor: colors.background.secondary
            }}>
              <input
                key={fileInputKey}
                accept={dynamicAccept}
                style={{ display: 'none' }}
                id={`${uniqueId}-modal`}
                name={name}
                multiple={multiple}
                type="file"
                onChange={handleChange}
                disabled={uploading}
                {...rest}
              />
              <label htmlFor={`${uniqueId}-modal`}>
                <Button
                  variant="contained"
                  component="span"
                  size="small"
                  disabled={uploading}
                  sx={{
                    textTransform: 'none',
                    fontSize: '14px',
                    padding: '6px 16px',
                    minWidth: '100px'
                  }}
                >
                  Browse...
                </Button>
              </label>
              <Typography variant="body2" sx={{ color: colors.type.secondary, flex: 1 }}>
                {selectedFilesForUpload.length === 0
                  ? 'No file(s) chosen'
                  : selectedFilesForUpload.length === 1
                  ? selectedFilesForUpload[0].name
                  : `${selectedFilesForUpload.length} file(s) chosen`
                }
              </Typography>
            </Box>
          </Box>
          
          {/* Description Field */}
          <Box>
            <Typography variant="body1" sx={{ mb: 1, fontWeight: 600, fontSize: '14px' }}>
              Provide a description of the attachment you are uploading:
            </Typography>
            <TextField
              fullWidth
              multiline
              rows={3}
              placeholder="Enter description here..."
              value={description}
              onChange={(e) => {
                const value = e.target.value;
                if (value.length <= 100) {
                  setDescription(value);
                  setDescriptionCharCount(value.length);
                }
              }}
              inputProps={{ maxLength: 100 }}
              size="small"
              disabled={uploading}
              sx={{
                '& .MuiOutlinedInput-root': {
                  backgroundColor: colors.background.default,
                  '&:hover fieldset': {
                    borderColor: colors.type.tertiary
                  }
                }
              }}
            />
            <Box sx={{ display: 'flex', justifyContent: 'flex-end', mt: 0.5 }}>
              <Typography 
                variant="caption" 
                sx={{ 
                  fontSize: '12px',
                  color: descriptionCharCount >= 100 
                    ? colors.status.error // Red when at limit
                    : descriptionCharCount > 90 
                      ? colors.status.warning // Orange/warning when over 90%
                      : colors.type.secondary // Gray/default
                }}
              >
                {descriptionCharCount}/100 characters
              </Typography>
            </Box>
          </Box>
          
          {/* File Name Character Limit Notice */}
          <Typography variant="body2" sx={{ mt: 2, color: colors.type.tertiary, fontSize: '14px' }}>
            The file name must not exceed 100 characters.
          </Typography>
          
          {/* Upload Progress */}
          {uploading && (
            <Box sx={{ mt: 2, display: 'flex', alignItems: 'center', gap: 1 }}>
              <CircularProgress size={20} />
              <Typography variant="body2" sx={{ color: colors.type.secondary }}>
                Uploading... {uploadProgress > 0 && `${uploadProgress}%`}
              </Typography>
            </Box>
          )}
        </DialogContent>
        
        <DialogActions sx={{ padding: '16px 24px', justifyContent: 'center', gap: 2 }}>
          <Button
            variant="outlined"
            onClick={handleModalUpload}
            disabled={uploading || selectedFilesForUpload.length === 0}
            sx={{
              textTransform: 'none',
              padding: '8px 20px',
              borderRadius: '4px',
              minWidth: '100px',
              backgroundColor: 'white',
              border: '1px solid',
              borderColor: colors.ui.border.static,
              color: colors.type.primary,
              '&:hover': {
                backgroundColor: colors.background.secondary,
                borderColor: colors.type.tertiary
              }
            }}
          >
            Upload
          </Button>
          <Button
            variant="outlined"
            onClick={handleModalCancel}
            disabled={uploading}
            sx={{
              textTransform: 'none',
              padding: '8px 20px',
              borderRadius: '4px',
              minWidth: '100px',
              color: colors.type.secondary,
              borderColor: colors.ui.border.static,
              '&:hover': {
                backgroundColor: colors.background.secondary,
                borderColor: colors.type.tertiary
              }
            }}
          >
            Cancel
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
});

LiveformUpload.displayName = 'LiveformUpload';

export default React.memo(LiveformUpload);
