import React, { useState, useEffect } from "react";
import { Box, Alert, CircularProgress } from "@mui/material";
import FAWTooltip from "../../../component-widget/FAWTooltip";
import RefreshIcon from '@mui/icons-material/Refresh';
import parse from "html-react-parser";
import DOMPurify from "dompurify";
import axios from "axios";
import FAWTypography from "../../../component-widget/FAWTypography";
import FAWLoader from "../../../component-widget/FAWLoader";
import FAWSkeleton from "../../../component-widget/FAWSkeleton";
import FAWButton from "../../../component-widget/FAWButton";
import FAWToast from "../../../component-widget/FAWToast";

function AntiCorruptionLanguage(props) {
    const [acl, setAcl] = useState();
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(false);
    const [refetch, setRefetch] = useState(0);
    const [errorMessages, setErrorMessages] = useState();
    const [toast, setToast] = useState({ open: false, message: '', type: 'info' });

    useEffect(() => {
        const fetchAclText = async () => {
            try {
                setError(false);
                setLoading(true);

                const { data } = await axios.get(
                    "/Questionnaire/GetAntiCorruptionLanguage"
                );

                const { content, errorMessages } = data;

                setLoading(false);
                setErrorMessages(errorMessages);
                setAcl(content);

            } catch (e) {
                setError(true);
                setLoading(false);
                setToast({ open: true, message: 'Network error while loading Anti-Corruption Language', type: 'error' });
            }
        };

        fetchAclText();
    }, [refetch]); // ✅ FIX: Add refetch to dependencies so retry works

    const html = html => {
        return parse(DOMPurify.sanitize(html, { ADD_ATTR: ["target"] }));
    };

    const handleToastClose = () => {
        setToast(prev => ({ ...prev, open: false }));
    };


    if (loading) {
        return (
            <>
                <Box sx={{ px: 5, pt: 2 }}>
                    <FAWSkeleton variant="document" />
                </Box>

                <FAWToast
                    open={toast.open}
                    message={toast.message}
                    type={toast.type}
                    onClose={handleToastClose}
                />
            </>
        );
    }

    if (error) {
        return (
            <>
                <Box sx={{ px: 5, pt: 2 }}>
                    <Alert
                        severity="error"
                        action={
                            <FAWTooltip title="Retry">
                                <RefreshIcon
                                    onClick={() => setRefetch(c => c + 1)}
                                    sx={{
                                        cursor: 'pointer',
                                        color: 'primary.main',
                                        '&:hover': {
                                            color: 'primary.dark',
                                            transform: 'scale(1.1)'
                                        },
                                        transition: 'all 0.2s ease'
                                    }}
                                />
                            </FAWTooltip>
                        }
                    >
                        Failed to load Anti-Corruption Language. Please try again.
                    </Alert>
                </Box>

                <FAWToast
                    open={toast.open}
                    message={toast.message}
                    type={toast.type}
                    onClose={handleToastClose}
                />
            </>
        );
    }

    return (
        <>
            <Box sx={{ px: 5, pt: 2 }}>
                {html(acl)}
            </Box>

            <FAWToast
                open={toast.open}
                message={toast.message}
                type={toast.type}
                onClose={handleToastClose}
            />
        </>
    );
}

export default AntiCorruptionLanguage;
