/**
 * Validation Engine
 * 
 * Modern validation system with modular validators, structured error handling,
 * performance optimization, and comprehensive business rule validation.
 */

// Import helper functions
import { generateErrorId, convertMaskToRegex, processTextBoxAttributes } from './validationHelpers.js';
import { isDateField } from './dateFieldUtils.js';

/**
 * Field types excluded from frontend validation
 */
const EXCLUDE_VALIDATION_TYPES = [
  'KeyPersonnel',
  'PSACompany',
  'CountrySelect',
  'ScormQuestionEditor',
  'ScormQuestionEditorItemType'
];

/**
 * Check if field type should be excluded from frontend validation
 */
const isBackendValidatedField = (fieldType) => {
  return EXCLUDE_VALIDATION_TYPES.includes(fieldType);
};

export const ValidationResult = {
  SUCCESS: 'success',
  ERROR: 'error',
  WARNING: 'warning',
  INFO: 'info'
};

export const ErrorTypes = {
  REQUIRED: 'required',
  FORMAT: 'format',
  BUSINESS_RULE: 'business_rule',
  DEPENDENCY: 'dependency',
  CUSTOM: 'custom'
};

export const Severity = {
  LOW: 'low',
  MEDIUM: 'medium',
  HIGH: 'high',
  CRITICAL: 'critical'
};

/**
 * Creates the main validation engine
 */
export const createValidationEngine = (config = {}) => {
  const {
    formItems = [],
    answers = {},
    visibilityState = {},
    options = {}
  } = config;

  const validationCache = new Map();
  const errorManager = createErrorManager();
  const fieldValidators = createFieldValidators();
  const businessRules = createBusinessRules();
  const orchestrator = createValidationOrchestrator({
    fieldValidators,
    businessRules,
    errorManager,
    validationCache
  });

  return {
    validateField: (fieldName, value, options = {}) => 
      orchestrator.validateField(fieldName, value, options),
    
    validateForm: (options = {}) => 
      orchestrator.validateForm(options),
    
    validateBusinessRules: (options = {}) => 
      orchestrator.validateBusinessRules(options),
    
    getErrors: () => errorManager.getErrors(),
    clearErrors: (fieldName) => errorManager.clearErrors(fieldName),
    hasErrors: () => errorManager.hasErrors(),
    formatErrors: (options = {}) => errorManager.formatErrors(options),
    
    clearCache: () => validationCache.clear(),
    getCacheStats: () => ({
      size: validationCache.size,
      keys: Array.from(validationCache.keys())
    }),
    
    updateConfig: (newConfig) => {
      Object.assign(config, newConfig);
      validationCache.clear();
    }
  };
};

const createErrorManager = () => {
  let errors = {
    fieldErrors: new Map(),
    formErrors: [],
    businessRuleErrors: [],
    dependencyErrors: []
  };

  return {
    // Add error
    addError: (error) => {
      const { type, fieldName, message, severity = Severity.MEDIUM, metadata = {} } = error;
      
      const errorObject = {
        type,
        fieldName,
        message,
        severity,
        metadata,
        timestamp: new Date().toISOString(),
        id: generateErrorId()
      };

      switch (type) {
        case ErrorTypes.REQUIRED:
        case ErrorTypes.FORMAT:
          if (fieldName) {
            if (!errors.fieldErrors.has(fieldName)) {
              errors.fieldErrors.set(fieldName, []);
            }
            errors.fieldErrors.get(fieldName).push(errorObject);
          }
          break;
        case ErrorTypes.BUSINESS_RULE:
          errors.businessRuleErrors.push(errorObject);
          break;
        case ErrorTypes.DEPENDENCY:
          errors.dependencyErrors.push(errorObject);
          break;
        default:
          errors.formErrors.push(errorObject);
      }
    },

    // Get all errors
    getErrors: () => ({
      fieldErrors: Object.fromEntries(errors.fieldErrors),
      formErrors: errors.formErrors,
      businessRuleErrors: errors.businessRuleErrors,
      dependencyErrors: errors.dependencyErrors,
      summary: {
        total: errors.fieldErrors.size + errors.formErrors.length + 
               errors.businessRuleErrors.length + errors.dependencyErrors.length,
        byType: {
          field: errors.fieldErrors.size,
          form: errors.formErrors.length,
          businessRule: errors.businessRuleErrors.length,
          dependency: errors.dependencyErrors.length
        }
      }
    }),

    // Clear errors
    clearErrors: (fieldName) => {
      if (fieldName) {
        errors.fieldErrors.delete(fieldName);
      } else {
        // Clear all errors by clearing the existing objects/arrays
        errors.fieldErrors.clear();
        errors.formErrors.length = 0;
        errors.businessRuleErrors.length = 0;
        errors.dependencyErrors.length = 0;
      }
    },

    // Check if has errors
    hasErrors: () => {
      return errors.fieldErrors.size > 0 || 
             errors.formErrors.length > 0 || 
             errors.businessRuleErrors.length > 0 || 
             errors.dependencyErrors.length > 0;
    },

    // Get errors for specific field
    getFieldErrors: (fieldName) => {
      return errors.fieldErrors.get(fieldName) || [];
    },

    // Format errors for display
    formatErrors: (options = {}) => {
      const { includeMetadata = false, groupBySeverity = false } = options;
      const allErrors = [];
      
      // Collect all errors from fieldErrors Map
      errors.fieldErrors.forEach((fieldErrors, fieldName) => {
        allErrors.push(...fieldErrors);
      });
      allErrors.push(...errors.formErrors);
      allErrors.push(...errors.businessRuleErrors);
      allErrors.push(...errors.dependencyErrors);
      
      // Format based on options
      return allErrors.map(error => ({
        message: error.message,
        field: error.fieldName,
        severity: error.severity,
        type: error.type,
        ...(includeMetadata && { metadata: error.metadata })
      }));
    }
  };
};

const createFieldValidators = () => {
  const validators = new Map();

  // Register built-in validators
  registerBuiltInValidators(validators);

  return {
    // Register a new validator
    register: (name, validator) => {
      validators.set(name, validator);
    },

    // Get validator by name
    get: (name) => validators.get(name),

    // Validate field with specific validator
    validate: (fieldName, value, validatorName, options = {}) => {
      const validator = validators.get(validatorName);
      if (!validator) {
        throw new Error(`Validator '${validatorName}' not found`);
      }
      return validator(value, options);
    },

    // Get all registered validators
    list: () => Array.from(validators.keys())
  };
};

/**
 * Registers built-in field validators
 */
const registerBuiltInValidators = (validators) => {
  // Required field validator
  validators.set('required', (value, options = {}, context = {}) => {
    const { message = 'This field is required' } = options;
    
    if (value === null || value === undefined || value === '') {
      return {
        isValid: false,
        error: {
          type: ErrorTypes.REQUIRED,
          message,
          severity: Severity.HIGH
        }
      };
    }
    
    return { isValid: true };
  });

  // Email validator
  validators.set('email', (value, options = {}, context = {}) => {
    const { message = 'Please enter a valid email address' } = options;
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    
    if (value && !emailRegex.test(value)) {
      return {
        isValid: false,
        error: {
          type: ErrorTypes.FORMAT,
          message,
          severity: Severity.MEDIUM
        }
      };
    }
    
    return { isValid: true };
  });

  // Phone validator
  validators.set('phone', (value, options = {}, context = {}) => {
    const { message = 'Please enter a valid phone number' } = options;
    const phoneRegex = /^[\+]?[1-9][\d]{0,15}$/;
    const cleanValue = value ? value.replace(/[\s\-\(\)]/g, '') : '';
    
    if (value && !phoneRegex.test(cleanValue)) {
      return {
        isValid: false,
        error: {
          type: ErrorTypes.FORMAT,
          message,
          severity: Severity.MEDIUM
        }
      };
    }
    
    return { isValid: true };
  });

  // URL validator
  validators.set('url', (value, options = {}, context = {}) => {
    const { message = 'Please enter a valid URL' } = options;
    
    if (value) {
      try {
        new URL(value);
      } catch {
        return {
          isValid: false,
          error: {
            type: ErrorTypes.FORMAT,
            message,
            severity: Severity.MEDIUM
          }
        };
      }
    }
    
    return { isValid: true };
  });

  // Date validator - validates YYYY-MM-DD format
  validators.set('date', (value, options = {}, context = {}) => {
    const { message = 'Please enter a valid date in YYYY-MM-DD format' } = options;
    
    if (value) {
      // Check format first (YYYY-MM-DD)
      const dateFormatRegex = /^\d{4}-\d{2}-\d{2}$/;
      if (!dateFormatRegex.test(value)) {
        return {
          isValid: false,
          error: {
            type: ErrorTypes.FORMAT,
            message: 'Date must be in YYYY-MM-DD format (e.g., 2026-02-09)',
            severity: Severity.MEDIUM
          }
        };
      }
      
      // Check if it's a valid date
      const dateValue = new Date(value);
      if (isNaN(dateValue.getTime())) {
        return {
          isValid: false,
          error: {
            type: ErrorTypes.FORMAT,
            message: 'Please enter a valid date',
            severity: Severity.MEDIUM
          }
        };
      }
      
      // Additional validation: check year, month, day ranges
      const [year, month, day] = value.split('-').map(num => parseInt(num, 10));
      if (year < 1900 || year > 2099) {
        return {
          isValid: false,
          error: {
            type: ErrorTypes.FORMAT,
            message: 'Year must be between 1900 and 2099',
            severity: Severity.MEDIUM
          }
        };
      }
      if (month < 1 || month > 12) {
        return {
          isValid: false,
          error: {
            type: ErrorTypes.FORMAT,
            message: 'Month must be between 01 and 12',
            severity: Severity.MEDIUM
          }
        };
      }
      if (day < 1 || day > 31) {
        return {
          isValid: false,
          error: {
            type: ErrorTypes.FORMAT,
            message: 'Day must be between 01 and 31',
            severity: Severity.MEDIUM
          }
        };
      }
    }
    
    return { isValid: true };
  });

  // Number validator
  validators.set('number', (value, options = {}, context = {}) => {
    const { message = 'Please enter a valid number', min, max } = options;
    
    if (value) {
      const numValue = parseFloat(value);
      if (isNaN(numValue)) {
        return {
          isValid: false,
          error: {
            type: ErrorTypes.FORMAT,
            message,
            severity: Severity.MEDIUM
          }
        };
      }
      
      if (min !== undefined && numValue < min) {
        return {
          isValid: false,
          error: {
            type: ErrorTypes.FORMAT,
            message: `Value must be at least ${min}`,
            severity: Severity.MEDIUM
          }
        };
      }
      
      if (max !== undefined && numValue > max) {
        return {
          isValid: false,
          error: {
            type: ErrorTypes.FORMAT,
            message: `Value must be no more than ${max}`,
            severity: Severity.MEDIUM
          }
        };
      }
    }
    
    return { isValid: true };
  });

  // Percentage validator
  validators.set('percentage', (value, options = {}, context = {}) => {
    const { message = 'Please enter a valid percentage (0-100)' } = options;
    
    if (value) {
      const numValue = parseFloat(value);
      if (isNaN(numValue) || numValue < 0 || numValue > 100) {
        return {
          isValid: false,
          error: {
            type: ErrorTypes.FORMAT,
            message,
            severity: Severity.MEDIUM
          }
        };
      }
    }
    
    return { isValid: true };
  });

  // Array validator (for checkboxes, etc.)
  validators.set('array', (value, options = {}, context = {}) => {
    const { message = 'At least one option must be selected', minLength = 1 } = options;
    
    if (!Array.isArray(value) || value.length < minLength) {
      return {
        isValid: false,
        error: {
          type: ErrorTypes.REQUIRED,
          message,
          severity: Severity.MEDIUM
        }
      };
    }
    
    return { isValid: true };
  });

  // Alphabet validator (only letters and spaces)
  validators.set('alphabet', (value, options = {}, context = {}) => {
    const { message = 'Only alphabetic characters and spaces are allowed' } = options;
    
    if (value) {
      const alphabetRegex = /^[a-zA-Z\s]+$/;
      if (!alphabetRegex.test(value)) {
        return {
          isValid: false,
          error: {
            type: ErrorTypes.FORMAT,
            message,
            severity: Severity.MEDIUM
          }
        };
      }
    }
    
    return { isValid: true };
  });

  // AlphaNumeric validator (letters, numbers, spaces, underscores)
  validators.set('alphaNumeric', (value, options = {}, context = {}) => {
    const { message = 'Only alphanumeric characters, spaces, and underscores are allowed' } = options;
    
    if (value) {
      const alphaNumericRegex = /^[a-zA-Z0-9\s_]+$/;
      if (!alphaNumericRegex.test(value)) {
        return {
          isValid: false,
          error: {
            type: ErrorTypes.FORMAT,
            message,
            severity: Severity.MEDIUM
          }
        };
      }
    }
    
    return { isValid: true };
  });

  // Numeric format validator (only numbers and decimal point)
  validators.set('numericFormat', (value, options = {}, context = {}) => {
    const { message = 'Only numeric characters are allowed' } = options;
    
    if (value) {
      const numericRegex = /^[0-9]+(\.[0-9]+)?$/;
      if (!numericRegex.test(value)) {
        return {
          isValid: false,
          error: {
            type: ErrorTypes.FORMAT,
            message,
            severity: Severity.MEDIUM
          }
        };
      }
    }
    
    return { isValid: true };
  });

  // Mask pattern validator (uses convertMaskToRegex from helpers)
  validators.set('maskPattern', (value, options = {}, context = {}) => {
    const { mask, message = 'Please match the requested format' } = options;
    
    if (value && mask) {
      const regexPattern = convertMaskToRegex(mask);
      if (regexPattern) {
        try {
          const regex = new RegExp(`^${regexPattern}$`);
          if (!regex.test(value)) {
            return {
              isValid: false,
              error: {
                type: ErrorTypes.FORMAT,
                message,
                severity: Severity.MEDIUM
              }
            };
          }
        } catch (error) {
        }
      }
    }
    
    return { isValid: true };
  });

  // Max length validator
  validators.set('maxLength', (value, options = {}, context = {}) => {
    const { maxLength, message } = options;
    
    if (value && maxLength && value.length > maxLength) {
      return {
        isValid: false,
        error: {
          type: ErrorTypes.FORMAT,
          message: message || `Maximum ${maxLength} characters allowed`,
          severity: Severity.MEDIUM
        }
      };
    }
    
    return { isValid: true };
  });

  // Accept text validator (for ACL acknowledgment)
  validators.set('acceptText', (value, options = {}, context = {}) => {
    const { message = 'You must type "Accept" to acknowledge' } = options;
    
    if (!value) {
      return {
        isValid: false,
        error: {
          type: ErrorTypes.REQUIRED,
          message,
          severity: Severity.HIGH
        }
      };
    }
    
    if (value.toLowerCase() !== 'accept') {
      // User has typed something but it's not exactly "Accept"
      return {
        isValid: false,
        error: {
          type: ErrorTypes.REQUIRED,
          message: `Please type exactly "Accept" (you typed: "${value}")`,
          severity: Severity.HIGH
        }
      };
    }
    
    return { isValid: true };
  });

  // Confirmation text validator (for Format="Confirm" fields)
  validators.set('confirmationText', (value, options = {}, context = {}) => {
    const { expectedText, message } = options;
    const defaultMessage = `You must type "${expectedText}" to confirm`;
    const finalMessage = message || defaultMessage;
    
    if (!value || value.toLowerCase() !== expectedText.toLowerCase()) {
      return {
        isValid: false,
        error: {
          type: ErrorTypes.REQUIRED,
          message: finalMessage,
          severity: Severity.HIGH
        }
      };
    }
    
    return { isValid: true };
  });

  // Match input validator (for Format="MatchInput" fields like email confirmation)
  validators.set('matchInput', (value, options = {}, context = {}) => {
    const { matchFieldName, message } = options;
    const { answers = {}, formItems = [] } = context;
    const defaultMessage = `The confirmation must match the ${matchFieldName} exactly.`;
    const finalMessage = message || defaultMessage;
    
    // Get the value of the field we need to match from constructed payload (formItems)
    let matchFieldValue = '';
    
    // Helper function to find actual field name by matching with language suffixes
    // Handles cases where MatchingInput doesn't have language suffix but actual field Name does
    const findActualFieldName = (fieldNameFromAttr) => {
      // Try exact match first
      let matchItem = formItems.find(item => item.Name === fieldNameFromAttr || item.NameRaw === fieldNameFromAttr);
      if (matchItem) {
        return matchItem.Name;
      }
      
      // Try matching where field Name starts with fieldNameFromAttr + '_' (for language suffixes)
      // e.g., MatchingInput="subByEmail" should match Name="subByEmail_KA"
      matchItem = formItems.find(item => {
        const itemName = item.Name?.trim();
        const itemNameRaw = item.NameRaw?.trim();
        return (itemName && itemName.startsWith(fieldNameFromAttr + '_')) ||
               (itemNameRaw && itemNameRaw === fieldNameFromAttr);
      });
      
      if (matchItem) {
        return matchItem.Name;
      }
      
      // Fallback: return original field name
      return fieldNameFromAttr;
    };
    
    // Find actual field name (handles language suffixes)
    const actualMatchFieldName = findActualFieldName(matchFieldName);
    
    // First try to get from constructed formItems (most up-to-date)
    const matchFormItem = formItems.find(item => item.Name === actualMatchFieldName);
    if (matchFormItem && matchFormItem.Answers && matchFormItem.Answers.length > 0) {
      const selectedAnswer = matchFormItem.Answers.find(answer => answer.Selected === true);
      matchFieldValue = selectedAnswer ? selectedAnswer.Answer : '';
    } else {
      // Fallback to answers object if formItem not found
      // Try both actual name and original name
      matchFieldValue = answers[actualMatchFieldName] || answers[matchFieldName] || '';
    }
    
    
    // Always validate match if either field has a value
    // This ensures confirmation fields work correctly regardless of required status
    if ((value || matchFieldValue) && value !== matchFieldValue) {
      return {
        isValid: false,
        error: {
          type: ErrorTypes.FORMAT,
          message: finalMessage,
          severity: Severity.MEDIUM
        }
      };
    }
    
    return { isValid: true };
  });
};

const createBusinessRules = () => {
  const rules = new Map();

  // Register built-in business rules
  registerBuiltInBusinessRules(rules);

  return {
    // Register a new business rule
    register: (name, rule) => {
      rules.set(name, rule);
    },

    // Get business rule by name
    get: (name) => rules.get(name),

    // Execute business rule
    execute: (ruleName, data, options = {}) => {
      const rule = rules.get(ruleName);
      if (!rule) {
        throw new Error(`Business rule '${ruleName}' not found`);
      }
      return rule(data, options);
    },

    // Get all registered business rules
    list: () => Array.from(rules.keys())
  };
};

/**
 * Registers built-in business rules
 */
const registerBuiltInBusinessRules = (rules) => {
  // SCORM completion validation rule
  rules.set('scormCompletion', (data, options = {}) => {
    const { formItems = [], answers = {} } = data;
    const { visibilityState = {} } = options;
    const errors = [];
    
    // Recursive function to check all SCORM items including nested ones
    const checkScormItems = (items) => {
      if (!Array.isArray(items)) return;
      
      items.forEach(item => {
        if (item.Type === 'ScormQuestionEditor' || item.Type === 'ScormQuestionEditorItemType') {
          if (item.Name && visibilityState[item.Name] === false) {
            return;
          }

          const status = answers[item.Name];
          const failOnIncomplete = item.Attributes?.find(
            attr => attr.AttributeName === 'FailOnInComplete'
          )?.AttributeValue;
          // Normalize failOnIncomplete to boolean (can be string 'true' or boolean true)
          const failOnIncompleteBoolean = failOnIncomplete === 'true' || failOnIncomplete === true;
          const isRequired = item.Required === 'true' || item.Required === true;
          
          // When either Required or FailOnInComplete is set, SCORM must be completed/passed
          if ((failOnIncompleteBoolean || isRequired) && status !== 'completed' && status !== 'passed') {
            const validationMessage = item.ValidationMessage ||
              `SCORM course '${item.HtmlStrippedText || item.Text || item.Name}' must be completed`;
            errors.push({
              type: ErrorTypes.BUSINESS_RULE,
              fieldName: item.Name,
              message: validationMessage,
              severity: Severity.HIGH,
              metadata: { field: item.Name }
            });
          }
        }
        
        // Check nested form items
        if (item.FormItems && Array.isArray(item.FormItems)) {
          checkScormItems(item.FormItems);
        }
      });
    };
    
    checkScormItems(formItems);
    
    return {
      isValid: errors.length === 0,
      errors
    };
  });
};

const createValidationOrchestrator = ({ fieldValidators, businessRules, errorManager, validationCache }) => {
  return {
    // Validate a single field
    validateField: (fieldName, value, options = {}) => {
      const cacheKey = `field_${fieldName}_${JSON.stringify(value)}_${JSON.stringify(options)}`;
      
      // Check cache first
      if (validationCache.has(cacheKey)) {
        return validationCache.get(cacheKey);
      }
      
      const result = {
        isValid: true,
        errors: []
      };
      
      // Get field configuration
      const fieldConfig = options.fieldConfig || {};
      const validators = fieldConfig.validators || [];
      
      // Run field validators
      validators.forEach(validatorConfig => {
        const { name, options: validatorOptions = {} } = validatorConfig;
        const validator = fieldValidators.get(name);
        
        if (validator) {
          // Pass context for validators that need access to other field values (like matchInput)
          const context = {
            answers: options.answers || {},
            formItems: options.formItems || [],
            visibilityState: options.visibilityState || {}
          };
          
          const validationResult = validator(value, validatorOptions, context);
          
          if (!validationResult.isValid) {
            result.isValid = false;
            result.errors.push({
              ...validationResult.error,
              fieldName
            });
          }
        }
      });
      
      // Cache result
      validationCache.set(cacheKey, result);
      
      return result;
    },

    // Validate entire form
    validateForm: (options = {}) => {
      const { formItems = [], answers = {}, visibilityState = {} } = options;
      
      
      const results = {
        isValid: true,
        fieldResults: {},
        formErrors: []
      };
      
      // Create a reference to the validateField method
      const validateFieldMethod = (fieldName, value, fieldOptions) => {
        const cacheKey = `field_${fieldName}_${JSON.stringify(value)}_${JSON.stringify(fieldOptions)}`;
        
        // Check cache first
        if (validationCache.has(cacheKey)) {
          return validationCache.get(cacheKey);
        }
        
        const result = {
          isValid: true,
          errors: []
        };
        
        // Get field configuration
        const fieldConfig = fieldOptions.fieldConfig || {};
        const validators = fieldConfig.validators || [];
        
        // Run field validators
        validators.forEach(validatorConfig => {
          const { name, options: validatorOptions = {} } = validatorConfig;
          const validator = fieldValidators.get(name);
          
          if (validator) {
            // Pass context for validators that need access to other field values (like matchInput)
            const context = {
              answers: fieldOptions.answers || {},
              formItems: fieldOptions.formItems || [],
              visibilityState: fieldOptions.visibilityState || {}
            };
            
            const validationResult = validator(value, validatorOptions, context);
            
            if (!validationResult.isValid) {
              result.isValid = false;
              result.errors.push({
                ...validationResult.error,
                fieldName,
                field: fieldName  // Add field property for compatibility
              });
            }
          }
        });
        
        // Cache the result
        validationCache.set(cacheKey, result);
        
        return result;
      };
      
      // Validate each visible field
      const validateFormItems = (items) => {
        if (!Array.isArray(items)) {
          return;
        }
        items.forEach(item => {
      if (item.Name && visibilityState[item.Name] === false) {
        return;
      }
      
      if (item.Name) {
        let value;
        if (item.Answers && item.Answers.length > 0) {
          const selectedAnswer = item.Answers.find(answer => answer.Selected === true);
          value = selectedAnswer ? selectedAnswer.Answer : '';
        } else {
          value = answers[item.Name] || '';
        }
        
        const fieldConfig = getFieldValidationConfig(item);
        const fieldResult = validateFieldMethod(item.Name, value, { 
          fieldConfig,
          answers,
          formItems,
          visibilityState
        });
        
        results.fieldResults[item.Name] = fieldResult;
            
            if (!fieldResult.isValid) {
              results.isValid = false;
              fieldResult.errors.forEach(error => {
                errorManager.addError(error);
              });
            }
          }
          
          // Process nested form items
          if (item.FormItems && Array.isArray(item.FormItems)) {
            validateFormItems(item.FormItems);
          }
        });
      };
      
      validateFormItems(formItems);
      
      return results;
    },

    // Validate business rules
    validateBusinessRules: (options = {}) => {
      const { formItems = [], answers = {}, rules = [] } = options;
      
      const results = {
        isValid: true,
        ruleResults: {},
        errors: []
      };
      
      // Extract answers from form items for business rules
      const extractedAnswers = {};
      const extractAnswers = (items) => {
        if (!Array.isArray(items)) {
          return;
        }
        items.forEach(item => {
          if (item.Name) {
            if (item.Answers && item.Answers.length > 0) {
              const selectedAnswer = item.Answers.find(answer => answer.Selected === true);
              extractedAnswers[item.Name] = selectedAnswer ? selectedAnswer.Answer : '';
            } else {
              extractedAnswers[item.Name] = answers[item.Name] || '';
            }
          }
          
          if (item.FormItems && Array.isArray(item.FormItems)) {
            extractAnswers(item.FormItems);
          }
        });
      };
      
      extractAnswers(formItems);
      
      // Execute each business rule
      rules.forEach(ruleName => {
        const rule = businessRules.get(ruleName);
        if (rule) {
          const ruleResult = rule({ formItems, answers: extractedAnswers }, options);
          results.ruleResults[ruleName] = ruleResult;
          
          if (!ruleResult.isValid) {
            results.isValid = false;
            results.errors.push(...ruleResult.errors);
            ruleResult.errors.forEach(error => {
              errorManager.addError(error);
            });
          }
        }
      });
      
      return results;
    }
  };
};


/**
 * Gets field validation configuration from form item
 */
const getFieldValidationConfig = (formItem) => {
  const config = {
    validators: []
  };
  
  if ((formItem.Required === 'true' || formItem.Required === true) && 
      !isBackendValidatedField(formItem.Type)) {
    const message = formItem.ValidationMessage || `${formItem.HtmlStrippedText || formItem.Name} is required`;
    config.validators.push({
      name: 'required',
      options: { message }
    });
  }
  
  // Add type-specific validators
  switch (formItem.Type) {
    case 'TextBox':
    case 'FAWInput':
      if (formItem.Attributes && Array.isArray(formItem.Attributes)) {
        processTextBoxAttributes(formItem, config);
      }
      
      // Check if this is a date field based on the Text property
      const isDateFieldDetected = isDateField(formItem);
      
      if (isDateFieldDetected) {
        // Add date validator for date fields
        config.validators.push({ name: 'date' });
      } else if (config.validators.length <= 1) {
        if (formItem.Name?.toLowerCase().includes('email')) {
          config.validators.push({ name: 'email' });
        } else if (formItem.Name?.toLowerCase().includes('phone')) {
          config.validators.push({ name: 'phone' });
        } else if (formItem.Name?.toLowerCase().includes('url')) {
          config.validators.push({ name: 'url' });
        } else if (formItem.Name?.toLowerCase().includes('percentage')) {
          config.validators.push({ name: 'percentage' });
        }
      }
      break;
      
    case 'Date':
      config.validators.push({ name: 'date' });
      break;
      
    case 'CheckBoxList':
      break;
      
    case 'KeyPersonnel':
    case 'PSACompany':
      break;
      
    case 'ScormQuestionEditor':
      break;
  }
  
  return config;
};


export default {
  createValidationEngine,
  ValidationResult,
  ErrorTypes,
  Severity
};
