import React, { useState, useEffect } from 'react';
import { Box, Alert } from '@mui/material';
import FAWButton from "../../../component-widget/FAWButton";
import FAWTypography from "../../../component-widget/FAWTypography";
import FAWLoader from "../../../component-widget/FAWLoader";
import axios from 'axios';

/**
 * ScormCourse - React component for SCORM course integration
 * Handles SCORM course loading, tracking, and completion
 */
const ScormCourse = ({
    courseId,
    connectionName = '',
    language = 'EN',
    failOnIncomplete = false,
    questionnaireAnswerId,
    responseContainerId,
    itemName,
    label = 'SCORM Course',
    required = false,
    error = false,
    helperText = '',
    onChange,
    registerValidationMethod,
    sx = {},
    ...props
}) => {
    const [scormData, setScormData] = useState(null);
    const [isLoading, setIsLoading] = useState(true);
    const [loadError, setLoadError] = useState(null);
    const [scormStatus, setScormStatus] = useState('not_started');
    const [lessonStatus, setLessonStatus] = useState('incomplete');
    const scormIframeRef = React.useRef(null);
    const lessonStatusRef = React.useRef(lessonStatus);

    // Load SCORM course data on mount
    useEffect(() => {
        if (courseId) {
            loadScormCourse();
        }
    }, [courseId, connectionName]);
    
    // Auto-setup SCORM API when data is loaded
    useEffect(() => {
        if (scormData && scormData.launchUrl) {
            setupScormAPI();
        }
    }, [scormData]);

    // Register validation method
    useEffect(() => {
        if (registerValidationMethod && typeof registerValidationMethod === 'function') {
            registerValidationMethod(itemName, validateScormCompletion);
        }
    }, [registerValidationMethod, itemName, required, failOnIncomplete, lessonStatus]);

    /**
     * Load SCORM course data from backend
     */
    const loadScormCourse = async () => {
        try {
            setIsLoading(true);
            setLoadError(null);

            const response = await axios.get('/Questionnaire/GetScormCourseData', {
                params: {
                    courseId,
                    connectionName,
                    language,
                    responseContainerId,
                    questionnaireAnswerId
                }
            });

            if (response.data && response.data.success) {
                const newStatus = response.data.data.lessonStatus || 'incomplete';
                setScormData(response.data.data);
                lessonStatusRef.current = newStatus;
                setLessonStatus(newStatus);
                setScormStatus(mapLessonStatusToScormStatus(newStatus));
                
                // Notify parent of initial status
                if (onChange && response.data.data.lessonStatus) {
                    onChange({
                        target: {
                            value: response.data.data.lessonStatus
                        }
                    });
                }
            } else {
                throw new Error(response.data?.error || 'Failed to load SCORM course');
            }
        } catch (error) {
            console.error('Error loading SCORM course:', error);
            setLoadError(error.message || 'Failed to load SCORM course');
        } finally {
            setIsLoading(false);
        }
    };

    /**
     * Map lesson status to SCORM status for UI display
     */
    const mapLessonStatusToScormStatus = (status) => {
        if (!status) return 'not_started';
        const statusLower = status.toLowerCase();
        
        if (statusLower === 'passed' || statusLower === 'completed') {
            return 'completed';
        } else if (statusLower === 'failed') {
            return 'failed';
        } else if (statusLower === 'incomplete' || statusLower === 'browsed') {
            return 'in_progress';
        }
        return 'not_started';
    };

    /**
     * Setup SCORM API for communication with course (iframe or window)
     */
    const setupScormAPI = () => {
        // Create SCORM API adapter that the SCORM content can access
        window.API = {
            LMSInitialize: () => {
                return 'true';
            },
            LMSFinish: () => {
                handleScormCompletion();
                return 'true';
            },
            LMSGetValue: (element) => {
                if (element === 'cmi.core.lesson_status') {
                    return lessonStatusRef.current;
                } else if (element === 'cmi.core.student_id') {
                    return scormData?.studentId || '';
                } else if (element === 'cmi.core.student_name') {
                    return scormData?.studentName || '';
                }
                return '';
            },
            LMSSetValue: (element, value) => {
                if (element === 'cmi.core.lesson_status') {
                    handleStatusChange(value);
                } else if (element === 'cmi.core.score.raw') {
                    handleScoreChange(value);
                }
                return 'true';
            },
            LMSCommit: () => {
                saveCMIData();
                return 'true';
            },
            LMSGetLastError: () => '0',
            LMSGetErrorString: () => '',
            LMSGetDiagnostic: () => ''
        };

        // Also support SCORM 2004 API
        window.API_1484_11 = {
            Initialize: () => window.API.LMSInitialize(),
            Terminate: () => window.API.LMSFinish(),
            GetValue: (element) => window.API.LMSGetValue(element),
            SetValue: (element, value) => window.API.LMSSetValue(element, value),
            Commit: () => window.API.LMSCommit(),
            GetLastError: () => window.API.LMSGetLastError(),
            GetErrorString: () => window.API.LMSGetErrorString(),
            GetDiagnostic: () => window.API.LMSGetDiagnostic()
        };
    };

    /**
     * Handle SCORM status change
     */
    const handleStatusChange = async (newStatus) => {
        lessonStatusRef.current = newStatus;
        setLessonStatus(newStatus);
        setScormStatus(mapLessonStatusToScormStatus(newStatus));

        // Notify parent component
        if (onChange) {
            onChange({
                target: {
                    value: newStatus
                }
            });
        }

        // Save to backend
        await saveCMIData(newStatus);
    };

    /**
     * Handle score change
     */
    const handleScoreChange = (score) => {
        // You can track score if needed
    };

    /**
     * Save CMI data to backend
     */
    const saveCMIData = async (status) => {
        const statusToSave = status ?? lessonStatusRef.current;
        try {
            await axios.post('/Questionnaire/SaveScormProgress', {
                courseId,
                connectionName,
                responseContainerId,
                questionnaireAnswerId,
                lessonStatus: statusToSave
            });
        } catch (error) {
            console.error('Error saving SCORM progress:', error);
        }
    };

    /**
     * Handle SCORM course completion
     */
    const handleScormCompletion = async () => {
        const currentStatus = lessonStatusRef.current;
        const completedStatus = currentStatus === 'failed' ? 'failed' : 'completed';
        await handleStatusChange(completedStatus);
    };

    /**
     * Validate SCORM completion
     */
    const validateScormCompletion = () => {
        if (!required && !failOnIncomplete) {
            return null;
        }

        if (lessonStatus !== 'completed' && lessonStatus !== 'passed') {
            return `SCORM course '${label}' must be completed`;
        }

        return null;
    };

    /**
     * Get status color
     */
    const getStatusColor = () => {
        switch (scormStatus) {
            case 'completed':
                return '#4caf50'; // Green
            case 'failed':
                return '#f44336'; // Red
            case 'in_progress':
                return '#ff9800'; // Orange
            default:
                return '#9e9e9e'; // Gray
        }
    };

    /**
     * Get status label
     */
    const getStatusLabel = () => {
        switch (scormStatus) {
            case 'completed':
                return 'Completed';
            case 'failed':
                return 'Failed - Try Again';
            case 'in_progress':
                return 'In Progress';
            default:
                return 'Not Started';
        }
    };

    // Loading state
    if (isLoading) {
        return (
            <Box sx={{ p: 3, textAlign: 'center', ...sx }} {...props}>
                <FAWLoader size={40} label="Loading SCORM course..." />
            </Box>
        );
    }

    // Error state
    if (loadError) {
        return (
            <Box sx={{ ...sx }} {...props}>
                <Alert severity="error">
                    <FAWTypography variant="body2">
                        {loadError}
                    </FAWTypography>
                </Alert>
                <Box sx={{ mt: 2 }}>
                    <FAWButton
                        variant="outlined"
                        onClick={loadScormCourse}
                    >
                        Retry
                    </FAWButton>
                </Box>
            </Box>
        );
    }

    // Main view - Course content loaded directly (no button required)
    return (
        <Box
            sx={{
                border: '1px solid #e0e0e0',
                borderRadius: 1,
                backgroundColor: '#fafafa',
                ...(error && {
                    borderColor: '#f44336',
                    backgroundColor: '#ffebee'
                }),
                ...sx
            }}
            {...props}
        >
            {/* Header */}
            <Box sx={{ p: 2, pb: 1 }}>
                <FAWTypography variant="h6" sx={{ fontWeight: 'bold', mb: 1 }}>
                    {label}
                    {required && <span style={{ color: '#f44336', marginLeft: 4 }}>*</span>}
                </FAWTypography>
                
                {scormData?.courseTitle && (
                    <FAWTypography variant="body2" sx={{ color: '#666' }}>
                        {scormData.courseTitle}
                    </FAWTypography>
                )}
            </Box>

            {/* SCORM Content Box - Displayed directly */}
            <Box
                sx={{
                    position: 'relative',
                    width: 'calc(100% - 32px)',
                    height: '70vh',
                    minHeight: '500px',
                    border: '2px solid #2196f3',
                    borderRadius: 1,
                    backgroundColor: '#fff',
                    overflow: 'hidden',
                    mx: 2,
                    mb: 2
                }}
            >
                <iframe
                    ref={scormIframeRef}
                    src={scormData?.launchUrl}
                    title={scormData?.courseTitle || 'SCORM Course'}
                    style={{
                        width: '100%',
                        height: '100%',
                        border: 'none',
                        display: 'block'
                    }}
                    allow="autoplay; fullscreen"
                    sandbox="allow-same-origin allow-scripts allow-popups allow-forms allow-modals"
                />
            </Box>

            {/* Status Display at Bottom */}
            <Box sx={{ p: 2, pt: 0 }}>
                <Box
                    sx={{
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'space-between',
                        p: 2,
                        backgroundColor: '#fff',
                        borderRadius: 1,
                        border: '1px solid #e0e0e0'
                    }}
                >
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5 }}>
                        <Box
                            sx={{
                                width: 12,
                                height: 12,
                                borderRadius: '50%',
                                backgroundColor: getStatusColor()
                            }}
                        />
                        <Box>
                            <FAWTypography variant="body2" sx={{ fontWeight: 'bold', color: '#666', mb: 0.5 }}>
                                Status:
                            </FAWTypography>
                            <FAWTypography variant="body1" sx={{ color: getStatusColor(), fontWeight: 'bold' }}>
                                {getStatusLabel()}
                            </FAWTypography>
                        </Box>
                    </Box>
                </Box>

                {/* Completion Message */}
                {scormStatus === 'completed' && (
                    <Alert severity="success" sx={{ mt: 2 }}>
                        <FAWTypography variant="body2">
                            ✓ Course completed successfully!
                        </FAWTypography>
                    </Alert>
                )}

                {/* Failed Message */}
                {scormStatus === 'failed' && (
                    <Alert severity="error" sx={{ mt: 2 }}>
                        <FAWTypography variant="body2">
                            Course not passed. Please try again.
                        </FAWTypography>
                    </Alert>
                )}

                {/* Helper Text / Error */}
                {(helperText || error) && (
                    <FAWTypography
                        variant="caption"
                        sx={{
                            color: error ? '#f44336' : '#666',
                            display: 'block',
                            mt: 1
                        }}
                    >
                        {helperText}
                    </FAWTypography>
                )}

                {/* Fail on Incomplete Warning */}
                {failOnIncomplete && scormStatus !== 'completed' && (
                    <Alert severity="warning" sx={{ mt: 2 }}>
                        <FAWTypography variant="body2">
                            ⚠️ This training must be completed to proceed.
                        </FAWTypography>
                    </Alert>
                )}
            </Box>
        </Box>
    );
};

export default ScormCourse;

