import React, { useState, useEffect } from "react";
import axios from "axios";
import update from "immutability-helper";
import { findIndex } from "lodash";
import { Box, Container, Tabs, Tab, ButtonGroup, Stack, Alert, CircularProgress } from "@mui/material";
import FAWButton from "../../../component-widget/FAWButton";
import FAWLoader from "../../../component-widget/FAWLoader";
import FAWAlert from "../../../component-widget/FAWAlert";
import FAWThemeProvider from "../../../Theme/FAWThemeProvider";
import FAWSkeleton from "../../../component-widget/FAWSkeleton";
import CountryTab from "./CountryTab";
import { selectionType, displayText, defaultQuestionText, defaultGeneralInfo } from "./constants";

function RegionCountrySelect(props) {
  const [regionInfo, setRegionInfo] = useState([]);
  const [answers, setAnswers] = useState([]);
  const [page, setPage] = useState("Asia");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(false);
  const [initFail, setInitFail] = useState(false);
  const [initFetch, setInitFetch] = useState(true);
  const [refetch, setRefetch] = useState(0);
  const [editting, setEditting] = useState(false);
   const [original, setOriginal] = useState([]);
   const [translations, setTranslations] = useState([]);

  useEffect(
    () => {
      const fetchCountries = async () => {
        setInitFail(false);
        setInitFetch(true);
        try {
          const { data } = await axios.get(
            "/Questionnaire/LoadCountriesByRegion"
           );

           const { countriesByRegion, Translations } = data;
           setTranslations(Translations);

          const mapped = countriesByRegion.map(region => {
            const countries = region.Countries.map(rc => {
               return {
                  countryCode: rc.IsoCode,
                  display: rc.Name || rc.EnglishName
               };

            });

             return {
                continent: region.Name,
                continentEnglish: region.EnglishName,
                countries
             };
          });

          setInitFetch(false);
          setRegionInfo(mapped);
        } catch (e) {
          setInitFetch(false);
          setInitFail(true);
        }
      };

      fetchCountries();
    },
    [refetch]
  );

  useEffect(() => {
    const fetchInit = async () => {
      const { data } = await axios.get("/Questionnaire/LoadSavedCountries");
      setAnswers(data);
      setOriginal(data);
    };

    fetchInit();
  }, []);

  // Register validation method for form validation
  useEffect(() => {
    if (props.registerValidationMethod) {
      props.registerValidationMethod('CountrySelect', () => {
        // Only validate if the field is required
        if (props.required) {
          // Check if table has active data (excluding items marked for deletion)
          if (!answers || answers.length === 0) {
            return {
              field: 'countrySelect',
              message: "Country/Region Selection requires at least one entry. Please add data to continue."
            };
          }
          
          // Filter out items marked for deletion to get actual active selections
          const activeAnswers = answers.filter(answer => !answer.MarkForDelete);
          
          if (activeAnswers.length === 0) {
            return {
              field: 'countrySelect',
              message: "Country/Region Selection requires at least one entry. Please add data to continue."
            };
          }
        }
        
        // Return null if validation passes (has active selections)
        return null;
      });
    }
  }, [answers, props.registerValidationMethod, props.required]);

   const findLabel = id => {
      if (translations) {
         const message = translations.find(x => x.Id === id);
         return message ? message.Label : defaultQuestionText[id];
      }

      return defaultQuestionText[id];
   }

   const findDescription = id => {
      if (translations) {
         const message = translations.find(x => x.Id === id);
         return message ? message.Description : defaultGeneralInfo[id];
      }

      return defaultGeneralInfo[id];
   }

  const createNewAnswer = countryCode => {
    return {
      QuestionnaireAnswerId: 0,
      Name: "CountrySelect",
      GroupIndicator: "False",
      Value: countryCode,
      HasDocument: false,
      Language: "EN",
      IgnoreDocument: true
    };
  };

  const getCountryIndex = countryCode => {
    return findIndex(answers, ans => ans.Value === countryCode);
  };

  const updateAnswers = countryCode => {
    const idx = getCountryIndex(countryCode);

    if (idx !== -1) {
      if (answers[idx].Id) {
        setAnswers(c =>
          update(c, {
            [idx]: { MarkForDelete: { $set: !c[idx].MarkForDelete } }
          })
        );
      } else {
        setAnswers(c =>
          update(c, {
            $splice: [[findIndex(c, ans => ans.Value === countryCode), 1]]
          })
        );
      }
    } else {
      const newAnswer = createNewAnswer(countryCode);

      setAnswers(c => update(c, { $push: [newAnswer] }));
    }
  };

  const handleSelectionToggle = (selection, countries) => {
    if (selection === selectionType.DESELECT_ALL) {
      countries.map(({ countryCode }) => {
        const idx = getCountryIndex(countryCode);

        if (idx !== -1 && answers[idx].Id) {
          if (answers[idx].MarkForDelete === false) {
            setAnswers(c =>
              update(c, {
                [idx]: { MarkForDelete: { $set: true } }
              })
            );
          }
        } else {
          setAnswers(c => c.filter(i => i.Id));
        }
      });
    } else {
      countries.map(({ countryCode }) => {
        const idx = getCountryIndex(countryCode);

        if (idx === -1) {
          const newAnswer = createNewAnswer(countryCode);

          setAnswers(c => update(c, { $push: [newAnswer] }));
        } else {
          if (answers[idx].MarkForDelete === true) {
            setAnswers(c =>
              update(c, {
                [idx]: { MarkForDelete: { $set: false } }
              })
            );
          }
        }
      });
    }
  };

  const saveCountries = async () => {
    setLoading(true);
    try {
      const { data } = await axios.post("/Questionnaire/SaveCountries", {
        answers
      });

      setLoading(false);
      setAnswers(data);
      setOriginal(data);
    } catch (e) {
      setLoading(false);
      setError(true);
    }

    setEditting(false);
  };

  const toggleEditting = () => {
    setEditting(c => !c);
  };

  const cancelEditting = () => {
    setAnswers(original);
    setEditting(false);
  };

  if (initFail) {
    return (
      <FAWThemeProvider>
        <Box sx={{ px: 5, pt: 2 }}>
          <FAWAlert
            severity="error"
            title={findLabel(displayText.CountrySelectLoadError)}
            message={findDescription(displayText.CountrySelectLoadError)}
            action={
              <FAWButton
                variant="outlined"
                color="inherit"
                onClick={() => setRefetch(c => c + 1)}
              >
                {findLabel(displayText.Retry)}
              </FAWButton>
            }
          />
        </Box>
      </FAWThemeProvider>
    );
  }

  if (initFetch) {
    return (
      <FAWThemeProvider>
        <Box sx={{ px: 5, pt: 2 }}>
          <FAWSkeleton variant="countrySelect" />
        </Box>
      </FAWThemeProvider>
    );
  }

  return (
    regionInfo.length > 0 && (
      <FAWThemeProvider>
        <Box sx={{ px: 5, pt: 2 }}>
          <Box sx={{ borderBottom: 1, borderColor: 'divider' }}>
            <Tabs
              value={page}
              onChange={(event, newValue) => setPage(newValue)}
              variant="scrollable"
              scrollButtons="auto"
              sx={{ width: '100%' }}
            >
              {regionInfo.map(({ continent, continentEnglish }) => (
                <Tab
                  key={continentEnglish}
                  label={continent}
                  value={continentEnglish}
                />
              ))}
            </Tabs>
          </Box>
        <React.Fragment>
          <CountryTab
                 region={regionInfo.find(rg => rg.continentEnglish === page) || []}
                 answers={answers}
                 updateAnswers={updateAnswers}
                 handleSelectionToggle={handleSelectionToggle}
                 editting={editting}
                 translations={translations}
          />
          <Box sx={{ mt: 2 }}>
            {!editting ? (
              <FAWButton
                variant="contained"
                color="primary"
                onClick={toggleEditting}
                sx={{ width: '5em' }}
              >
                {findLabel(displayText.Edit)}
              </FAWButton>
            ) : (
              <Stack direction="row" spacing={2} sx={{ py: 2 }}>
                <FAWButton
                  variant="contained"
                  color="primary"
                  disabled={loading}
                  onClick={saveCountries}
                >
                  {loading ? (
                    <FAWLoader size={20} />
                  ) : (
                    findLabel(displayText.Save)
                  )}
                </FAWButton>
                <FAWButton
                  variant="outlined"
                  color="inherit"
                  onClick={cancelEditting}
                  disabled={loading}
                >
                  {findLabel(displayText.Cancel)}
                </FAWButton>
              </Stack>
            )}
          </Box>
          {error && (
            <FAWAlert
              severity="error"
              title={findLabel(displayText.CountrySelectSaveError)}
              message={findDescription(displayText.CountrySelectSaveError)}
              onClose={() => setError(false)}
              sx={{ mt: 2 }}
            />
          )}
        </React.Fragment>
        </Box>
      </FAWThemeProvider>
    )
  );
}

export default RegionCountrySelect;
