import React from 'react';
import { Alert } from '@mui/material';
import FAWTypography from '../../FAWTypography';

class FormItemErrorBoundary extends React.Component {
    constructor(props) {
        super(props);
        this.state = { hasError: false, error: null };
    }

    static getDerivedStateFromError(error) {
        return { hasError: true, error };
    }

    componentDidCatch(error, errorInfo) {
        console.error('🚨 Form item error:', {
            itemName: this.props.itemName,
            itemType: this.props.itemType,
            error: error.message,
            errorInfo
        });
    }

    render() {
        if (this.state.hasError) {
            return (
                <Alert severity="warning" sx={{ marginBottom: 2 }}>
                    <FAWTypography variant="body2">
                        <strong>Component Error:</strong> {this.props.itemName || 'Unknown Item'} 
                        ({this.props.itemType || 'Unknown Type'})
                    </FAWTypography>
                    <FAWTypography variant="caption" sx={{ display: 'block' }}>
                        {this.state.error?.message || 'Component failed to render'}
                    </FAWTypography>
                    {process.env.NODE_ENV === 'development' && (
                        <FAWTypography variant="caption" sx={{ display: 'block', mt: 1, fontFamily: 'monospace' }}>
                            {this.state.error?.stack}
                        </FAWTypography>
                    )}
                </Alert>
            );
        }

        return this.props.children;
    }
}

export default FormItemErrorBoundary;
