import { colors } from '../../../../utils/designTokens';

/**
 * Utility functions for scroll-to-error functionality
 */

/**
 * Scrolls smoothly to a form field with the given name
 * Uses the same pattern as QuestionnaireHeader component
 * @param {string} fieldName - The name of the field to scroll to
 * @param {Object} options - Scroll options
 */
export const scrollToField = (fieldName, options = {}) => {
    const {
        behavior = 'smooth',
        block = 'center'
    } = options;

    try {
        
        // Handle special business rule field names
        let actualFieldName = fieldName;
        let element = null;
        
        // Map business rule field names to actual component selectors
        if (fieldName === 'keyPersonnel') {
            // Look for KeyPersonnel component
            element = document.querySelector('[data-field-name*="KeyPersonnel"], .key-personnel-container, [id*="KeyPersonnel"]');
        } else if (fieldName === 'psaCompany') {
            // Look for PSACompany component
            element = document.querySelector('[data-field-name*="PSACompany"], .psa-company-container, [id*="PSACompany"]');
        } else if (fieldName === 'countrySelect') {
            // Look for CountrySelect component
            element = document.querySelector('[data-field-name*="CountrySelect"], .country-select-container, [id*="CountrySelect"]');
        } else if (fieldName === 'tableData') {
            // Generic tableData - try to find any table component
            element = document.querySelector('.key-personnel-container, .psa-company-container, .country-select-container');
        }
        
        // If not found by special handling, try standard approaches
        if (!element) {
            // Try to find the field by data-field-name attribute first (our new format)
            element = document.querySelector(`[data-field-name="${actualFieldName}"]`);
        }
        
        // If not found by data attribute, try to find by name attribute
        if (!element) {
            element = document.querySelector(`[name="${actualFieldName}"]`);
        }
        
        // If still not found, try to find any element containing the field name
        if (!element) {
            element = document.querySelector(`[id*="${actualFieldName}"], [class*="${actualFieldName}"]`);
        }

        if (element) {
            // Use the same scrollIntoView method as QuestionnaireHeader
            element.scrollIntoView({
                behavior: behavior,
                block: block
            });

            // Focus the element if it's focusable
            setTimeout(() => {
                try {
                    if (element.focus && typeof element.focus === 'function') {
                        element.focus();
                        
                        // If it's an input, select the text
                        if (element.select && typeof element.select === 'function') {
                            element.select();
                        }
                    }
                } catch (e) {
                    // Ignore focus errors
                    console.debug('Could not focus element:', e);
                }
            }, 300); // Small delay to ensure scroll completes

            // Add a temporary highlight effect
            addHighlightEffect(element);
            
            return true;
        } else {
            console.warn(`Could not find field with name: ${fieldName}`);
            return false;
        }
    } catch (error) {
        console.error('Error scrolling to field:', error);
        return false;
    }
};

/**
 * Adds a temporary highlight effect to an element
 * @param {HTMLElement} element - The element to highlight
 */
const addHighlightEffect = (element) => {
    try {
        // Add highlight class
        element.classList.add('field-highlight');
        
        // Create highlight styles if they don't exist
        if (!document.getElementById('scroll-to-error-styles')) {
            const linkColor = colors.action.link.default || '#1976d2';
            // Convert hex to RGB for rgba usage
            const hexToRgb = (hex) => {
                const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
                return result ? {
                    r: parseInt(result[1], 16),
                    g: parseInt(result[2], 16),
                    b: parseInt(result[3], 16)
                } : { r: 25, g: 118, b: 210 };
            };
            const rgb = hexToRgb(linkColor);
            
            const style = document.createElement('style');
            style.id = 'scroll-to-error-styles';
            style.textContent = `
                .field-highlight {
                    animation: fieldHighlight 2s ease-in-out;
                    transition: all 0.3s ease;
                }
                
                @keyframes fieldHighlight {
                    0% { 
                        box-shadow: 0 0 0 3px rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0.4);
                        background-color: rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0.1);
                    }
                    50% { 
                        box-shadow: 0 0 0 6px rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0.2);
                        background-color: rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0.05);
                    }
                    100% { 
                        box-shadow: 0 0 0 0 rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0);
                        background-color: transparent;
                    }
                }
                
                .field-highlight input,
                .field-highlight textarea,
                .field-highlight .MuiOutlinedInput-root {
                    border-color: ${linkColor} !important;
                }
            `;
            document.head.appendChild(style);
        }
        
        // Remove highlight after animation
        setTimeout(() => {
            element.classList.remove('field-highlight');
        }, 2000);
    } catch (error) {
        console.debug('Could not add highlight effect:', error);
    }
};

/**
 * Scrolls to the first error field from a list of errors
 * @param {Array} errors - Array of error objects with field property
 * @param {Object} options - Scroll options
 */
export const scrollToFirstError = (errors, options = {}) => {
    if (!errors || errors.length === 0) {
        return false;
    }
    
    // Find the first error with a field name
    const firstFieldError = errors.find(error => error.field && error.field !== 'general' && error.field !== 'system');
    
    if (firstFieldError) {
        return scrollToField(firstFieldError.field, options);
    }
    
    return false;
};

/**
 * Scrolls to the main error box that displays form submission errors
 * @param {Object} options - Scroll options
 */
export const scrollToMainErrorBox = (options = {}) => {
    const {
        behavior = 'smooth',
        block = 'center'
    } = options;

    try {
        const errorBox = document.getElementById('main-error-box');
        
        if (errorBox) {
            errorBox.scrollIntoView({
                behavior: behavior,
                block: block
            });
            return true;
        }
        
        return false;
    } catch (error) {
        console.error('Error scrolling to main error box:', error);
        return false;
    }
};

/**
 * Creates a clickable error message that scrolls to the field when clicked
 * @param {string} fieldName - The name of the field
 * @param {string} message - The error message
 * @param {Object} options - Options for styling and behavior
 */
export const createClickableErrorMessage = (fieldName, message, options = {}) => {
    const {
        className = 'clickable-error',
        style = {},
        onClick = null
    } = options;
    
    const handleClick = (e) => {
        e.preventDefault();
        e.stopPropagation();
        
        const scrolled = scrollToField(fieldName);
        
        // Call custom onClick if provided
        if (onClick && typeof onClick === 'function') {
            onClick(fieldName, scrolled);
        }
    };
    
    return {
        message,
        fieldName,
        onClick: handleClick,
        className: `${className} cursor-pointer hover:underline`,
        style: {
            cursor: 'pointer',
            color: colors.action.link.default,
            textDecoration: 'underline',
            ...style
        }
    };
};
