import React from 'react';
import { Box, Alert } from '@mui/material';
import FAWTypography from '../../FAWTypography';
import RequiredIndicator from '../../RequiredIndicator';
import FormItemErrorBoundary from './FormItemErrorBoundary';
import { componentTypeMap } from '../utils/componentMapping';
import { createComponentProps } from '../utils/componentPropsGenerator';
import { updateStateOptionsForCountry, isStateFiltering as checkStateFiltering } from '../utils/stateOptionsManager';
import { parseHtmlContent } from '../utils/htmlParser';
import '../styles/questionnaire.css';

/**
 * Get CSS class name for consistent form styling
 */
const getFormComponentClassName = (componentType) => {
    // Handle both Atlas component names and legacy types
    switch (componentType) {
        // Atlas component names
        case 'FAWInput':
        case 'TextBox':
        case 'Date':
        case 'SelfIdentification':
        case 'Relationship':
        case 'ScormQuestionEditor':
        case 'CustomFields':
            return 'que-input';
        
        case 'FAWDropdown':
        case 'DropDownMultiSelect':
            return 'que-dropdown';
        
        case 'FAWSelect':
        case 'DropDownList':
        case 'CustomValueSelector':
            return 'que-select';
        
        case 'FAWRadioGroup':
        case 'RadioButtonList':
            return 'que-radio';
        
        case 'FAWCheckbox':
        case 'FAWCheckboxGroup':
        case 'CheckBoxList':
            return 'que-checkbox';
        
        case 'FAWTypography':
        case 'Label':
        case 'ACL':
        case 'FormLogin':
        case 'FormLoginPage':
            return 'que-typography';
        
        default:
            return 'que-component';
    }
};

/**
 * Get CSS class name for scroll-to-error functionality
 */
const getScrollableClassName = (componentType) => {
    switch (componentType) {
        case 'KeyPersonnel':
            return 'key-personnel-container';
        case 'PSACompany':
            return 'psa-company-container';
        case 'CountrySelect':
        case 'RegionCountrySelect':
            return 'country-select-container';
        default:
            return '';
    }
};

const FormRenderer = ({ 
    formItems, 
    visibilityState, 
    initialAnswers, 
    answerId,
    responseContainerId,
    language,
    saveAnswerToAPI,
    onDependencyChange,
    fieldErrors,
    onAnswersChange,
    onFormItemsChange,
    onFileDataRefresh,
    allFileData,
    registerValidationMethod,
    validateField,
    ...rest
}) => {

    const [answers, setAnswers] = React.useState(initialAnswers || {});
    const [isStateFiltering, setIsStateFiltering] = React.useState({});
    const [filteringTrigger, setFilteringTrigger] = React.useState(0);
    
    const debouncedSaveRef = React.useRef({});
    
    // Monitor state filtering status for all state fields
    React.useEffect(() => {
        const stateFields = formItems.filter(item => item.Name === 'state' || item.Name === 'genQuest116');
        if (stateFields.length === 0) {
            return;
        }

        const checkFilteringStatus = () => {
            const fieldLoadingStates = {};
            let hasActiveFiltering = false;
            
            stateFields.forEach(field => {
                const isLoading = checkStateFiltering(field.Name);
                fieldLoadingStates[field.Name] = isLoading;
                if (isLoading) {
                    hasActiveFiltering = true;
                }
            });
            
            setIsStateFiltering(fieldLoadingStates);
            return hasActiveFiltering;
        };
        
        // Check immediately
        const hasActiveFiltering = checkFilteringStatus();
        
        // Only set up polling if there's active filtering
        let intervalId = null;
        if (hasActiveFiltering) {
            intervalId = setInterval(() => {
                const stillFiltering = checkFilteringStatus();
                if (!stillFiltering) {
                    clearInterval(intervalId);
                }
            }, 100);
        }
        
        return () => {
            if (intervalId) {
                clearInterval(intervalId);
            }
        };
    }, [formItems, filteringTrigger]);
    
    // Initialize all form fields in answers object when component mounts
    React.useEffect(() => {
        if (formItems && formItems.length > 0) {
            const initializedAnswers = { ...answers };
            let hasChanges = false;
            
            formItems.forEach(item => {
                if (item.Name) {
                    const isMultiSelect = item.Type === 'CheckBoxList' || item.Type === 'DropDownMultiSelect';
                    const currentValue = initializedAnswers[item.Name];
                    
                    // For multi-select fields: ensure value is an array (fix incorrect string values)
                    if (isMultiSelect) {
                        // Check if value is undefined OR if it's incorrectly set as a string
                        if (currentValue === undefined || !Array.isArray(currentValue)) {
                            const selectedAnswers = (item.Answers || [])
                                .filter(ans => ans && ans.Selected !== false && ans.Deleted !== true)
                                .map(ans => ans.Answer || ans.Value)
                                .filter(val => val !== null && val !== undefined && val !== '');
                            initializedAnswers[item.Name] = selectedAnswers.length > 0 ? selectedAnswers : [];
                            hasChanges = true;
                        }
                    } else {
                        // For single-select fields: initialize only if undefined
                        if (currentValue === undefined) {
                            const originalValue = item.Answers?.[0]?.Answer || item.Answers?.[0]?.Value || '';
                            initializedAnswers[item.Name] = originalValue;
                            hasChanges = true;
                        }
                    }
                }
            });
            
            if (hasChanges) {
                setAnswers(initializedAnswers);
            }
        }
    }, [formItems]); // Only run when formItems change
    
    const debouncedSaveAnswer = (itemName, value) => {
        if (debouncedSaveRef.current[itemName]) {
            clearTimeout(debouncedSaveRef.current[itemName]);
        }
        debouncedSaveRef.current[itemName] = setTimeout(() => {
            if (saveAnswerToAPI) {
                saveAnswerToAPI(itemName, value, false);
            }
        }, 1000);
    };

    const handleAnswerChange = (itemName, value) => {
        // Find form item in nested structure
        const findFormItemRecursive = (items, targetName) => {
            for (const item of items) {
                if (item.Name === targetName) {
                    return { item, parentItems: items };
                }
                if (item.FormItems && Array.isArray(item.FormItems)) {
                    const result = findFormItemRecursive(item.FormItems, targetName);
                    if (result) {
                        return result;
                    }
                }
            }
            return null;
        };

        const searchResult = findFormItemRecursive(formItems, itemName);
        if (!searchResult) {
            console.warn(`FormItem not found: ${itemName}`);
            return;
        }

        
        // Update nested FormItems structure
        const updateFormItemsRecursive = (items) => {
            return items.map(item => {
                if (item.Name === itemName) {
                    const updatedItem = { ...item };
                
                // Ensure Answers array exists
                if (!updatedItem.Answers) {
                    updatedItem.Answers = [];
                }

                // Handle different input types
                switch (item.Type) {
                    case 'TextBox':
                    case 'Date':
                    case 'SelfIdentification':
                    case 'ScormQuestionEditor':
                    case 'Relationship':
                        // Single value inputs - update first answer
                        if (updatedItem.Answers.length === 0) {
                            updatedItem.Answers.push({
                                Id: 0,
                                Answer: value || '',
                                Value: value || '',
                                Selected: true,
                                Deleted: false
                            });
                        } else {
                            updatedItem.Answers[0] = {
                                ...updatedItem.Answers[0],
                                Answer: value || '',
                                Value: value || ''
                            };
                        }
                        break;

                    case 'DropDownList':
                    case 'CustomValueSelector':
                        // Single selection dropdown - update first answer
                        if (updatedItem.Answers.length === 0) {
                            updatedItem.Answers.push({
                                Id: 0,
                                Answer: value || '',
                                Value: value || '',
                                Selected: true,
                                Deleted: false
                            });
                        } else {
                            updatedItem.Answers[0] = {
                                ...updatedItem.Answers[0],
                                Answer: value || '',
                                Value: value || ''
                            };
                        }
                        break;

                    case 'RadioButtonList':
                    case 'FAWRadioGroup':
                        // Single selection radio - update first answer
                        if (updatedItem.Answers.length === 0) {
                            updatedItem.Answers.push({
                                Id: 0,
                                Answer: value || '',
                                Value: value || '',
                                Selected: true,
                                Deleted: false
                            });
                        } else {
                            updatedItem.Answers[0] = {
                                ...updatedItem.Answers[0],
                                Answer: value || '',
                                Value: value || ''
                            };
                        }
                        break;

                    case 'CheckBoxList':

                        if (Array.isArray(value)) {
                            // Normalize current values to strings for comparison
                            const selectedValues = value
                                .filter(val => val !== null && val !== undefined && val !== '')
                                .map(val => String(val));
                            
                            updatedItem.Answers = [];
                            
                            // Process all existing answers (to handle deletions)
                            const existingAnswers = item.Answers || [];
                            existingAnswers.forEach((existingAnswer) => {
                                if (existingAnswer && !existingAnswer.Deleted) {
                                    const answerValue = String(existingAnswer.Answer || existingAnswer.Value || '');
                                    const isSelected = selectedValues.includes(answerValue);
                                    
                                    updatedItem.Answers.push({
                                        Id: existingAnswer.Id || 0,
                                        Answer: answerValue,
                                        Value: answerValue,
                                        Selected: isSelected,
                                        Deleted: !isSelected // Mark as deleted if not in selected values
                                    });
                                }
                            });
                            
                            // Add new answers for values that don't have existing answers
                            selectedValues.forEach((val) => {
                                const hasExistingAnswer = existingAnswers.some(
                                    ans => ans && !ans.Deleted && (String(ans.Answer || ans.Value || '') === val)
                                );
                                if (!hasExistingAnswer) {
                                    updatedItem.Answers.push({
                                        Id: 0, // New answer
                                        Answer: val,
                                        Value: val,
                                        Selected: true,
                                        Deleted: false
                                    });
                                }
                            });
                        } else {
                            // Single value - update first answer (fallback for non-array values)
                            if (updatedItem.Answers.length === 0) {
                                updatedItem.Answers.push({
                                    Id: 0,
                                    Answer: value || '',
                                    Value: value || '',
                                    Selected: true,
                                    Deleted: false
                                });
                            } else {
                                updatedItem.Answers[0] = {
                                    ...updatedItem.Answers[0],
                                    Answer: value || '',
                                    Value: value || ''
                                };
                            }
                        }
                        break;

                    case 'DropDownMultiSelect':
                        if (Array.isArray(value)) {
                            // Normalize current values to strings for comparison
                            const selectedValues = value
                                .filter(val => val !== null && val !== undefined && val !== '')
                                .map(val => String(val));
                            
                            updatedItem.Answers = [];
                            
                            // Process all existing answers (to handle deletions)
                            const existingAnswers = item.Answers || [];
                            existingAnswers.forEach((existingAnswer) => {
                                if (existingAnswer && !existingAnswer.Deleted) {
                                    const answerValue = String(existingAnswer.Answer || existingAnswer.Value || '');
                                    const isSelected = selectedValues.includes(answerValue);
                                    
                                    updatedItem.Answers.push({
                                        Id: existingAnswer.Id || 0,
                                        Answer: answerValue,
                                        Value: answerValue,
                                        Selected: isSelected,
                                        Deleted: !isSelected // Mark as deleted if not in selected values
                                    });
                                }
                            });
                            
                            // Add new answers for values that don't have existing answers
                            selectedValues.forEach((val) => {
                                const hasExistingAnswer = existingAnswers.some(
                                    ans => ans && !ans.Deleted && (String(ans.Answer || ans.Value || '') === val)
                                );
                                if (!hasExistingAnswer) {
                                    updatedItem.Answers.push({
                                        Id: 0, // New answer
                                        Answer: val,
                                        Value: val,
                                        Selected: true,
                                        Deleted: false
                                    });
                                }
                            });
                        } else {
                            // Single value - update first answer (fallback for non-array values)
                            if (updatedItem.Answers.length === 0) {
                                updatedItem.Answers.push({
                                    Id: 0,
                                    Answer: value || '',
                                    Value: value || '',
                                    Selected: true,
                                    Deleted: false
                                });
                            } else {
                                updatedItem.Answers[0] = {
                                    ...updatedItem.Answers[0],
                                    Answer: value || '',
                                    Value: value || ''
                                };
                            }
                        }
                        break;

                    case 'Attachment':
                        // File upload - store file info (LEGACY COMPATIBLE: separate Answer record for each file)
                        
                        // Clear existing answers for attachments (legacy behavior)
                        updatedItem.Answers = [];
                        
                        // Handle both single file and array of files
                        let filesToProcess = [];
                        if (Array.isArray(value) && value.length > 0) {
                            // Multiple files - filter out invalid entries
                            const validFiles = value.filter(file => 
                                file && typeof file === 'object' && file.name && !file.uploaded
                            );
                            if (validFiles.length > 0) {
                                filesToProcess = validFiles;
                            } else {
                                // Fallback: try to extract any filename from the array
                                const anyFile = value.find(file => file && file.name);
                                if (anyFile) {
                                    filesToProcess = [anyFile];
                                }
                            }
                        } else if (value && typeof value === 'object' && value.name) {
                            // Single file object
                            filesToProcess = [value];
                        } else if (typeof value === 'string' && value.trim() !== '') {
                            // String filename (legacy format)
                            filesToProcess = [{ name: value }];
                        }
                        
                        // Create separate Answer record for each file (LEGACY COMPATIBLE)
                        filesToProcess.forEach((file, index) => {
                            updatedItem.Answers.push({
                                Id: 0, // New answer (legacy will assign proper ID)
                                Answer: file.name, // Single filename per Answer record
                                Selected: true,
                                Deleted: false
                            });
                        });
                        
                        break;

                    default:
                        // Default handling for unknown types
                        if (updatedItem.Answers.length === 0) {
                            updatedItem.Answers.push({
                                Id: 0,
                                Answer: value || '',
                                Value: value || '',
                                Selected: true,
                                Deleted: false
                            });
                        } else {
                            updatedItem.Answers[0] = {
                                ...updatedItem.Answers[0],
                                Answer: value || '',
                                Value: value || ''
                            };
                        }
                        break;
                }

                    return updatedItem;
                }
                
                // Recursively update nested FormItems
                if (item.FormItems && Array.isArray(item.FormItems)) {
                    return {
                        ...item,
                        FormItems: updateFormItemsRecursive(item.FormItems)
                    };
                }
                
                return item;
            });
        };

        const updatedFormItems = updateFormItemsRecursive(formItems);

        // Update parent's formItems state with direct Answers array updates
        if (onFormItemsChange) {
            onFormItemsChange(updatedFormItems);
        }
        
        // Also update local answers state for backward compatibility
        setAnswers(prev => {
            const newAnswers = { ...prev, [itemName]: value };
            
            // Handle country-state dependency reset
            if (itemName === 'country' || itemName === 'genQuest115') {
                let stateFieldName;
                if (itemName === 'genQuest115') {
                    stateFieldName = 'genQuest116';
                } else if (itemName === 'country') {
                    stateFieldName = 'state';
                }
                
                const stateFieldExists = formItems.some(item => item.Name === stateFieldName);
                
                if (stateFieldExists) {
                    updateStateOptionsForCountry(value, itemName);
                    
                    // Trigger filtering status check
                    setFilteringTrigger(prev => prev + 1);
                    
                    if (prev[stateFieldName] && prev[stateFieldName] !== '') {
                        newAnswers[stateFieldName] = '';
                    }
                }
            }
            
            // Notify parent component of answer changes
            if (onAnswersChange) {
                onAnswersChange(newAnswers);
            }
            
            return newAnswers;
        });
    };

    React.useEffect(() => {
        return () => {
            Object.values(debouncedSaveRef.current).forEach(timeoutId => {
                if (timeoutId) {
                    clearTimeout(timeoutId);
                }
            });
        };
    }, []);

    const renderFormComponent = (item, index, isNested = false) => {
        try {
            if (!item || typeof item !== 'object') {
                return (
                    <Alert key={`invalid_${index}`} severity="error" sx={{ mb: 2 }}>
                        <FAWTypography variant="body2">
                            Invalid form item at position {index + 1}
                        </FAWTypography>
                    </Alert>
                );
            }

            if (!item.Type) {
                return (
                    <Alert key={`no_type_${index}`} severity="error" sx={{ mb: 2 }}>
                        <FAWTypography variant="body2">
                            Form item missing Type at position {index + 1}
                        </FAWTypography>
                    </Alert>
                );
            }

            const Component = componentTypeMap[item.Type];
            
            const isSubmitButton = item.Name === 'closePreview' || 
                                 (item.InputType && item.InputType.toLowerCase() === 'submit') ||
                                 (item.Type === 'TextBox' && item.Value === 'Close');
            
            const ActualComponent = isSubmitButton ? componentTypeMap['Button'] : Component;

            // Create context for file uploads
            const context = {
                questionnaireAnswerId: answerId,
                responseContainerId: responseContainerId,
                onFileDataRefresh: onFileDataRefresh,
                allFileData: allFileData,
                registerValidationMethod: registerValidationMethod,
                validateField: validateField
            };

            const props = createComponentProps(
                item,
                index,
                answers,
                handleAnswerChange,
                onDependencyChange,
                fieldErrors,
                context
            );
            
            // Add loading state to state dropdowns (field-specific)
            if (props && (item.Name === 'genQuest116' || item.Name === 'state')) {
                props.loading = isStateFiltering[item.Name] || false;
            }
            
            if (!props) {
                return null;
            }
            
            // Use the component from props if available, otherwise use the mapped component
            const ComponentToRender = props.component || ActualComponent;
            
            if (!ComponentToRender) {
                return (
                    <Alert key={`unsupported_${index}`} severity="warning" sx={{ mb: 2 }}>
                        <FAWTypography variant="body2">
                            <strong>Unsupported form type:</strong> {item.Type}
                        </FAWTypography>
                        <FAWTypography variant="caption" display="block">
                            Item: {item.Name || item.Text || 'Unknown'}
                        </FAWTypography>
                    </Alert>
                );
            }
            
            const itemName = item.Name ? item.Name.trim() : `item_${index}`;
            const isVisible = visibilityState[itemName] !== false;

            const nestedItems = item.FormItems && Array.isArray(item.FormItems) ? 
                item.FormItems.map((nestedItem, nestedIndex) => 
                    renderFormComponent(nestedItem, `${index}_${nestedIndex}`, true)
                ) : null;

            return (
                <FormItemErrorBoundary 
                    key={props.key}
                    itemName={item.Name || item.Text}
                    itemType={item.Type}
                >
                    <Box 
                        className={`${getFormComponentClassName(item.Type)} ${getScrollableClassName(item.Type)}`}
                        data-field-name={props['data-field-name'] || itemName} // Add data-field-name for scroll-to-error
                        sx={{ 
                            ...props.sx,
                            display: isVisible ? 'block' : 'none',
                            marginLeft: isNested ? 2 : 0,
                            paddingLeft: isNested ? 2 : 0
                        }}
                    >
                        {props.isACLAcceptance && (
                            <Box sx={{ mb: 2, mt: 2 }}>
                                {parseHtmlContent(item.Text) && (
                                    <FAWTypography variant="body2" sx={{ 
                                        mb: 2,
                                        fontSize: '14px',
                                        fontWeight: 'bold',
                                        color: '#e74c3c !important',
                                        textAlign: 'left',
                                        lineHeight: 1.4
                                    }}>
                                        {parseHtmlContent(item.Text)}
                                    </FAWTypography>
                                )}
                            </Box>
                        )}
                        
                        {props.isSectionHeader && (
                            <Box sx={{ mb: 1 }}>
                                <FAWTypography 
                                    variant="caption" 
                                    sx={{ 
                                        color: '#666', 
                                        fontSize: '10px',
                                        fontFamily: 'monospace' 
                                    }}
                                >
                                </FAWTypography>
                            </Box>
                        )}
                        
                        {renderSpecialHeaders(props, item)}
                        
                        <ComponentToRender 
                            {...props} 
                        />
                        {nestedItems && nestedItems.length > 0 && (
                            <Box sx={{ mt: 1 }}>
                                {nestedItems}
                            </Box>
                        )}
                    </Box>
                </FormItemErrorBoundary>
            );
                 } catch (error) {
            return (
                <Alert key={`render_error_${index}`} severity="error" sx={{ mb: 2 }}>
                    <FAWTypography variant="body2">
                        <strong>Render Error:</strong> {item?.Name || item?.Text || `Item ${index + 1}`}
                    </FAWTypography>
                    <FAWTypography variant="caption" display="block">
                        {error.message}
                    </FAWTypography>
                </Alert>
            );
        }
    };

    const renderSpecialHeaders = (props, item) => {
        if (props.isPSACompanyWithHeader) {
            return (
                <Box sx={{ mb: 2 }}>
                    <FAWTypography 
                        variant="h6" 
                        sx={{ 
                            color: '#254460 !important',
                            fontWeight: 'bold !important',
                            fontSize: '14px !important',
                            marginBottom: '16px !important',
                            marginTop: '0px !important',
                            padding: '8px 0 !important',
                            width: '100% !important',
                            display: 'block !important',
                            lineHeight: '1.4 !important',
                            paddingLeft: '12px !important'
                        }}
                    >
                        {parseHtmlContent(props.headerText)}
                        <RequiredIndicator required={item.Required === 'true' || item.Required === true} />
                    </FAWTypography>
                </Box>
            );
        }
        
        if (props.isKeyPersonnelWithHeader) {
            return (
                <Box sx={{ mb: 2 }}>
                    <FAWTypography 
                        variant="h6" 
                        sx={{ 
                            color: '#254460 !important',
                            fontWeight: 'bold !important',
                            fontSize: '14px !important',
                            marginBottom: '16px !important',
                            marginTop: '0px !important',
                            padding: '8px 0 !important',
                            width: '100% !important',
                            display: 'block !important',
                            lineHeight: '1.4 !important',
                            paddingLeft: '12px !important'
                        }}
                    >
                        {parseHtmlContent(props.headerText)}
                        <RequiredIndicator required={item.Required === 'true' || item.Required === true} />
                    </FAWTypography>
                </Box>
            );
        }
        
        if (props.isCountrySelectWithHeader) {
            return (
                <Box sx={{ mb: 2 }}>
                    <FAWTypography 
                        variant="h6" 
                        sx={{ 
                            color: '#254460 !important',
                            fontWeight: 'bold !important',
                            fontSize: '14px !important',
                            marginBottom: '16px !important',
                            marginTop: '0px !important',
                            padding: '8px 0 !important',
                            width: '100% !important',
                            display: 'block !important',
                            lineHeight: '1.4 !important',
                            paddingLeft: '12px !important'
                        }}
                    >
                        {parseHtmlContent(props.headerText)}
                        <RequiredIndicator required={item.Required === 'true' || item.Required === true} />
                    </FAWTypography>
                </Box>
            );
        }
        
        return null;
    };

    return (
        <Box>
            {(() => {
                try {
                    if (!formItems || formItems.length === 0) {
                        return (
                            <Alert severity="info">
                                <FAWTypography>No form items to display</FAWTypography>
                            </Alert>
                        );
                    }
                    return formItems
                        .map((item, index) => renderFormComponent(item, index))
                        .filter(component => component !== null);
                                 } catch (error) {
                    return (
                        <Alert severity="error">
                            <FAWTypography variant="h6">Form Rendering Error</FAWTypography>
                            <FAWTypography>Unable to render form components: {error.message}</FAWTypography>
                            {process.env.NODE_ENV === 'development' && (
                                <FAWTypography variant="caption" display="block" sx={{ mt: 1, fontFamily: 'monospace' }}>
                                    {error.stack}
                                </FAWTypography>
                            )}
                        </Alert>
                    );
                }
            })()}
        </Box>
    );
};

export default FormRenderer;
