import React, { useMemo, useEffect, useState } from "react";
import { findIndex } from "lodash";
import update from "immutability-helper";
import axios from "axios";
import parse from "html-react-parser";
import DOMPurify from "dompurify";
import FAWInput from "../../../component-widget/FAWInput";
import FAWButton from "../../../component-widget/FAWButton";
import FAWCheckbox from "../../../component-widget/FAWCheckbox";
import FAWTypography from "../../../component-widget/FAWTypography";
import FAWLoader from "../../../component-widget/FAWLoader";
import FAWThemeProvider from '../../../Theme/FAWThemeProvider';
import FAWToast from "../../../component-widget/FAWToast";
import FAWConfirmDialogue from "../../../component-widget/FAWConfirmDialogue";
import FAWSelect from "../../../component-widget/FAWSelect";
import Box from '@mui/material/Box';
import Stack from '@mui/material/Stack';
import Dialog from '@mui/material/Dialog';
import DialogActions from '@mui/material/DialogActions';
import DialogContent from '@mui/material/DialogContent';
import DialogTitle from '@mui/material/DialogTitle';
import InputAdornment from '@mui/material/InputAdornment';
import MenuItem from '@mui/material/MenuItem';
import AddIcon from '@mui/icons-material/Add';
import { Autocomplete, Chip, TextField, Select, FormControl, InputLabel, FormHelperText } from '@mui/material';
import FAWSkeleton from "../../../component-widget/FAWSkeleton";
import KeyPersonnelTable from "./KeyPersonnelTable";
import RoleBadges from "./RoleBadges";
import {
    questionIds,
    defaultQuestionText,
    displayText,
    defaultGeneralInfo,
} from "./constants";
import { colors } from "../../../../utils/designTokens";

// Safe template function to replace lodash.template (security vulnerability fix)
const safeTemplate = (templateString) => {
    return (data) => {
        return templateString.replace(/\$\{(\w+)\}/g, (match, key) => {
            return data[key] || match;
        });
    };
};

// Ensure colors object is properly initialized
const safeColors = {
    ui: {
        border: {
            static: colors?.ui?.border?.static || '#ccc'
        }
    },
    background: {
        secondary: colors?.background?.secondary || '#f5f5f5',
        overlay: colors?.background?.overlay || 'rgba(0, 0, 0, 0.5)',
        default: colors?.background?.default || '#fff'
    },
    type: {
        default: colors?.type?.default || '#000'
    }
};

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const INITIAL_DATA = {
    Name: '',
    Email: '',
    Roles: [],
    Position: '',
    Address: '',
    Nationality: '',
    OwnershipPercent: 0,
    EmbargoedResident: false
};

// Error Boundary Component
class KeyPersonnelErrorBoundary extends React.Component {
    constructor(props) {
        super(props);
        this.state = { hasError: false, error: null };
    }

    static getDerivedStateFromError(error) {
        return { hasError: true, error };
    }

    componentDidCatch(error, errorInfo) {
        console.error('KeyPersonnel Error:', error, errorInfo);
    }

    render() {
        if (this.state.hasError) {
            return (
                <Box sx={{ p: 2, border: '1px solid #f44336', borderRadius: 1, backgroundColor: '#ffebee' }}>
                    <FAWTypography variant="h6" sx={{ color: '#d32f2f', mb: 1 }}>
                        KeyPersonnel Component Error
                    </FAWTypography>
                    <FAWTypography variant="body2" sx={{ color: '#666' }}>
                        {this.state.error?.message || 'An unexpected error occurred'}
                    </FAWTypography>
                </Box>
            );
        }

        return this.props.children;
    }
}

function KeyPersonnelComponent(props) {
    const [data, setData] = useState([]);
    const [trans, setTrans] = useState([]);
    const [show, setShow] = useState(false);
    const [edit, setEdit] = useState(0);
    const [initFetch, setInitFetch] = useState(true);
    const [formData, setFormData] = useState(INITIAL_DATA);
    const [errors, setErrors] = useState({});
    const [bypassValue, setBypassValue] = useState(0);
    const [saving, setSaving] = useState(false);
    const [toast, setToast] = useState({ open: false, message: '', type: 'info' });
    
    // Dynamic column support
    const [dynamicColumns, setDynamicColumns] = useState([]);
    const [refDomainOptions, setRefDomainOptions] = useState({});
    
    // Confirmation dialog and loading states
    const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
    const [itemToDelete, setItemToDelete] = useState(null);
    const [deleting, setDeleting] = useState(false);
    const [loading, setLoading] = useState(false);

    const fetchBypassValue = async () => {
        try {
            const { data } = await axios.get("/Questionnaire/GetKeyPersonnelProperties");
            setBypassValue(data.BypassProperty || 0);
        } catch (error) {
            console.error("Error in fetching ownership percentage from key personnel:", error);
            setBypassValue(0);
        }
    };

    // Fetch dynamic columns from the server
    const fetchDynamicColumns = async () => {
        try {
            // Try to get questionnaire item ID from hidden field (used on actual form)
            let questionnaireItemId = 0;
            const hiddenFields = document.querySelectorAll('input[id*="hdnQuestionnaireItemId"]');
            if (hiddenFields.length > 0) {
                questionnaireItemId = parseInt(hiddenFields[0].value) || 0;
            }

            // If we have an ID, use the ID-based endpoint
            if (questionnaireItemId > 0) {
                const response = await axios.post(
                    "/FormsManagement/KeyPersonnelService.asmx/GetModelColumns",
                    { questionnaireItemId: questionnaireItemId },
                    { headers: { "Content-Type": "application/json" } }
                );

                if (response.data && response.data.d) {
                    const columns = JSON.parse(response.data.d);
                    setDynamicColumns(columns);

                    // Fetch reference domain options for dropdown fields with non-empty refDomain
                    const refDomains = [...new Set(columns
                        .filter(col => col.refDomain && col.refDomain.trim() !== '')
                        .map(col => col.refDomain.trim())
                    )];
                    if (refDomains.length > 0) {
                        fetchRefDomainOptions(refDomains);
                    }
                    return;
                }
            }

            // Since this is KeyPersonnel.jsx, we know it's always for KeyPersonnel
            const questionnaireItemName = "KeyPersonnel";

            const response = await axios.post(
                "/FormsManagement/KeyPersonnelService.asmx/GetColumnsForPreview",
                { questionnaireItemName: questionnaireItemName },
                { headers: { "Content-Type": "application/json" } }
            );

            if (response.data && response.data.d) {
                const columns = JSON.parse(response.data.d);
                setDynamicColumns(columns);

                // Fetch reference domain options for dropdown fields with non-empty refDomain
                const refDomains = [...new Set(columns
                    .filter(col => col.refDomain && col.refDomain.trim() !== '')
                    .map(col => col.refDomain.trim())
                )];
                if (refDomains.length > 0) {
                    fetchRefDomainOptions(refDomains);
                }
            } else {
                setDynamicColumns([]);
            }
        } catch (error) {
            console.error("KeyPersonnel: Error fetching dynamic columns:", error);
            // Set empty array on error to use default columns
            setDynamicColumns([]);
        }
    };

    // Fetch reference codes for specific domains from DataGridEntryColumn
    const fetchRefDomainOptions = async (refDomains) => {
        try {
            
            const optionsMap = {};
            
            // Load reference codes for each domain that has a non-empty refDomain
            for (const domainName of refDomains) {
                if (domainName && domainName.trim() !== '') {
                    try {
                        console.log(`KeyPersonnel: Loading reference codes for domain: ${domainName}`);
                        
                        // First get the available domains to validate the domain exists
                        const domainsResponse = await axios.post('/FormsManagement/KeyPersonnelService.asmx/GetRefDomains',
                            JSON.stringify({}),
                            { headers: { 'Content-Type': 'application/json; charset=utf-8' } }
                        );
                        
                        let availableDomains = [];
                        if (domainsResponse.data) {
                            if (typeof domainsResponse.data === 'string') {
                                availableDomains = JSON.parse(domainsResponse.data);
                            } else if (domainsResponse.data.d) {
                                availableDomains = JSON.parse(domainsResponse.data.d);
                            } else if (Array.isArray(domainsResponse.data)) {
                                availableDomains = domainsResponse.data;
                            } else {
                                availableDomains = domainsResponse.data;
                            }
                        }
                        
                        console.log(`KeyPersonnel: Available domains:`, availableDomains);
                        
                        // Check if the domain exists in available domains
                        const domainExists = availableDomains.some(d => 
                            (d.name || d.Name || d.code || d.Code) === domainName
                        );
                        
                        if (domainExists) {
                            // Load reference codes for this specific domain
                            // Since we removed GetRefCode, we'll extract codes from the domain data
                            const domainData = availableDomains.find(d => 
                                (d.name || d.Name || d.code || d.Code) === domainName
                            );
                            
                            if (domainData) {
                                if (domainData.options || domainData.Options) {
                                    // Domain has pre-loaded options
                                    optionsMap[domainName] = domainData.options || domainData.Options;
                                    console.log(`KeyPersonnel: Loaded ${optionsMap[domainName].length} options for domain '${domainName}'`);
                                } else if (domainData.codes || domainData.Codes) {
                                    // Domain has codes array
                                    const codes = domainData.codes || domainData.Codes;
                                    optionsMap[domainName] = codes.map(code => ({
                                        value: code.value || code.Value || code.code || code.Code,
                                        label: code.label || code.Label || code.description || code.Description || code.value || code.Value || code.code || code.Code,
                                        Value: code.value || code.Value || code.code || code.Code,
                                        Label: code.label || code.Label || code.description || code.Description || code.value || code.Value || code.code || code.Code
                                    }));
                                    console.log(`KeyPersonnel: Mapped ${optionsMap[domainName].length} codes for domain '${domainName}'`);
                                } else {
                                    // Create a basic option from domain info
                                    optionsMap[domainName] = [{
                                        value: domainData.value || domainData.name || domainData.Name || domainData.code || domainData.Code,
                                        label: domainData.text || domainData.Text || domainData.description || domainData.Description || domainData.name || domainData.Name,
                                        Value: domainData.value || domainData.name || domainData.Name || domainData.code || domainData.Code,
                                        Label: domainData.text || domainData.Text || domainData.description || domainData.Description || domainData.name || domainData.Name
                                    }];
                                    console.log(`KeyPersonnel: Created basic option for domain '${domainName}'`);
                                }
                            } else {
                                console.warn(`KeyPersonnel: Domain '${domainName}' found but no data available`);
                                optionsMap[domainName] = [];
                            }
                        } else {
                            console.warn(`KeyPersonnel: Domain '${domainName}' not found in available domains`);
                            optionsMap[domainName] = [];
                        }
                        
                    } catch (domainError) {
                        console.error(`KeyPersonnel: Error loading reference codes for domain '${domainName}':`, domainError);
                        optionsMap[domainName] = [];
                    }
                } else {
                    console.log(`KeyPersonnel: Skipping empty domain name`);
                }
            }
            
            setRefDomainOptions(optionsMap);
            
        } catch (error) {
            console.error("KeyPersonnel: Error fetching reference domain options:", error);
            setRefDomainOptions({});
        }
    };

    const fetchKeyPersonnel = async () => {
        try {
            setLoading(true);
            const { data } = await axios.get("/Questionnaire/LoadKeyPersonnel");
            const { KeyPersonnel, Translations } = data;

            setData(KeyPersonnel || []);
            setTrans(Translations || []);
            setInitFetch(false);
        } catch (error) {
            console.error("Error in fetching key personnel list data:", error);
            showToast('Failed to load Key Personnel data. Please try again.', 'error');
            setData([]);
            setTrans([]);
            setInitFetch(false);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchBypassValue();
        fetchKeyPersonnel();
        fetchDynamicColumns();
    }, []);

    // Register validation method for form validation
    useEffect(() => {
        if (props.registerValidationMethod) {
            props.registerValidationMethod('KeyPersonnel', () => {
                if (props.required && (!data || data.length === 0)) {
                    return {
                        field: 'keyPersonnel',
                        message: "Key Personnel requires at least one entry. Please add data to continue."
                    };
                }
                return null;
            });
        }
    }, [data, props.registerValidationMethod, props.required]);

    const resetForm = () => {
        setFormData(INITIAL_DATA);
        setErrors({});
    };

    const showToast = (message, type = 'info') => {
        setToast({ open: true, message, type });
    };

    const handleToastClose = () => {
        setToast(prev => ({ ...prev, open: false }));
    };

    const toggleShow = () => {
        setEdit(0);
        setShow((c) => !c);
        if (!show) {
            resetForm();
        }
    };

    // Show delete confirmation dialog
    const handleDeleteClick = (rowNumber) => {
        const personData = data.find(person => person.Row === rowNumber);
        const personName = personData?.Name || 'Unknown Person';
        
        setItemToDelete({ rowNumber, personName });
        setDeleteConfirmOpen(true);
    };

    // Confirm delete action
    const handleDeleteConfirm = async () => {
        if (!itemToDelete) return;
        
        setDeleting(true);
        try {
            await axios.post("/Questionnaire/DeleteKeyPersonnel", { rowNumber: itemToDelete.rowNumber });
            setData((c) => c.filter((r) => r.Row !== itemToDelete.rowNumber));
            showToast('Key Personnel deleted successfully!', 'success');
            setDeleteConfirmOpen(false);
            setItemToDelete(null);
        } catch (error) {
            showToast('Failed to delete Key Personnel. Please try again.', 'error');
        } finally {
            setDeleting(false);
        }
    };

    // Cancel delete action
    const handleDeleteCancel = () => {
        setDeleteConfirmOpen(false);
        setItemToDelete(null);
    };

    const validatePercentage = (value) => {
        const numValue = Number(value);

        if (isNaN(numValue)) {
            return findText(displayText.OwnershipPercentValidation);
        }

        if (numValue <= 0) {
            return compiledOwnershipCurrentTemplate({ totalPercentage: numValue });
        }

        const totalPercentage = data.reduce((sum, d) => {
            const rowNum = d.Row ?? d.row;
            const ownershipPct = d.OwnershipPercent ?? d.ownershipPercent ?? 0;
            return sum + (edit !== rowNum ? Number(ownershipPct) : 0);
        }, numValue);

        if (totalPercentage > 100 || totalPercentage <= 0) {
            return compiledOwnershipTemplate({ totalPercentage });
        }

        if (bypassValue > 0 && numValue > bypassValue) {
            return bypassMsgTemplate();
        }

        return null;
    };

    const validateForm = () => {
        const newErrors = {};
        
        // Validate fields based on column configuration's required status
        if (dynamicColumns && dynamicColumns.length > 0) {
            dynamicColumns.forEach(col => {
                const fieldName = col.accessor || col.name;
                const isRequired = col.required === true;
                
                // Skip validation if field is not required
                if (!isRequired) {
                    return;
                }
                
                // Handle Roles field (array validation)
                if (fieldName === "Roles" || fieldName === "roles") {
                    if (!formData.Roles || !Array.isArray(formData.Roles) || formData.Roles.length === 0) {
                        newErrors.Roles = true;
                    } else {
                        const hasValidRole = formData.Roles.some(role => 
                            role && typeof role === 'string' && role.trim()
                        );
                        if (!hasValidRole) {
                            newErrors.Roles = true;
                        }
                    }
                    return;
                }
                
                // Handle OwnershipPercent (only validate if shown)
                if (fieldName === "OwnershipPercent" || fieldName === "OwnershipPercentage") {
                    if (showOwnership()) {
                        // First check for percentage validation errors
                        const percentError = validatePercentage(formData.OwnershipPercent);
                        if (percentError) {
                            newErrors.OwnershipPercent = percentError;
                        } else if (isRequired && (!formData.OwnershipPercent && formData.OwnershipPercent !== 0)) {
                            // Only check required if no percentage validation error
                            newErrors.OwnershipPercent = true;
                        }
                    }
                    return;
                }
                
                // Handle checkbox fields (EmbargoedResident)
                if (col.type === "CheckBox" || fieldName === "EmbargoedResident") {
                    // Checkboxes are typically not validated as required in the same way
                    // They're either checked or unchecked, so we skip validation
                    return;
                }
                
                // Handle dropdown fields
                if (col.type === "DropDownList" || (col.formFieldType === "select" && col.refDomain)) {
                    const value = formData[fieldName];
                    if (!value || (typeof value === 'string' && !value.trim())) {
                        newErrors[fieldName] = true;
                    }
                    return;
                }
                
                // Handle all other text/number/email fields
                const value = formData[fieldName];
                
                // For numeric fields, check if value is null/undefined/empty string
                // (allow 0 as a valid value for numeric fields)
                if (col.type === "NumericTextbox" || col.formFieldType === "number") {
                    if (value === null || value === undefined || value === '') {
                        newErrors[fieldName] = true;
                    }
                } else {
                    // For text fields, check for empty/whitespace
                    if (!value || (typeof value === 'string' && !value.trim())) {
                        newErrors[fieldName] = true;
                    }
                }
                
                // Email format validation for Email type fields (required or optional)
                if ((col.type === "Email" || col.formFieldType === "email") &&
                    value && typeof value === 'string' && value.trim() && !EMAIL_REGEX.test(value.trim())
                ) {
                    newErrors[fieldName] = findText(displayText.EmailFormatError);
                }
            });
        } else {
            if (!formData.Name || !formData.Name.trim()) {
                newErrors.Name = true;
            }
            if (!formData.Email || !formData.Email.trim()) {
                newErrors.Email = true;
            } else if (!EMAIL_REGEX.test(formData.Email.trim())) {
                newErrors.Email = findText(displayText.EmailFormatError);
            }
        }
        
        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    const handleFieldChange = (field, value) => {
        setFormData(prev => ({ ...prev, [field]: value }));
        
        if (errors[field]) {
            setErrors(prev => ({ ...prev, [field]: null }));
        }
        
        if (field === 'OwnershipPercent' && showOwnership()) {
            const percentError = validatePercentage(value);
            if (percentError) {
                setErrors(prev => ({ ...prev, OwnershipPercent: percentError }));
            } else {
                setErrors(prev => ({ ...prev, OwnershipPercent: null }));
            }
        }
    };

    const submitModal = async () => {
        if (!validateForm()) {
            return;
        }
        
        setSaving(true);
        try {
            const kp = {
                ...formData,
                Roles: formData.Roles,
                Row: edit,
                // Ensure OwnershipPercent is sent as a number, not a string
                OwnershipPercent: parseFloat(formData.OwnershipPercent) || 0,
            }; 
            
            const res = await axios.post("/Questionnaire/AddKeyPersonnel", kp);
            if (edit === 0) {
                setData((c) => update(c, { $push: res.data }));
                showToast('Key Personnel created successfully!', 'success');
            } else {
                await fetchKeyPersonnel();
                showToast('Key Personnel updated successfully!', 'success');
            }
            toggleShow();
            resetForm();
        } catch (error) {
            showToast('Failed to save Key Personnel. Please try again.', 'error');
        } finally {
            setSaving(false);
        }
    };

    const toggleEdit = (rowNumber) => {
        setEdit(rowNumber);
        if (rowNumber > 0) {
            // Handle both camelCase and PascalCase property names from server response
            const existingData = data.find(d => (d.Row ?? d.row) === rowNumber);
            if (existingData) {
                setFormData({
                    Name: existingData.Name ?? existingData.name ?? '',
                    Email: existingData.Email ?? existingData.email ?? '',
                    Roles: existingData.Roles ?? existingData.roles ?? [],
                    Position: existingData.Position ?? existingData.position ?? '',
                    Address: existingData.Address ?? existingData.address ?? '',
                    Nationality: existingData.Nationality ?? existingData.nationality ?? '',
                    OwnershipPercent: existingData.OwnershipPercent ?? existingData.ownershipPercent ?? 0,
                    EmbargoedResident: existingData.EmbargoedResident ?? existingData.embargoedResident ?? false,
                    // Add dynamic fields
                    TaxID: existingData.TaxID ?? existingData.taxID ?? '',
                    Country: existingData.Country ?? existingData.country ?? ''
                });
            }
        } else {
            resetForm();
        }
        setErrors({});
        setShow(true);
    };

    const html = (html) => {
        return parse(DOMPurify.sanitize(html, { ADD_ATTR: ["target"] }));
    };

    const findText = (id) => {
        if (trans) {
            const question = trans.find((x) => x.QuestionId === id);
            return question ? question.LabelText : defaultQuestionText[id];
        }

        return defaultQuestionText[id];
    };

    const findGeneralInfo = (id) => {
        if (trans) {
            const question = trans.find((x) => x.QuestionId === id);
            return question ? question.GeneralInfo : defaultGeneralInfo[id];
        }

        return defaultGeneralInfo[id];
    };

    const compiledOwnershipTemplate = safeTemplate(
        findGeneralInfo(
            displayText.OwnershipPercentValidation in defaultGeneralInfo
                ? displayText.OwnershipPercentValidation
                : "CurrentOwnershipPercent"
        )
    );

    const bypassMsgTemplate = safeTemplate(
        findGeneralInfo(displayText.BypassOwnershipValidation)
    );

    const compiledOwnershipCurrentTemplate = safeTemplate(
        findGeneralInfo(displayText.OwnershipCurrentPercentValidation)
    );

    // Build Roles options from dynamic columns or use defaults
    const Roles = useMemo(() => {
        // Check if we have dynamic columns loaded
        if (dynamicColumns && dynamicColumns.length > 0) {
            // Check if Roles column is configured
            const rolesColumn = dynamicColumns.find(col =>
                col.name?.toLowerCase() === "roles" || col.accessor === "Roles"
            );

            // If Roles is NOT configured, return empty array
            if (!rolesColumn) {
                return [];
            }

            // If configured with a refDomain (dropdown), use those options
            if (rolesColumn.refDomain && refDomainOptions[rolesColumn.refDomain]) {
                const domainOptions = refDomainOptions[rolesColumn.refDomain];
                return domainOptions.map(opt => {
                    const optionValue = typeof opt === 'object' ? (opt.value || opt.Value || opt) : opt;
                    const optionLabel = typeof opt === 'object' ? (opt.label || opt.Label || opt.value || opt.Value || opt) : opt;
                    return { value: optionValue, label: optionLabel };
                });
            }
        }

        // Default roles for backward compatibility
        return [
            { value: "Owner", label: findText(displayText.KPTableRoleOwner) },
            { value: "Officer", label: findText(displayText.KPTableRoleKeyManager) },
            { value: "BoardMember", label: findText(displayText.KPTableRoleBoard_Member) },
            { value: "KeyEmployee", label: findText(displayText.KPTableRoleKeyEmployee) },
        ];
    }, [trans, dynamicColumns, refDomainOptions]);

    // Check if Ownership field should be shown
    const showOwnership = () => {
        // Check if Roles column is configured
        const rolesColumn = dynamicColumns && dynamicColumns.find(col =>
            col.name?.toLowerCase() === "roles" || col.accessor === "Roles"
        );

        // If Roles is NOT configured, always show ownership fields
        if (!rolesColumn || Roles.length === 0) {
            return true;
        }

        // If Roles IS configured, only show ownership if "Owner" role is selected
        return (formData.Roles && Array.isArray(formData.Roles) && formData.Roles.some((x) => x === "Owner"));
    };

    // Build table columns based on dynamic configuration
    const columns = useMemo(
        () => {
            const dataColumns = [];

            // If we have dynamic columns from database, use them
            if (dynamicColumns && dynamicColumns.length > 0) {
                dynamicColumns.forEach(col => {
                    // Skip OwnershipPercent in table if Roles column is configured and Roles is not empty
                    const rolesColumn = dynamicColumns.find(c => 
                        c.name?.toLowerCase() === "roles" || c.accessor === "Roles"
                    );
                    if (rolesColumn && Roles.length > 0 && (
                        col.name === "OwnershipPercent" || col.name === "OwnershipPercentage"
                    )) return;

                    const columnDef = {
                        Header: col.heading,
                        accessor: col.accessor || col.name,
                        sortable: col.sortable !== false
                    };

                    // Add custom Cell renderer for boolean/checkbox fields
                    if (col.type === "CheckBox" || col.formFieldType === "checkbox" ||
                        col.name === "EmbargoedResident" || col.accessor === "EmbargoedResident") {
                        columnDef.Cell = ({ cell: { value } }) => {
                            if (value === null || value === undefined || value === "") {
                                return <span>-</span>;
                            }
                            if (value === true || (typeof value === 'string' && value.toLowerCase() === "true")) {
                                return <span>{findText(displayText.KPTableTextYes)}</span>;
                            } else if (value === false || (typeof value === 'string' && value.toLowerCase() === "false")) {
                                return <span>{findText(displayText.KPTableTextNo)}</span>;
                            }
                            return <span>{String(value)}</span>;
                        };
                    }

                    // Special handling for Roles column
                    if (col.name?.toLowerCase() === "roles" || col.accessor === "Roles") {
                        columnDef.sortable = false;
                        columnDef.Cell = ({ row, cell: { value } }) => {
                            const { original } = row;
                            return (
                                <RoleBadges
                                    values={value}
                                    percentage={original.OwnershipPercent}
                                    roles={Roles}
                                />
                            );
                        };
                    }

                    dataColumns.push(columnDef);
                });
            } else {
                // Fallback to default columns if no dynamic columns loaded
                dataColumns.push(
                    {
                        Header: findText(displayText.KPTableHeaderName),
                        accessor: "Name",
                    },
                    {
                        Header: findText(displayText.KPTableHeaderEmail),
                        accessor: "Email",
                    },
                    {
                        Header: findText(displayText.KPTableHeaderRole),
                        accessor: "Roles",
                        sortable: false,
                        Cell: ({ row, cell: { value } }) => {
                            const { original } = row;
                            // Handle both camelCase and PascalCase property names
                            const ownershipPercent = original.OwnershipPercent ?? original.ownershipPercent ?? 0;

                            return (
                                <RoleBadges
                                    values={value}
                                    percentage={ownershipPercent}
                                    roles={Roles}
                                />
                            );
                        },
                    },
                    {
                        Header: findText(displayText.KPTableHeaderPosition),
                        accessor: "Position",
                    },
                    {
                        Header: findText(displayText.KPTableHeaderAddress),
                        accessor: "Address",
                    },
                    {
                        Header: findText(displayText.KPTableHeaderNationality),
                        accessor: "Nationality",
                    },
                    {
                        Header: findText(displayText.KPTableHeaderEmbargoed),
                        accessor: "EmbargoedResident",
                        Cell: ({ cell: { value } }) => {
                            return value ? findText(displayText.KPTableTextYes) : findText(displayText.KPTableTextNo);
                        },
                    }
                );
            }

            return [
                {
                    id: "Key Personnel",
                    Header: "",
                    sortable: false,
                    columns: dataColumns
                },
            ];
        },
        [trans, dynamicColumns, data, edit, Roles]
    );

    // Render dynamic form fields based on column configuration
    // This renders ALL fields from dynamicColumns in the order configured in the database
    const renderDynamicField = (column, index) => {
        const fieldName = column.accessor || column.name;
        const isRequired = column.required === true;
        // Use the heading from the database, not static text
        const label = column.heading || fieldName;

        // Handle Roles field specially (multi-select with autocomplete)
        if (fieldName === "Roles" && Roles.length > 0) {
            return (
                <Box key={`${fieldName}-${index}`}>
                    <FAWTypography variant="body2" sx={{ mb: 1, color: '#282E37', fontSize: '14px' }}>
                        {label} {isRequired && <span style={{ color: 'red' }}>*</span>}
                    </FAWTypography>
                    <Autocomplete
                        multiple
                        options={Roles}
                        value={formData.Roles ? formData.Roles.map(roleString => 
                            Roles.find(role => role.value === roleString) || { value: roleString, label: roleString }
                        ) : []}
                        onChange={(event, newValue) => {
                            const stringArray = newValue ? newValue.map(item => item.value) : [];
                            handleFieldChange("Roles", stringArray);
                        }}
                        getOptionLabel={(option) => option.label || option}
                        isOptionEqualToValue={(option, value) => option.value === value.value}
                        filterSelectedOptions
                        disableCloseOnSelect={false}
                        renderTags={(value, getTagProps) =>
                            value.map((option, idx) => (
                                <Chip
                                    variant="outlined"
                                    label={option.label || option}
                                    {...getTagProps({ index: idx })}
                                    key={option.value || option}
                                />
                            ))
                        }
                        renderInput={(params) => (
                            <TextField
                                {...params}
                                variant="outlined"
                                placeholder={findText(displayText.SelectRolesPlaceholder)}
                                error={!!errors.Roles}
                                helperText={errors.Roles && findText(displayText.RequiredFieldMessage)}
                                size="small"
                            />
                        )}
                        size="small"
                    />
                </Box>
            );
        }

        // Handle OwnershipPercent with percentage input
        if (fieldName === "OwnershipPercent") {
            if (!showOwnership()) return null;
            // Handle both validation errors (string) and required errors (boolean)
            const errorMessage = errors.OwnershipPercent 
                ? (typeof errors.OwnershipPercent === 'string' 
                    ? errors.OwnershipPercent 
                    : findText(displayText.RequiredFieldMessage))
                : '';
            return (
                <FAWInput
                    key={`${fieldName}-${index}`}
                    label={label}
                    type="number"
                    placeholder={label}
                    value={formData.OwnershipPercent || ""}
                    onChange={(e) => handleFieldChange("OwnershipPercent", e.target.value)}
                    error={!!errors.OwnershipPercent}
                    helperText={errorMessage}
                    required={isRequired}
                    InputProps={{
                        endAdornment: <InputAdornment position="end">%</InputAdornment>,
                    }}
                    fullWidth
                />
            );
        }

        // Handle dropdown fields with reference domains (DropDownList type or select formFieldType)
        if (column.type === "DropDownList" || (column.formFieldType === "select" && column.refDomain)) {
            const options = refDomainOptions[column.refDomain] || [];
            return (
                <Box key={`${fieldName}-${index}`}>
                    <FAWTypography variant="body2" sx={{ mb: 1, color: '#282E37', fontSize: '14px' }}>
                        {label} {isRequired && <span style={{ color: 'red' }}>*</span>}
                    </FAWTypography>
                    <Select
                        fullWidth
                        size="small"
                        variant="outlined"
                        value={formData[fieldName] || ""}
                        onChange={(e) => handleFieldChange(fieldName, e.target.value)}
                        displayEmpty
                        error={!!errors[fieldName]}
                        sx={{
                            fontSize: '14px',
                            color: '#282E37',
                            backgroundColor: '#fff',
                            '& .MuiOutlinedInput-notchedOutline': {
                                borderColor: 'rgba(0, 0, 0, 0.23)',
                                borderWidth: '1px',
                            },
                            '&:hover .MuiOutlinedInput-notchedOutline': {
                                borderColor: 'rgba(0, 0, 0, 0.87)',
                            },
                            '&.Mui-focused .MuiOutlinedInput-notchedOutline': {
                                borderColor: '#1976d2',
                                borderWidth: '2px',
                            },
                            '& .MuiSelect-select': {
                                padding: '8.5px 14px',
                            },
                        }}
                    >
                        <MenuItem value="">{findText(displayText.SelectOptionPlaceholder)}</MenuItem>
                        {options.map((opt, idx) => {
                            const optionValue = opt.value || opt.Value || opt.code || opt.Code || '';
                            const optionLabel = opt.label || opt.Label || opt.description || opt.Description || '';
                            
                            return (
                                <MenuItem key={idx} value={optionValue}>
                                    {optionLabel}
                                </MenuItem>
                            );
                        })}
                    </Select>
                    {errors[fieldName] && (
                        <FormHelperText error>{findText(displayText.RequiredFieldMessage)}</FormHelperText>
                    )}
                </Box>
            );
        }

        // Handle checkbox fields (CheckBox type or EmbargoedResident)
        if (column.type === "CheckBox" || column.formFieldType === "checkbox") {
            return (
                <FAWCheckbox
                    key={`${fieldName}-${index}`}
                    id={fieldName}
                    name={fieldName}
                    label={label}
                    checked={formData[fieldName] || false}
                    onChange={(e) => handleFieldChange(fieldName, e.target.checked)}
                />
            );
        }

        // Handle numeric fields (NumericTextbox type)
        if (column.type === "NumericTextbox" || column.formFieldType === "number") {
            return (
                <FAWInput
                    key={`${fieldName}-${index}`}
                    label={label}
                    type="number"
                    placeholder={label}
                    value={formData[fieldName] || ""}
                    onChange={(e) => handleFieldChange(fieldName, e.target.value)}
                    error={!!errors[fieldName]}
                    helperText={errors[fieldName] && findText(displayText.RequiredFieldMessage)}
                    required={isRequired}
                    fullWidth
                />
            );
        }

        // Handle Email type
        if (column.type === "Email" || column.formFieldType === "email") {
            const emailError = errors[fieldName];
            const emailHelperText = emailError
                ? (typeof emailError === 'string' ? emailError : findText(displayText.RequiredFieldMessage))
                : '';
            return (
                <FAWInput
                    key={`${fieldName}-${index}`}
                    label={label}
                    type="email"
                    placeholder={label}
                    value={formData[fieldName] || ""}
                    onChange={(e) => handleFieldChange(fieldName, e.target.value)}
                    error={!!emailError}
                    helperText={emailHelperText}
                    required={isRequired}
                    fullWidth
                />
            );
        }

        // Default: text input (Textbox type)
        return (
            <FAWInput
                key={`${fieldName}-${index}`}
                label={label}
                type="text"
                placeholder={label}
                value={formData[fieldName] || ""}
                onChange={(e) => handleFieldChange(fieldName, e.target.value)}
                error={!!errors[fieldName]}
                helperText={errors[fieldName] && findText(displayText.RequiredFieldMessage)}
                required={isRequired}
                fullWidth
            />
        );
    };

    if (initFetch) {
        return (
            <FAWThemeProvider>
                <Box sx={{ px: 5, pt: 2 }}>
                    <FAWSkeleton variant="table" />
                </Box>
            </FAWThemeProvider>
        );
    }

    return (
        <FAWThemeProvider>
            <Box sx={{ px: 5, pt: 2, width: '100%', position: 'relative' }}>
                <Dialog open={show} onClose={toggleShow} fullWidth maxWidth="lg">
                <DialogTitle>
                    {html(findText(displayText.KPTableTitle))}
                </DialogTitle>
                <DialogContent>
                    <Box component="form" id="key-personnel-form" sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
                        {/* Render ALL fields dynamically based on column configuration from database */}
                        {/* Fields are rendered in the order configured in DataGridEntryColumn table */}
                        {/* Labels use the Heading from the database, not static text */}
                        {dynamicColumns && dynamicColumns.length > 0 ? (
                            dynamicColumns
                                .sort((a, b) => (a.sequence || a.index || 0) - (b.sequence || b.index || 0))
                                .map((col, index) => renderDynamicField(col, index))
                        ) : (
                            /* Fallback to default fields if no dynamic columns configured */
                            <>
                                <FAWInput
                                    label={findText(displayText.KPTableHeaderName)}
                                    placeholder={findText(displayText.KPTableHeaderName)}
                                    value={formData.Name}
                                    onChange={(e) => handleFieldChange("Name", e.target.value)}
                                    error={!!errors.Name}
                                    helperText={errors.Name && findText(displayText.RequiredFieldMessage)}
                                    required={true}
                                    fullWidth
                                />
                                <FAWInput
                                    label={findText(displayText.KPTableHeaderEmail)}
                                    type="email"
                                    placeholder={findText(displayText.KPTableHeaderEmail)}
                                    value={formData.Email}
                                    onChange={(e) => handleFieldChange("Email", e.target.value)}
                                    error={!!errors.Email}
                                    helperText={errors.Email ? (typeof errors.Email === 'string' ? errors.Email : findText(displayText.RequiredFieldMessage)) : ''}
                                    required={true}
                                    fullWidth
                                />
                            </>
                        )}
                    </Box>
                </DialogContent>
                <DialogActions sx={{ justifyContent: 'space-between', px: 3, py: 2 }}>
                    <FAWButton variant="outlined" color="inherit" onClick={toggleShow}>
                        {findText(displayText.Close)}
                    </FAWButton>
                    <FAWButton 
                        variant="contained" 
                        color="primary" 
                        onClick={submitModal}
                        disabled={saving}
                    >
                        {saving ? (
                            <FAWLoader size={20} />
                        ) : (
                            findText(displayText.Save)
                        )}
                    </FAWButton>
                </DialogActions>
            </Dialog>
            <Box sx={{ 
                display: 'flex', 
                justifyContent: 'space-between', 
                alignItems: 'center', 
                mb: 2,
                p: 2,
                border: `1px solid ${safeColors.ui.border.static}`,
                borderRadius: 1,
                backgroundColor: safeColors.background.secondary
            }}>
                <FAWTypography 
                    variant="h6"
                    sx={{ 
                        color: safeColors.type.default, 
                        fontSize: '18px',
                        fontWeight: 600
                    }}
                >
                    {html(findText(displayText.KPTableTitle))}
                </FAWTypography>
                <FAWButton variant="contained" color="primary" onClick={toggleShow} startIcon={<AddIcon size="small" />}>
                    {findText(displayText.KPTableClickHereButton)}
                </FAWButton>
            </Box>
            
            {loading ? (
                <FAWSkeleton variant="table" />
            ) : columns && (
                <KeyPersonnelTable
                    data={data}
                    columns={columns}
                    roles={Roles}
                    trans={trans}
                    onEdit={toggleEdit}
                    onDelete={handleDeleteClick}
                    dynamicColumns={dynamicColumns}
                    refDomainOptions={refDomainOptions}
                />
            )}
        </Box>
        
        <FAWToast
            open={toast.open}
            message={toast.message}
            type={toast.type}
            onClose={handleToastClose}
        />

        {/* Delete Confirmation Dialog */}
        <FAWConfirmDialogue
            open={deleteConfirmOpen}
            onClose={handleDeleteCancel}
            onConfirm={handleDeleteConfirm}
            variant="delete"
            title="Confirm Delete"
            message={`Are you sure you want to delete this Key Personnel entry ${itemToDelete?.personName || ''}?`}
            description=""
            loading={deleting}
        />

        {/* Loading Overlay for Table Data */}
        {loading && (
            <Box
                sx={{
                    position: 'fixed',
                    top: 0,
                    left: 0,
                    right: 0,
                    bottom: 0,
                    backgroundColor: safeColors.background.overlay,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    zIndex: 9999
                }}
            >
                <Box
                    sx={{
                        backgroundColor: safeColors.background.default,
                        padding: 3,
                        borderRadius: 2,
                        display: 'flex',
                        alignItems: 'center',
                        gap: 2,
                        boxShadow: 3
                    }}
                >
                    <FAWLoader size={24} />
                    <FAWTypography variant="body1">
                        Loading Key Personnel data...
                    </FAWTypography>
                </Box>
            </Box>
        )}
        </FAWThemeProvider>
    );
}

// Main KeyPersonnel component with error boundary
function KeyPersonnel(props) {
    return (
        <KeyPersonnelErrorBoundary>
            <KeyPersonnelComponent {...props} />
        </KeyPersonnelErrorBoundary>
    );
}

KeyPersonnel.propTypes = {};

export default KeyPersonnel;
