import { Box, Paper, Alert, Button, Dialog, DialogTitle, DialogContent, DialogActions } from '@mui/material';
import FAWTypography from '../FAWTypography';
import FAWButton from '../FAWButton';
import FAWTooltip from '../FAWTooltip';
import { colors } from '../../../utils/designTokens';

import QuestionnaireHeader from '../../FormsManagement/controls/QuestionnaireHeader/QuestionnaireHeader';

import FormRenderer from './components/FormRenderer';
import ActionButtons from './components/ActionButtons';
import { useQuestionnaireState, useAutoSave } from './hooks/useQuestionnaireState';
import { useDependencyManagement } from './hooks/useDependencyManagement';
import { componentTypeMap, normalizeTypeName, validateFormItem } from './utils/componentMapping';
import { createValidationHelpers } from './utils/validationHelpersCore';
import { createFormActions } from './utils/formActions';
import { QuestionnaireService } from './services/QuestionnaireService';
import { scrollToField } from './utils/scrollToError';
