import FAWConfirmDialogue from '../FAWConfirmDialogue';

/**
 * Enhanced URL resolution function with comprehensive handling
 * @param {string} url - The URL to resolve
 * @returns {string} - Fully resolved URL
 */
const resolveRedirectUrl = (url) => {
    if (!url || typeof url !== 'string') {
        return window.location.origin; // Fallback to current origin
    }

    try {
        let processedUrl = url.trim();
        
        // Handle ASP.NET virtual path syntax
        if (processedUrl.startsWith('~/')) {
            // Remove ~ to get relative path from application root
            processedUrl = processedUrl.substring(1);
        } 
        // Handle relative paths (no leading / or protocol)
        else if (!processedUrl.startsWith('/') && !processedUrl.match(/^https?:\/\//)) {
            // Check if it's a known FormsManagement file
            const formsManagementFiles = [
                'FormEditor.aspx', 'formeditor.aspx', 'version.aspx', 
                'Questionnaire.aspx', 'questionnaire.aspx'
            ];
            
            if (formsManagementFiles.some(file => processedUrl.toLowerCase().includes(file.toLowerCase()))) {
                processedUrl = '/FormsManagement/' + processedUrl;
            } else {
                // For other relative paths, assume they're in the current directory
                processedUrl = '/' + processedUrl;
            }
        }
        
        // Construct final URL
        const finalUrl = new URL(processedUrl, window.location.origin).href;
        
        
        return finalUrl;
        
    } catch (error) {
        
        // Fallback to current origin if URL construction fails
        return window.location.origin;
    }
};

const callOnClosePreviewClickAPI = async (answerId) => {
    try {
        const response = await fetch('/Questionnaire/OnClosePreviewClick', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ qaId: answerId })
        });

        const result = await response.json();
        
        return result;
    } catch (error) {
        throw error;
    }
};

const QuestionnairePreview = React.memo(({ 
    questionnaireData, 
    onFormLoad, 
    onDependencyChange,
    onComponentMount,
    onLanguageChange,
    questionnaireVersionId,
    responseContainerId,
    translations = {
        submitLabel: 'Submit',
        saveLabel: 'Save',
        cancelLabel: 'Cancel',
        exportLabel: 'Export Form',
        exportBlankLabel: 'Export Blank Form',
        closeLabel: 'Close',
        confirmSaveLabel: 'Save Confirmation',
        confirmSaveMessage: 'Are you sure you want to save your changes and exit the questionnaire?',
        confirmSaveDescription: 'Your questionnaire will not be reviewed until you complete it and select the Submit button.',
        confirmSubmitLabel: 'Submit Confirmation',
        confirmSubmitMessage: 'Are you sure you want to submit this questionnaire?',
        confirmSubmitDescription: 'Once submitted, you will not be able to make further changes.',
        includeAnswerAppendixHeader: 'Include Answer Appendix',
        includeAnswerAppendixMessage: 'Do you want to export the form with the answer appendix?',
        yesLabel: 'Yes',
        noLabel: 'No',
        closeTooltip: 'Close modal and do not save',
        cancelTooltip: 'Close modal and do not save',
        submitTooltip: 'Save and submit completed form',
        saveTooltip: 'Save completed answers to submit later',
        exportBlankTooltip: 'Generate a PDF',
        exportWithAnswersTooltip: 'Generate a PDF with all questions and possible answers'
    },
    sx = {} 
}) => {

    // Try to get data from props first, then fallback to window.questionnaireJson
    const getQuestionnaireData = () => {
        if (questionnaireData && questionnaireData.form) {
            return questionnaireData;
        }
        
        if (window.questionnaireJson && window.questionnaireJson.form) {
            return window.questionnaireJson;
        }
        
        return null;
    };

    // Get the current language from sessionStorage first, then fallback to data
    const getCurrentLanguage = (questionnaireData) => {
        try {
            // Check if language was reset to English (highest priority)
            const languageResetFlag = localStorage.getItem('questionnaireLanguageResetToEnglish');
            
            if (languageResetFlag === 'true') {
                // Clear the flag after using it
                localStorage.removeItem('questionnaireLanguageResetToEnglish');
                return 'EN';
            }
            
            // Check browser sessionStorage (second priority)
            const sessionLanguage = sessionStorage.getItem('SelectedQuestionnaireLanguage');
            
            if (sessionLanguage) {
                return sessionLanguage;
            }
        } catch (error) {
            console.error('QuestionnairePreview - getCurrentLanguage: Error accessing storage:', error);
        }
        
        // Fallback to questionnaireData.currentLanguage (lowest priority)
        const dataLanguage = questionnaireData?.currentLanguage;
        return dataLanguage;
    };

    const data = getQuestionnaireData();  
      
    if (!data) {
        return (
            <Box sx={{ p: 2, textAlign: 'center' }}>
                <FAWTypography variant="body1" sx={{ color: 'text.secondary' }}>
                    Loading questionnaire data...
                </FAWTypography>
            </Box>
        );
    }

    const formData = data.form;
    const languages = data.availableLanguages;
    const language = getCurrentLanguage(data); // Use sessionStorage-aware function
    const answerId = data.questionnaireAnswerId;
    
    const {
        formItems, setFormItems,
        dependencyMap, setDependencyMap,
        visibilityState, setVisibilityState,
        isLoading, setIsLoading,
        error, setError,
        stats, setStats,
        answers, setAnswers,
        isSaving, setIsSaving,
        isSubmitting, setIsSubmitting,
        isValidating, setIsValidating,
        saveStatus, setSaveStatus,
        fieldErrors, setFieldErrors,
        showExportModal, setShowExportModal,
        isExporting, setIsExporting,
        toast, setToast,
        showSaveModal, setShowSaveModal,
    } = useQuestionnaireState();

    const [showSubmitModal, setShowSubmitModal] = React.useState(false);
    
    // Store all file data for easy access during form submission
    const [allFileData, setAllFileData] = React.useState({});

    const [currentLanguageState, setCurrentLanguageState] = React.useState(language);
    
    // Ref to track if initialization has been done
    const hasInitializedRef = React.useRef(false);
    // Create showToast function for form actions
    const showToast = React.useCallback((toastData) => {
        setToast({
            open: true,
            message: toastData.message,
            type: toastData.type || 'info',
            duration: toastData.duration || 3000
        });
    }, []);

    // Fetch all file data from API using QuestionnaireService
    const fetchAllFileData = React.useCallback(async () => {
        if (!responseContainerId) return;
        
        
        // Fetch attachments - if there are none, API will return empty dict
        // This avoids dependency on formItems which causes unnecessary refetches
        try {
            const response = await QuestionnaireService.getAllAttachmentsForCurrentResponseContainer();
            
            if (response.success && response.data) {
                // Convert API response to a more usable format
                const fileDataMap = {};
                
                // Process dict files (grouped by field name)
                // The API now returns keys like "questionnaireViewer_genQuest138" directly
                if (response.data.dict) {
                    Object.keys(response.data.dict).forEach(key => {
                        const attachments = response.data.dict[key] || [];
                        
                        // Use the key as-is since it's already in the correct format
                        const files = attachments.map(attachment => ({
                            name: attachment.Name,
                            size: attachment.Size,
                            id: attachment.Id,
                            type: attachment.Type,
                            description: attachment.Description,
                            uploaded: true,
                            isExisting: true,
                            canBeDeleted: attachment.CanBeDeleted
                        }));
                        
                        fileDataMap[key] = files;
                    });
                }
                
                // Process rdLevelAtt files (RC-level attachments)
                // These need to be mapped based on their Description field
                if (response.data.rdLevelAtt && response.data.rdLevelAtt.length > 0) {
                    response.data.rdLevelAtt.forEach(attachment => {
                        // Try to extract field name from description
                        let itemName = null;
                        if (attachment.Description && attachment.Description.startsWith('Attached to ')) {
                            // Extract field name and reconstruct the key
                            const fieldName = attachment.Description.replace('Attached to ', '').split(' - ')[0];
                            itemName = `questionnaireViewer_${fieldName}`;
                        }
                        
                        if (itemName) {
                            if (!fileDataMap[itemName]) {
                                fileDataMap[itemName] = [];
                            }
                            
                            fileDataMap[itemName].push({
                                name: attachment.Name,
                                size: attachment.Size,
                                id: attachment.Id,
                                type: attachment.Type,
                                description: attachment.Description,
                                uploaded: true,
                                isExisting: true,
                                canBeDeleted: attachment.CanBeDeleted
                            });
                        }
                    });
                }
                
                setAllFileData(fileDataMap);
            }
        } catch (error) {
            console.error('QuestionnairePreview - fetchAllFileData: Error fetching file data:', error);
        }
    }, [responseContainerId]);

    // Fetch file data on component mount
    React.useEffect(() => {
        if (responseContainerId) {
            fetchAllFileData();
        }
    }, [fetchAllFileData]);

    // Effect to listen for language changes from sessionStorage
    useEffect(() => {
        const handleLanguageChange = () => {
            const newLanguage = getCurrentLanguage(data);
            if (newLanguage !== currentLanguageState) {
                setCurrentLanguageState(newLanguage);
            }
        };

        // Listen for custom language change events
        window.addEventListener('questionnaireJsonRefreshed', handleLanguageChange);
        
        // Listen for storage events (when sessionStorage changes in other tabs/windows)
        window.addEventListener('storage', (e) => {
            if (e.key === 'SelectedQuestionnaireLanguage') {
                handleLanguageChange();
            }
        });

        return () => {
            window.removeEventListener('questionnaireJsonRefreshed', handleLanguageChange);
            window.removeEventListener('storage', handleLanguageChange);
        };
    }, [data, currentLanguageState]);

    // Update currentLanguageState when language prop changes
    useEffect(() => {
        const newLanguage = getCurrentLanguage(data);
        if (newLanguage !== currentLanguageState) {
            setCurrentLanguageState(newLanguage);
        }
    }, [language, data]);

    const { debouncedSave, saveAnswer, clearTimeouts } = useAutoSave(
        answerId, 
        currentLanguageState, 
        setSaveStatus, 
        setIsSaving
    );

    const { handleDependencyChange } = useDependencyManagement(
        dependencyMap,
        visibilityState,
        setVisibilityState,
        onDependencyChange
    );

    const { validateAnswers, validateLegacyChecks, registerValidationMethod } = React.useMemo(() => 
        createValidationHelpers({
            formItems,
            answers,
            visibilityState,
            setFieldErrors,
            allFileData,
            getLatestAnswers: () => answers
        }), [formItems, answers, visibilityState, setFieldErrors, allFileData]
    );
    

   
    const formActions = React.useMemo(() => {
        
        return createFormActions({
            answerId,
            language: currentLanguageState,
            formData,
            answers,
            validateAnswers,
            validateLegacyChecks,
            setIsSaving,
            setIsSubmitting,
            setIsValidating,
            setSaveStatus,
            setIsExporting,
            setShowExportModal,
            fieldErrors,
            dependencyMap,
            formItems,
            handleDependencyChange,
            questionnaireVersionId,
            responseContainerId,
            showSubmitConfirmation: () => setShowSubmitModal(true),
            showToast,
            allFileData
        });
    }, [
        answerId, currentLanguageState, formData, answers, validateAnswers, validateLegacyChecks,
        setIsSaving, setIsSubmitting, setIsValidating, setSaveStatus, setIsExporting, setShowExportModal,
        fieldErrors, dependencyMap, formItems, handleDependencyChange,
        questionnaireVersionId, responseContainerId, showToast,
        allFileData
    ]);


    const { 
        saveAllAnswers, 
        handleSubmit, 
        performSubmit,
        handleExportForm, 
        handleExportBlankForm,
        handleExportBlankFormConfirm 
    } = formActions;

    /**
     * Handles cancel - like legacy OnCancel (no save, just redirect)
     */
    const handleCancel = async () => {
        try {
            // Clear language to English before canceling
            
            // Set flag to force English language on next load
            try {
                localStorage.setItem('questionnaireLanguageResetToEnglish', 'true');
                              
            } catch (error) {
                console.error('QuestionnairePreview - handleCancel: Error setting reset flag:', error);
            }
            
            // Clear session storage language
            try {
                sessionStorage.removeItem('SelectedQuestionnaireLanguage');
            } catch (error) {
                console.error('QuestionnairePreview - handleCancel: Error clearing sessionStorage:', error);
            }
            
            // Clear any server-side session language by calling the language change API
            try {
                const languageChangeResult = await fetch('/FormsManagement/api/QuestionnaireLanguage.aspx/ChangeLanguage', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({ languageCode: 'EN' })
                });
                               
            } catch (error) {
                console.error('QuestionnairePreview - handleCancel: Error setting server language:', error);
            }
            
            // Set server-side reset flag by calling a special endpoint
            try {
                const resetFlagResult = await fetch('/Questionnaire/SetLanguageResetFlag', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({ resetToEnglish: true })
                });
                            
            } catch (error) {
                console.error('QuestionnairePreview - handleCancel: Error setting server reset flag:', error);
            }
            
            // Get the view state that was active when preview was clicked
            const viewState = sessionStorage.getItem('previewFromViewState') || 'initial';
            const messageData = {
                action: 'previewClosed',
                fromViewState: viewState
            };
            
            // Always set localStorage as a backup, regardless of postMessage
            localStorage.setItem('previewClosed', JSON.stringify({
                timestamp: Date.now(),
                fromViewState: viewState
            }));
            
            if (window.opener && window.opener !== window) {
                window.opener.postMessage(messageData, '*');
            } else if (window.parent && window.parent !== window) {
                window.parent.postMessage(messageData, '*');
            }
            
            // Clean up the stored view state
            sessionStorage.removeItem('previewFromViewState');

            const result = await callOnClosePreviewClickAPI(answerId);

            if (result.success) {

                // Enhanced URL resolution with better error handling and logging
                const redirectUrl = resolveRedirectUrl(result.redirectUrl);
                
                
                window.location.href = redirectUrl;
            } else {
                throw new Error(result.error || 'Failed to cancel');
            }
        } catch (error) {
            
            // Fallback to direct redirect - fix the URL construction
            const fallbackUrl = new URL('/Questionnaire', window.location.origin).href;
            
            window.location.href = fallbackUrl;
        }
    };

    // Add effect to watch for language reset flag changes
    useEffect(() => {
        const checkLanguageReset = () => {
            try {
                
                const resetFlag = localStorage.getItem('questionnaireLanguageResetToEnglish');
                if (resetFlag === 'true') {
                    // Clear the flag
                    localStorage.removeItem('questionnaireLanguageResetToEnglish');
                    // Force a re-render by updating state or calling a refresh function
                    // This will cause the component to re-evaluate the language
                    window.location.reload();
                }
            } catch (error) {
                console.error('QuestionnairePreview - useEffect: Error checking reset flag:', error);
            }
        };

        // Check immediately
        checkLanguageReset();

        // Also listen for storage events (in case the flag is set from another tab/window)
        const handleStorageChange = (e) => {
            if (e.key === 'questionnaireLanguageResetToEnglish' && e.newValue === 'true') {
                checkLanguageReset();
            }
        };

        window.addEventListener('storage', handleStorageChange);
        
        return () => {
            window.removeEventListener('storage', handleStorageChange);
        };
    }, []);

    // Add effect to watch for window.questionnaireJson availability
    useEffect(() => {
        if (!data) {
            // Poll for window.questionnaireJson if data is not available
            const checkInterval = setInterval(() => {
                if (window.questionnaireJson && window.questionnaireJson.form) {
                    clearInterval(checkInterval);
                    // Force re-render by updating state
                    setFormItems([]);
                }
            }, 100);

            return () => clearInterval(checkInterval);
        }
    }, [data]);

    useEffect(() => {
        try {
            if (!formData?.FormItems) {
                setError('No questionnaire data provided');
                setIsLoading(false);
                return;
            }

            if (!Array.isArray(formData.FormItems)) {
                setError('Invalid questionnaire data format - FormItems must be an array');
                setIsLoading(false);
                return;
            }

            const items = formData.FormItems
                .filter(validateFormItem)
                .map((it) => ({
                    ...it,
                    OriginalType: it.Type,
                    Type: normalizeTypeName(it.Type)
                }));
            const depMap = {};
            const initialVisibility = {};

            const processItemsForDependencies = (itemList, parentItem = null) => {
                itemList.forEach((item, index) => {
                    try {
                        let isDependent = false;
                        if (item.ParentName && item.ParentValue !== undefined) {
                            const parentName = item.ParentName.trim();
                            const parentValue = typeof item.ParentValue === 'string' ? item.ParentValue.trim() : item.ParentValue;
                            
                            if (!depMap[parentName]) {
                                depMap[parentName] = [];
                            }
                            depMap[parentName].push({
                                childName: item.Name.trim(),
                                parentValue: parentValue,
                                childIndex: index
                            });
                            isDependent = true;
                            

                        }

                        if (item.Name) {
                            const itemName = item.Name.trim();
                            initialVisibility[itemName] = !isDependent;
                        }

                        if (item.FormItems && Array.isArray(item.FormItems)) {
                            processItemsForDependencies(item.FormItems, item);
                        }
                                         } catch (itemError) {
                     }
                });
            };

            processItemsForDependencies(items);

            const typeStats = items.reduce((acc, item) => {
                const type = (item.Type || '').toLowerCase();
                acc[type] = (acc[type] || 0) + 1;
                acc.total++;
                return acc;
            }, { total: 0 });

            const unsupportedTypes = items.filter(item => !componentTypeMap[item.Type]);
            if (unsupportedTypes.length > 0) {
            }

            // Extract existing answers FIRST (before setting visibility)
            const existingAnswers = {};
            items.forEach(item => {
                if (item.Answers && item.Answers.length > 0) {
                    // Handle CheckBoxList as multi-select (multiple selections)
                    if (item.Type === 'CheckBoxList') {
                        // Collect all selected checkbox answers
                        const selectedAnswers = item.Answers
                            .filter(ans => ans.Selected)
                            .map(ans => ans.Answer);
                        
                        // Store as comma-separated string for compatibility with existing logic
                        existingAnswers[item.Name] = selectedAnswers.join(',');
                    } else {
                        // For single-value types, use the first answer
                        const answer = item.Answers[0];
                        existingAnswers[item.Name] = answer.Answer;
                    }
                }
            });

            // Calculate correct initial visibility based on existing answers
            Object.keys(depMap).forEach(parentName => {
                const parentValue = existingAnswers[parentName];
                if (parentValue !== undefined && parentValue !== null && parentValue !== '') {
                    const children = depMap[parentName];
                    children.forEach(({ childName, parentValue: expectedParentValue }) => {
                        const shouldShow = parentValue === expectedParentValue;
                        initialVisibility[childName] = shouldShow;
                    });
                }
            });

            setFormItems(items);
            setDependencyMap(depMap);
            setVisibilityState(initialVisibility);
            setStats(typeStats);
            setAnswers(existingAnswers);
            
            // Initialize state options once when component mounts with answers
            initializeStateOptionsForForm(existingAnswers);
            // Add minimum loading time to ensure loader is visible
            setTimeout(() => {
                setIsLoading(false);
            }, 500); // 500ms minimum loading time

            if (onFormLoad) {
                onFormLoad(typeStats);
            }
                 } catch (error) {
             setError(`Failed to process questionnaire: ${error.message}`);
             setIsLoading(false);
             setStats({ total: 0, error: 1 });
         }
    }, [formData, onFormLoad, setFormItems, setDependencyMap, setVisibilityState, setIsLoading, setError, setStats, setAnswers]);

    // Extract initialization logic into a callable function
    const initializeStateOptionsForForm = React.useCallback((currentAnswers) => {
        if (!formItems || formItems.length === 0) {
            return;
        }

        // Detect which country-state pairs exist in this form
        const hasCountryField = formItems.some(item => item.Name === 'country');
        const hasGenQuest115Field = formItems.some(item => item.Name === 'genQuest115');
        const hasStateField = formItems.some(item => item.Name === 'state');
        const hasGenQuest116Field = formItems.some(item => item.Name === 'genQuest116');
        
        // Initialize state options only for state fields that exist
        formItems.forEach(item => {
            if (item.Name === 'genQuest116' || item.Name === 'state') {
                if (item.Options && item.Options.length > 0) {
                    initializeStateOptions(item.Name, item.Options);
                }
            }
        });
        
        // Handle first country-state pair (country -> state)
        if (hasCountryField && hasStateField) {
            const selectedCountry1 = currentAnswers?.country;
            if (selectedCountry1) {
                updateStateOptionsForCountry(selectedCountry1, 'country');
            } else {
                updateStateOptionsForCountry(null, 'country');
            }
        }
        
        // Handle second country-state pair (genQuest115 -> genQuest116)
        if (hasGenQuest115Field && hasGenQuest116Field) {
            const selectedCountry2 = currentAnswers?.genQuest115;
            if (selectedCountry2) {
                updateStateOptionsForCountry(selectedCountry2, 'genQuest115');
            } else {
                updateStateOptionsForCountry(null, 'genQuest115');
            }
        }
    }, [formItems]);

    // Initialize state options once when answers are populated (after setAnswers completes)
    useEffect(() => {
        if (answers && Object.keys(answers).length > 0 && !hasInitializedRef.current) {
            initializeStateOptionsForForm(answers);
            hasInitializedRef.current = true;
        }
    }, [answers, initializeStateOptionsForForm]);

    useEffect(() => {
        return () => {
            clearTimeouts();
        };
    }, [clearTimeouts]);

    if (isLoading) {
        return (
            <FAWSkeleton variant="questionnaire" />
        );
    }

    if (error) {
        return (
            <Alert severity="error" sx={{ mb: 2 }}>
                <FAWTypography variant="h6">Form Loading Error</FAWTypography>
                <FAWTypography>{error}</FAWTypography>
            </Alert>
        );
    }

    return (
        <>
            {(isSaving || isSubmitting || isExporting || isValidating) && (
                <Box
                    sx={{
                        position: 'fixed',
                        top: 0,
                        left: 0,
                        width: '100vw',
                        height: '100vh',
                        backgroundColor: 'rgba(255, 255, 255, 0.3)',
                        display: 'flex',
                        flexDirection: 'column',
                        justifyContent: 'center',
                        alignItems: 'center',
                        zIndex: 99999,
                        backdropFilter: 'blur(1px)'
                    }}
                >
                    <FAWLoader 
                        size={60} 
                        // label={isValidating ? 'Validating form...' :
                        //        isSaving && !isSubmitting && !isExporting ? 'Saving your data...' : 
                        //        isSubmitting ? 'Submitting form...' :
                        //        isExporting ? 'Preparing export...' : 
                        //        'Processing...'}
                    />
                    {/* <FAWTypography 
                        variant="body2" 
                        sx={{ 
                            color: colors.type.secondary,
                            textAlign: 'center',
                            maxWidth: '300px',
                            mt: 2
                        }}
                    >
                        {isValidating ? 'Please wait while we validate your form.' :
                         isSaving && !isSubmitting && !isExporting ? 'Please wait while we save your data.' : 
                         isSubmitting ? 'Please wait while we submit your form.' :
                         isExporting ? 'Please wait while we prepare your export.' : 
                         'Please wait...'}
                    </FAWTypography> */}
                </Box>
            )}
            
            <Box sx={{ padding: 3, ...sx }}>
                <ActionButtons
                    variant="top"
                    answerId={answerId}
                    isSaving={isSaving}
                    isSubmitting={isSubmitting}
                    isExporting={isExporting}
                    onSubmit={handleSubmit}
                    onExportBlankForm={handleExportBlankForm}
                    onExportForm={handleExportForm}
                    onCancel={handleCancel}
                    onSave={() => setShowSaveModal(true)}
                    onClose={handleCancel}
                    onLanguageChange={onLanguageChange}
                    languages={languages}
                    language={currentLanguageState}
                    submitLabel={translations.submitLabel}
                    submitTooltip={translations.submitTooltip}
                    exportBlankLabel={translations.exportBlankLabel}
                    exportBlankTooltip={translations.exportBlankTooltip}
                    exportLabel={translations.exportLabel}
                    exportWithAnswersTooltip={translations.exportWithAnswersTooltip}
                    cancelLabel={translations.cancelLabel}
                    saveLabel={translations.saveLabel}
                    cancelTooltip={translations.cancelTooltip}
                    saveTooltip={translations.saveTooltip}
                    closeLabel={translations.closeLabel}
                />

                <FAWTypography variant="h4" sx={{
                    color: colors.type.default,
                    marginBottom: 3,
                    fontWeight: 'bold',
                    fontSize: '18px'
                }}>
                    Due Diligence Questionnaire
                </FAWTypography>
                
                {saveStatus.message && (
                    <Alert 
                        id="main-error-box"
                        severity={saveStatus.type}
                        sx={{ 
                            mb: 2, 
                            '& .field-name': {
                                color: colors.action.link.default,
                                fontWeight: 'bold'
                            },
                            '& .error-message': {
                                color: 'inherit'
                            },
                            '& .clickable-error': {
                                cursor: 'pointer',
                                color: colors.action.link.default,
                                '&:hover': {
                                    textDecoration: 'underline',
                                    opacity: 0.8
                                }
                            }
                        }}
                        onClose={() => setSaveStatus({ message: '', type: '' })}
                    >
                        {saveStatus.errors && saveStatus.errors.length > 0 ? (
                            <div>
                                {saveStatus.errors.map((error, index) => (
                                    <div key={error.field ? `${error.field}-${error.message}` : `error-${index}`} style={{ marginBottom: index < saveStatus.errors.length - 1 ? '8px' : '0' }}>
                                        {error.field && error.field !== 'general' && error.field !== 'system' ? (
                                            <span 
                                                className="clickable-error"
                                                onClick={(e) => {
                                                    e.preventDefault();
                                                    e.stopPropagation();
                                                    scrollToField(error.field);
                                                }}
                                                title={`Click to scroll to ${error.field}`}
                                            >
{error.message}
                                            </span>
                                        ) : (
                                            <span>{error.message}</span>
                                        )}
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <div dangerouslySetInnerHTML={{ __html: saveStatus.message.replace(/\n/g, '<br/>') }} />
                        )}
                    </Alert>
                )}

                <Dialog 
                    open={showExportModal} 
                    onClose={() => setShowExportModal(false)}
                    maxWidth="md"
                    fullWidth={true}
                    sx={{
                        '& .MuiDialog-paper': {
                            maxWidth: '700px',
                            width: '100%'
                        }
                    }}
                >
                    <DialogTitle>
                        <FAWTypography variant="h5" sx={{ fontWeight: 'bold', fontSize: '1.5rem' }}>
                            {translations.includeAnswerAppendixHeader}
                        </FAWTypography>
                    </DialogTitle>
                    <DialogContent sx={{ 
                        padding: '20px 24px',
                        overflow: 'hidden',
                        maxWidth: '100%'
                    }}>
                        <FAWTypography sx={{ 
                            wordWrap: 'break-word',
                            overflowWrap: 'break-word'
                        }}>
                            {translations.includeAnswerAppendixMessage}
                        </FAWTypography>
                    </DialogContent>
                    <DialogActions sx={{ 
                        justifyContent: 'space-between', 
                        padding: '16px 24px'
                    }}>
                        <FAWTooltip title={translations.closeTooltip}>
                            <span style={{ display: 'inline-block' }}>
                                <FAWButton 
                                    onClick={() => setShowExportModal(false)} 
                                    variant="outlined" 
                                    color="inherit"
                                    sx={{ minWidth: '100px', whiteSpace: 'nowrap' }}
                                >
                                    {translations.closeLabel}
                                </FAWButton>
                            </span>
                        </FAWTooltip>
                        <FAWTooltip title={translations.exportBlankTooltip}>
                            <span style={{ display: 'inline-block' }}>
                                <FAWButton 
                                    onClick={() => handleExportBlankFormConfirm(false)} 
                                    variant="outlined" 
                                    color="inherit"
                                >
                                    {translations.noLabel}
                                </FAWButton>
                            </span>
                        </FAWTooltip>
                        <FAWTooltip title={translations.exportWithAnswersTooltip}>
                            <span style={{ display: 'inline-block' }}>
                                <FAWButton 
                                    onClick={() => handleExportBlankFormConfirm(true)} 
                                    variant="contained" 
                                    color="primary"
                                >
                                    {translations.yesLabel}
                                </FAWButton>
                            </span>
                        </FAWTooltip>
                    </DialogActions>
                </Dialog>

                <FAWConfirmDialogue
                    open={showSaveModal}
                    onClose={() => setShowSaveModal(false)}
                    onConfirm={() => {
                        setShowSaveModal(false);
                        saveAllAnswers();
                    }}
                    variant="info"
                    title={translations.confirmSaveLabel}
                    message={translations.confirmSaveMessage}
                    description={translations.confirmSaveDescription}
                    confirmLabel={translations.saveLabel}
                    cancelLabel={translations.cancelLabel}
                />

                <FAWConfirmDialogue
                    open={showSubmitModal}
                    onClose={() => setShowSubmitModal(false)}
                    onConfirm={() => {
                        setShowSubmitModal(false);
                        performSubmit();
                    }}
                    variant="info"
                    title={translations.confirmSubmitLabel}
                    message={translations.confirmSubmitMessage}
                    description={translations.confirmSubmitDescription}
                    confirmLabel={translations.submitLabel}
                    cancelLabel={translations.cancelLabel}
                />
                
                <Box sx={{ marginBottom: '24px' }}>
                    <QuestionnaireHeader />
                </Box>
                
                <Paper 
                    sx={{ 
                        padding: 3, 
                        border: 'none',
                        borderRadius: 1, 
                        backgroundColor: colors.background.default, 
                        minHeight: 200,
                        boxShadow: 'none'
                    }}
                >
                    <FormRenderer
                        formItems={formItems}
                        visibilityState={visibilityState}
                        initialAnswers={answers}
                        answerId={answerId}
                        responseContainerId={responseContainerId}
                        language={currentLanguageState}
                        saveAnswerToAPI={saveAnswer}
                        onDependencyChange={handleDependencyChange}
                        fieldErrors={fieldErrors}
                        onAnswersChange={setAnswers}
                        onFormItemsChange={setFormItems}
                        onFileDataRefresh={fetchAllFileData}
                        allFileData={allFileData}
                        registerValidationMethod={registerValidationMethod}
                    />
                    
                    <ActionButtons
                        variant="bottom"
                        answerId={answerId}
                        isSaving={isSaving}
                        isSubmitting={isSubmitting}
                        isExporting={isExporting}
                        onSubmit={handleSubmit}
                        onExportBlankForm={handleExportBlankForm}
                        onExportForm={handleExportForm}
                        onCancel={handleCancel}
                        onSave={() => setShowSaveModal(true)}
                        onClose={handleCancel}
                        onLanguageChange={onLanguageChange}
                        submitLabel={translations.submitLabel}
                        submitTooltip={translations.submitTooltip}
                        exportBlankLabel={translations.exportBlankLabel}
                        exportBlankTooltip={translations.exportBlankTooltip}
                        exportLabel={translations.exportLabel}
                        exportWithAnswersTooltip={translations.exportWithAnswersTooltip}
                        cancelLabel={translations.cancelLabel}
                        saveLabel={translations.saveLabel}
                        cancelTooltip={translations.cancelTooltip}
                        saveTooltip={translations.saveTooltip}
                        closeLabel={translations.closeLabel}
                    />
                </Paper>
            </Box>
            
            <FAWToast 
                open={toast.open} 
                message={toast.message} 
                type={toast.type || 'info'}
                duration={toast.duration}
                onClose={() => setToast(prev => ({ ...prev, open: false }))} 
            />
        </>
    );
}, (prevProps, nextProps) => {
    const prevLength = Array.isArray(prevProps.questionnaireData?.form?.FormItems)
        ? prevProps.questionnaireData.form.FormItems.length
        : 0;
    const nextLength = Array.isArray(nextProps.questionnaireData?.form?.FormItems)
        ? nextProps.questionnaireData.form.FormItems.length
        : 0;
    return prevLength === nextLength;
});

export default QuestionnairePreview;