import { useState, useRef, useCallback } from 'react';
import { QuestionnaireService } from '../services/QuestionnaireService';

export const useQuestionnaireState = () => {
    const [formItems, setFormItems] = useState([]);
    const [dependencyMap, setDependencyMap] = useState({});
    const [visibilityState, setVisibilityState] = useState({});
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState(null);
    const [stats, setStats] = useState({ total: 0 });
    
    const [answers, setAnswers] = useState({});
    const [isSaving, setIsSaving] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isValidating, setIsValidating] = useState(false);
    const [saveStatus, setSaveStatus] = useState({ message: '', type: '' });
    const [fieldErrors, setFieldErrors] = useState({});

    const [showExportModal, setShowExportModal] = useState(false);
    const [isExporting, setIsExporting] = useState(false);
    const [showSaveModal, setShowSaveModal] = useState(false);

    const [toast, setToast] = useState({ open: false, message: '', type: 'info', duration: 3000 });
    

    return {
        // Form state
        formItems, setFormItems,
        dependencyMap, setDependencyMap,
        visibilityState, setVisibilityState,
        isLoading, setIsLoading,
        error, setError,
        stats, setStats,
        
        // Answer state
        answers, setAnswers,
        isSaving, setIsSaving,
        isSubmitting, setIsSubmitting,
        isValidating, setIsValidating,
        saveStatus, setSaveStatus,
        fieldErrors, setFieldErrors,
        
        // Export state
        showExportModal, setShowExportModal,
        isExporting, setIsExporting,
        showSaveModal, setShowSaveModal,
        
        // Toast state
        toast, setToast
    };
};

export const useAutoSave = (answerId, language, setSaveStatus, setIsSaving) => {
    const debouncedSaveRef = useRef({});

    const debouncedSave = useCallback((itemName, value, delay = 1000) => {
        if (debouncedSaveRef.current[itemName]) {
            clearTimeout(debouncedSaveRef.current[itemName]);
        }
        
        debouncedSaveRef.current[itemName] = setTimeout(() => {
            saveAnswer(itemName, value, false);
        }, delay);
    }, []);

    const saveAnswer = useCallback(async (itemName, value, showStatus = true) => {
        if (!answerId || !itemName) {
            console.warn('Cannot save: missing answerId or itemName');
            return;
        }

        try {
            if (showStatus) {
                setIsSaving(true);
                setSaveStatus({ message: 'Saving...', type: 'info' });
            }
            
            await QuestionnaireService.saveAnswer(answerId, itemName, value, language);
            
            if (showStatus) {
                setSaveStatus({ message: 'Saved successfully', type: 'success' });
            }
        } catch (error) {
            console.error('Failed to save answer:', error);
            if (showStatus) {
                setSaveStatus({ 
                    message: `Save failed: ${error.message}`, 
                    type: 'error' 
                });
            }
        } finally {
            if (showStatus) {
                setIsSaving(false);
                setTimeout(() => setSaveStatus({ message: '', type: '' }), 3000);
            }
        }
    }, [answerId, language, setSaveStatus, setIsSaving]);

    const clearTimeouts = useCallback(() => {
        Object.values(debouncedSaveRef.current).forEach(timeoutId => {
            if (timeoutId) {
                clearTimeout(timeoutId);
            }
        });
    }, []);

    return {
        debouncedSave,
        saveAnswer,
        clearTimeouts
    };
};
