import React, { useMemo } from "react";
import FAWTable from '../../../component-widget/FAWTable/FAWTable';

function PSACompanyTable({ columns, data, onEdit, onDelete }) {
  // Convert columns to AtlasTable format
  const fawTableColumns = useMemo(() => {
    return columns[0].columns.map(col => {
      const colDef = {
        field: col.accessor,
        headerName: col.Header,
        sortable: col.sortable !== false,
        filterable: true,
        flex: col.accessor === 'Row' ? 0 : 1,
        minWidth: 100,
        align: 'left', // Explicitly set left alignment for all columns
        headerAlign: 'left', // Explicitly set left alignment for headers
      };

      // Convert cell renderer - handle special cases like PercentOwnership formatting
      if (col.Cell) {
        colDef.renderCell = (params) => {
          // Convert MUI DataGrid params to react-table format
          return col.Cell({ cell: { value: params.value } });
        };
      }

      return colDef;
    });
  }, [columns]);

  const fawTableRows = useMemo(() => {
    return data.map((row, index) => {
      let uniqueId;
      if (row.Row !== undefined && row.Row !== null) {
        uniqueId = row.Row;
      } else if (row.id !== undefined && row.id !== null) {
        uniqueId = row.id;
      } else if (row.Id !== undefined && row.Id !== null) {
        uniqueId = row.Id;
      } else {
        uniqueId = `psa_company_${index}`;
      }
      
      return {
        ...row,
        id: uniqueId,
      };
    });
  }, [data]);

  // Convert actions to AtlasTable format
  const fawTableActions = useMemo(() => {
    return [
      {
        icon: 'edit',
        onClick: (row) => onEdit(row.Row || row),
        tooltip: 'Edit'
      },
      {
        icon: 'delete',
        onClick: (row) => onDelete(row.Row || row),
        tooltip: 'Delete'
      }
    ];
  }, [onEdit, onDelete]);

  return (
    <div style={{ marginTop: '0px' }}>
      <FAWTable
          rows={fawTableRows}
          columns={fawTableColumns}
          actions={fawTableActions}
          getRowId={(row) => {
            if (row.Row !== undefined && row.Row !== null) {
              return row.Row;
            }
            return row.id;
          }}
          showPagination={true}
          defaultPageSize={10}
          showSearch={true}
          searchPlaceholder="Search..."
          autoHeight={true}
          showToolbar={true}
          showExport={true}
          showColumns={true}
          showFilter={true}
          enableMultiSelect={false}
          defaultHiddenColumns={['AdditionalInfo']}
          emptyStateTitle="No data available"
          emptyStateNoResultsTitle="No results found"
          emptyStateNoResultsMessage="Your search didn't match any PSA Company entries."
          emptyCellPlaceholder="---"
          rowHeight={44}
          columnHeaderHeight={56}
        />
    </div>
  );
}

PSACompanyTable.propTypes = {};

export default PSACompanyTable;
