import React from 'react';
import { Box } from '@mui/material';
import FAWDropdown from '../../FAWDropdown';
import FAWButton from '../../FAWButton';
import FAWTooltip from '../../FAWTooltip';

const ActionButtons = ({
    answerId,
    isSaving,
    isSubmitting,
    isExporting,
    onSubmit,
    onExportBlankForm,
    onExportForm,
    onCancel,
    onSave,
    onClose,
    onLanguageChange,
    languages = [],
    language,
    submitLabel = 'Submit',
    submitTooltip,
    exportBlankLabel = 'Export Blank Form',
    exportBlankTooltip,
    exportWithAnswersTooltip,
    exportLabel = 'Export Form',
    cancelLabel = 'Cancel',
    saveLabel = 'Save',
    closeLabel = 'Close',
    cancelTooltip,
    saveTooltip,
    variant = 'top',
    sx = {}
}) => {
    const isTopVariant = variant === 'top';
    
    const buttonSx = {
        minWidth: '120px',
        fontWeight: 500,
        textTransform: 'none'
    };

    const cancelButtonSx = {
        minWidth: '100px',
        fontWeight: 500,
        textTransform: 'none'
    };

    const closeButtonSx = {
        minWidth: '100px',
        fontWeight: 500,
        textTransform: 'none'
    };

    const exportBlankSx = {
        minWidth: '140px',
        fontWeight: 500,
        textTransform: 'none'
    };

    const languageDropdownSx = {
        minWidth: '150px',
        maxWidth: '200px',
        width: 'auto',
        marginLeft: isTopVariant ? 'auto' : '0'
    };

    const containerSx = {
        display: 'flex',
        gap: 2,
        flexWrap: 'wrap',
        alignItems: 'center',
        ...(isTopVariant ? { mb: 3 } : { mt: 3 }),
        ...sx
    };

    return (
        <Box sx={containerSx}>
            {answerId === 0 && (
                <FAWButton
                    variant="outlined"
                    color="inherit"
                    onClick={onClose}
                    sx={closeButtonSx}
                >
                    {closeLabel}
                </FAWButton>
            )}
            
            {answerId > 0 && (
                <>
                    <FAWTooltip title={submitTooltip}>
                        <span style={{ display: 'inline-block' }}>
                            <FAWButton
                                variant="contained"
                                color="primary"
                                onClick={onSubmit}
                                disabled={isSubmitting || isExporting}
                                sx={buttonSx}
                                style={{ pointerEvents: isSubmitting || isExporting ? 'none' : 'auto' }}
                            >
                                {submitLabel}
                            </FAWButton>
                        </span>
                    </FAWTooltip>
                    
                    <FAWTooltip title={exportBlankTooltip}>
                        <span style={{ display: 'inline-block' }}>
                            <FAWButton
                                variant="outlined"
                                color="inherit"
                                onClick={onExportBlankForm}
                                disabled={isSaving || isSubmitting || isExporting}
                                sx={exportBlankSx}
                                style={{ pointerEvents: isSaving || isSubmitting || isExporting ? 'none' : 'auto' }}
                            >
                                {exportBlankLabel}
                            </FAWButton>
                        </span>
                    </FAWTooltip>
                    
                    <FAWTooltip title={exportWithAnswersTooltip}>
                        <span style={{ display: 'inline-block' }}>
                            <FAWButton
                                variant="outlined"
                                color="inherit"
                                onClick={onExportForm}
                                disabled={isSaving || isSubmitting || isExporting}
                                sx={buttonSx}
                                style={{ pointerEvents: isSaving || isSubmitting || isExporting ? 'none' : 'auto' }}
                        >
                            {exportLabel}
                            </FAWButton>
                        </span>
                    </FAWTooltip>
                    
                    <FAWTooltip title={cancelTooltip}>
                        <span style={{ display: 'inline-block' }}>
                            <FAWButton
                                variant="outlined"
                                color="inherit"
                                onClick={onCancel}
                                sx={cancelButtonSx}
                            >
                                {cancelLabel}
                            </FAWButton>
                        </span>
                    </FAWTooltip>
                    
                    <FAWTooltip title={saveTooltip}>
                        <span style={{ display: 'inline-block' }}>
                            <FAWButton
                                variant="contained"
                                color="primary"
                                onClick={onSave}
                                disabled={isSaving || isSubmitting || isExporting}
                                sx={cancelButtonSx}
                                style={{ pointerEvents: isSaving || isSubmitting || isExporting ? 'none' : 'auto' }}
                                >
                                    {saveLabel}
                            </FAWButton>
                        </span>
                    </FAWTooltip>
                </>
            )}
            
            {answerId > 0 && isTopVariant && languages.length > 0 && (
                <Box sx={{ width: 'auto', flexShrink: 0 }}>
                    <FAWDropdown
                        value={language}
                        options={languages.map(lang => ({ 
                            label: lang.name || lang.description || lang.code, 
                            value: lang.code 
                        }))}
                        onChange={async (option) => {
                            const newLanguage = option?.value || 'EN';
                            
                            // Use custom onLanguageChange handler if provided
                            if (onLanguageChange) {
                                onLanguageChange(newLanguage);
                                return;
                            }
                        }}
                        fullWidth={false}
                        sx={languageDropdownSx}
                    />
                </Box>
            )}
        </Box>
    );
};

export default ActionButtons;
