/**
 * Validation Helper Functions
 * 
 * All utility functions for validation - moved here to keep main engine clean
 */

/**
 * Generate unique error ID
 */
export const generateErrorId = () => {
  return `error_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
};

/**
 * Convert mask pattern to regex (replicates legacy C# logic)
 * Examples:
 * - "+999.99" → "[-+]?[0-9]{1,3}(\.[0-9]{1,2})?"
 * - "999" → "[0-9]{1,3}"
 * - "-999.99" → "[-+]?[0-9]{1,3}(\.[0-9]{1,2})?"
 */
export const convertMaskToRegex = (mask) => {
  if (!mask || typeof mask !== 'string') {
    return '';
  }

  let regex = '';
  const firstChar = mask.substring(0, 1);
  
  // Handle sign prefix (+/-)
  if (firstChar === '+' || firstChar === '-') {
    regex += '[-+]?';
  }
  
  // Find numeric patterns in the mask
  const numericMatches = mask.match(/[0-9]+/g);
  
  if (numericMatches && numericMatches.length > 0) {
    // First numeric group (integer part)
    regex += `[0-9]{1,${numericMatches[0].length}}`;
    
    // Second numeric group (decimal part) - optional
    if (numericMatches.length > 1) {
      regex += `(\\.[0-9]{1,${numericMatches[1].length}})?`;
    }
  }
  
  return regex;
};

/**
 * Processes TextBox attributes to add appropriate validators (replicates XSLT logic)
 */
export const processTextBoxAttributes = (formItem, config) => {
  const attributes = formItem.Attributes || [];
  
  // Find Format attribute
  const formatAttr = attributes.find(attr => attr.AttributeName === 'Format');
  if (formatAttr) {
    const formatValue = formatAttr.AttributeValue;
    
    switch (formatValue) {
      case 'Alphabet':
        config.validators.push({
          name: 'alphabet',
          options: {
            message: formItem.ValidationMessage || 'Only alphabetic characters and spaces are allowed'
          }
        });
        break;
        
      case 'AlphaNumeric':
        config.validators.push({
          name: 'alphaNumeric',
          options: {
            message: formItem.ValidationMessage || 'Only alphanumeric characters, spaces, and underscores are allowed'
          }
        });
        break;
        
      case 'Numeric':
        // Check for Mask attribute for complex numeric patterns
        const maskAttr = attributes.find(attr => attr.AttributeName === 'Mask');
        if (maskAttr && maskAttr.AttributeValue) {
          config.validators.push({
            name: 'maskPattern',
            options: {
              mask: maskAttr.AttributeValue,
              message: formItem.ValidationMessage || 'Please match the requested format'
            }
          });
        } else {
          // Basic numeric validation
          config.validators.push({
            name: 'numericFormat',
            options: {
              message: formItem.ValidationMessage || 'Only numeric characters are allowed'
            }
          });
        }
        
        // Add MinValue validation if present
        const minValueAttr = attributes.find(attr => attr.AttributeName === 'MinValue');
        if (minValueAttr && minValueAttr.AttributeValue) {
          const minValue = parseFloat(minValueAttr.AttributeValue);
          if (!isNaN(minValue)) {
            config.validators.push({
              name: 'number',
              options: {
                min: minValue,
                message: formItem.ValidationMessage || `Value must be at least ${minValue}`
              }
            });
          }
        }
        
        // Add MaxValue validation if present
        const maxValueAttr = attributes.find(attr => attr.AttributeName === 'MaxValue');
        if (maxValueAttr && maxValueAttr.AttributeValue) {
          const maxValue = parseFloat(maxValueAttr.AttributeValue);
          if (!isNaN(maxValue)) {
            config.validators.push({
              name: 'number',
              options: {
                max: maxValue,
                message: formItem.ValidationMessage || `Value must be no more than ${maxValue}`
              }
            });
          }
        }
        break;
        
      case 'Confirm':
        // 🎯 NEW: Handle confirmation text validation (like Accept field)
        const confirmationTextAttr = attributes.find(attr => attr.AttributeName === 'ConfirmationText');
        if (confirmationTextAttr && confirmationTextAttr.AttributeValue) {
          config.validators.push({
            name: 'confirmationText',
            options: {
              expectedText: confirmationTextAttr.AttributeValue,
              message: formItem.ValidationMessage || `You must type "${confirmationTextAttr.AttributeValue}" to confirm`
            }
          });
        } else {
          // Fallback to acceptText validator for genQuest139
          config.validators.push({
            name: 'acceptText',
            options: {
              message: formItem.ValidationMessage || 'You must type "Accept" to acknowledge'
            }
          });
        }
        break;
        
      case 'MatchInput':
        // 🎯 NEW: Handle field matching validation (like email confirmation)
        const matchingInputAttr = attributes.find(attr => attr.AttributeName === 'MatchingInput');
        if (matchingInputAttr && matchingInputAttr.AttributeValue) {
          config.validators.push({
            name: 'matchInput',
            options: {
              matchFieldName: matchingInputAttr.AttributeValue,
              message: formItem.ValidationMessage || `This field must match ${matchingInputAttr.AttributeValue}`
            }
          });
        }
        break;
        
      case 'Percent':
        // Handle percentage format validation
        config.validators.push({
          name: 'percentage',
          options: {
            message: formItem.ValidationMessage || 'Please enter a valid percentage (0-100)'
          }
        });
        break;
        
      case 'Email':
        // Handle email format validation
        config.validators.push({
          name: 'email',
          options: {
            message: formItem.ValidationMessage || 'Please enter a valid email address'
          }
        });
        break;
        
      case 'Phone':
        // Handle phone format validation
        config.validators.push({
          name: 'phone',
          options: {
            message: formItem.ValidationMessage || 'Please enter a valid phone number'
          }
        });
        break;
    }
  }
  
  // MaxLength attribute
  const maxLengthAttr = attributes.find(attr => attr.AttributeName === 'MaxLength');
  if (maxLengthAttr && maxLengthAttr.AttributeValue) {
    const maxLength = parseInt(maxLengthAttr.AttributeValue, 10);
    if (!isNaN(maxLength) && maxLength > 0) {
      config.validators.push({
        name: 'maxLength',
        options: {
          maxLength: maxLength,
          message: formItem.ValidationMessage || `Maximum ${maxLength} characters allowed`
        }
      });
    }
  }
};

/**
 * Field types excluded from frontend validation
 */
export const EXCLUDE_VALIDATION_TYPES = [
  // These are handled by backend or special business rules
];

/**
 * Check if field type should be excluded from frontend validation
 */
export const isBackendValidatedField = (fieldType) => {
  return EXCLUDE_VALIDATION_TYPES.includes(fieldType);
};