import React, { useEffect, useState, useMemo } from "react";
import axios from "axios";
import FAWTable from '../../../component-widget/FAWTable/FAWTable';
import FAWButton from "../../../component-widget/FAWButton";
import FAWCheckbox from "../../../component-widget/FAWCheckbox";
import FAWTypography from "../../../component-widget/FAWTypography";
import FAWThemeProvider from '../../../Theme/FAWThemeProvider';
import Box from '@mui/material/Box';
import Stack from '@mui/material/Stack';
import {
    displayText,
    defaultQuestionText,
    defaultGeneralInfo
} from "./constants";
// Safe template function to replace lodash.template (security vulnerability fix)
const safeTemplate = (templateString) => {
    return (data) => {
        if (templateString == null || typeof templateString !== 'string') {
            return '';
        }
        const safeData = data != null && typeof data === 'object' ? data : {};
        return templateString.replace(/\$\{(\w+)\}/g, (match, key) => {
            const value = safeData[key];
            if (value === undefined || value === null || (typeof value === 'number' && isNaN(value))) {
                return '0';
            }
            return String(value);
        });
    };
};
import { colors } from "../../../../utils/designTokens";

// Ensure colors object is properly initialized
const safeColors = {
    interactive: {
        primary: {
            idle: colors?.interactive?.primary?.idle || '#1976d2'
        }
    },
    type: {
        inverse: colors?.type?.inverse || '#ffffff'
    }
};

// Error Boundary Component for KeyPersonnelTable
class KeyPersonnelTableErrorBoundary extends React.Component {
    constructor(props) {
        super(props);
        this.state = { hasError: false, error: null };
    }

    static getDerivedStateFromError(error) {
        return { hasError: true, error };
    }

    componentDidCatch(error, errorInfo) {
        console.error('KeyPersonnelTable Error:', error, errorInfo);
    }

    render() {
        if (this.state.hasError) {
            return (
                <Box sx={{ p: 2, border: '1px solid #f44336', borderRadius: 1, backgroundColor: '#ffebee' }}>
                    <FAWTypography variant="h6" sx={{ color: '#d32f2f', mb: 1 }}>
                        KeyPersonnelTable Component Error
                    </FAWTypography>
                    <FAWTypography variant="body2" sx={{ color: '#666' }}>
                        {this.state.error?.message || 'An unexpected error occurred in the table'}
                    </FAWTypography>
                </Box>
            );
        }

        return this.props.children;
    }
}

function KeyPersonnelTableComponent({ columns, data, roles = [], trans, onEdit, onDelete, dynamicColumns = [], refDomainOptions = {} }) {
    const [filterValue, setFilterValue] = useState("");
    const [thresholdConfirmation, setThresholdConfirmation] = useState(false);
    const [isThresholdEnabled, setIsThresholdEnabled] = useState(false);
    const [thresholdValue, setThresholdValue] = useState(100);
    const [bypassValue, setBypassValue] = useState(0);
    const [isBypassEnabled, setIsBypassEnabled] = useState(false);
    const [filteredData, setFilteredData] = useState(() => (Array.isArray(data) ? data : []));


    const findText = id => {
        if (Array.isArray(trans) && trans.length > 0) {
            const question = trans.find(x => x && x.QuestionId === id);
            return question && question.LabelText != null ? question.LabelText : defaultQuestionText[id];
        }

        return defaultQuestionText[id];
    };

    const handleBypassChange = async (newValue) => {
        setBypassValue(newValue);
        try {
            await axios.post("/Questionnaire/UpdateBypassProperty", { value: newValue });
        } catch (error) {
            console.error("Failed to update bypass property:", error);
        }
    };

    const findGeneralInfo = id => {
        if (Array.isArray(trans) && trans.length > 0) {
            const question = trans.find(x => x && x.QuestionId === id);
            return question && question.GeneralInfo != null ? question.GeneralInfo : defaultGeneralInfo[id];
        }

        return defaultGeneralInfo[id];
    };

    const compiledOwnershipTemplate = safeTemplate(
        findText(displayText.CurrentOwnershipPercent)
    );

    const compiledConfirmOwnershipTemplate = safeTemplate(
        findGeneralInfo(displayText.OwnershipThresholdConfirmation)
    );

    const handleFilterChange = (val) => {
        setFilterValue(val);
        const sourceData = Array.isArray(data) ? data : [];
        if (val) {
            const filtered = sourceData.filter(item =>
                Array.isArray(item.Roles) && item.Roles.includes(val)
            );
            setFilteredData(filtered);
        } else {
            setFilteredData(sourceData);
        }
    };

    const clearFilter = () => {
        setFilterValue(undefined);
        setFilteredData(Array.isArray(data) ? data : []);
    };

    const totalPercentage = () => {        
        if (!data || !Array.isArray(data)) {
            return 0;
        }
        const result = data.map(dt => {
            // Handle both camelCase and PascalCase property names in case of JSON serialization differences
            const ownershipValue = dt.OwnershipPercent ?? dt.ownershipPercent ?? 0;
            return parseFloat(ownershipValue) || 0;
        }).reduce((total, num) => total + num, 0);
        return (typeof result === 'number' && !isNaN(result)) ? result : 0;
    };

    // Threshold behavior
    const handlethresholdConfirmationChange = async e => {
        const kp = {
            ...data,
            isConfirmed: !thresholdConfirmation
        };

        const res = await axios.post("/Questionnaire/AddThresholdConfirmation", kp);
        setThresholdConfirmation(!thresholdConfirmation);
    };

    useEffect(() => {
        const getKeyPersonnelProperties = async () => {
            try {
                const { data } = await axios.get(
                    "/Questionnaire/GetKeyPersonnelProperties"
                );

                const {
                    OwnershipProperty,
                    ThresholdEnabledProperty,
                    BypassProperty,
                    BypassEnabledProperty,
                    ThresholdConfirmationProperty
                } = data;

                setIsThresholdEnabled(ThresholdEnabledProperty);
                setThresholdValue(OwnershipProperty);
                setBypassValue(BypassProperty);
                setIsBypassEnabled(BypassEnabledProperty);
                setThresholdConfirmation(ThresholdConfirmationProperty);
            } catch (error) {
                console.error("[KeyPersonnelTable] Error fetching key personnel properties:", error);
            }
        };

        getKeyPersonnelProperties();
    }, []);

    // Update filtered data when data changes
    useEffect(() => {
        const sourceData = Array.isArray(data) ? data : [];
        if (filterValue) {
            const filtered = sourceData.filter(item =>
                Array.isArray(item.Roles) && item.Roles.includes(filterValue)
            );
            setFilteredData(filtered);
        } else {
            setFilteredData(sourceData);
        }
    }, [data, filterValue]);

    // Convert columns to FAWTable format - now supports dynamic columns
    const fawTableColumns = useMemo(() => {
        // Use dynamic columns if available, otherwise fallback to passed columns
        const sourceColumns = columns[0]?.columns || [];
        
        return sourceColumns
            .filter(col => col.accessor !== "Row")
            .map(col => {
                const colDef = {
                    field: col.accessor,
                    headerName: col.Header,
                    sortable: col.sortable !== false,
                    filterable: true,
                    flex: 1,
                    minWidth: 100,
                };

                // Handle special cell renderers
                if (col.Cell) {
                    if (col.accessor === "Roles") {
                        // Use FAWTable's built-in chip type
                        colDef.type = 'chip';
                        // MUI DataGrid Pro signature: (value, row, column, apiRef)
                        colDef.valueGetter = (value, row, column, apiRef) => {
                            if (!row) {
                                return [];
                            }
                            // Handle both camelCase and PascalCase property names
                            const roleValues = row.Roles || row.roles || [];
                            const ownershipPercent = row.OwnershipPercent ?? row.ownershipPercent ?? 0;
                            
                            // Convert role values to display labels
                            return roleValues.map((roleValue) => {
                                const roleObj = roles.find(x => x.value === roleValue);
                                const roleLabel = roleObj ? roleObj.label : roleValue;
                                
                                // For Owner role, include percentage in the label
                                if (roleValue === "Owner" && ownershipPercent > 0) {
                                    return `${roleLabel} (${ownershipPercent}%)`;
                                }
                                return roleLabel;
                            });
                        };
                        // Set chip styles to match original Badge styling using Atlas theme tokens
                        colDef.chipStyles = {
                            backgroundColor: safeColors.interactive.primary.idle,
                            color: safeColors.type.inverse
                        };
                        colDef.filterable = true;
                    } else if (col.accessor === "EmbargoedResident") {
                        // This is the embargoed column with yes/no display
                        colDef.renderCell = (params) => {
                            return col.Cell({ cell: { value: params.value } });
                        };
                    } else {
                        // Default cell renderer
                        colDef.renderCell = (params) => {
                            return col.Cell({ cell: { value: params.value } });
                        };
                    }
                }

                // Handle dynamic columns from configuration
                const dynamicCol = dynamicColumns.find(dc => 
                    dc.name === col.accessor || dc.accessor === col.accessor
                );
                
                if (dynamicCol) {
                    // Handle checkbox columns
                    if (dynamicCol.type === "CheckBox" || dynamicCol.formFieldType === "checkbox") {
                        colDef.renderCell = (params) => {
                            const value = params.value;
                            if (value === null || value === undefined || value === "") {
                                return <span>-</span>;
                            }
                            if (value === true || (typeof value === 'string' && value.toLowerCase() === "true")) {
                                return <span>{findText(displayText.KPTableTextYes)}</span>;
                            }
                            return <span>{findText(displayText.KPTableTextNo)}</span>;
                        };
                    }
                    
                    // Handle dropdown columns with refDomain
                    else if (dynamicCol.formFieldType === "select" && dynamicCol.refDomain && refDomainOptions[dynamicCol.refDomain]) {
                        colDef.renderCell = (params) => {
                            const value = params.value;
                            if (value === null || value === undefined || value === "") {
                                return <span>-</span>;
                            }
                            
                            // Find the option that matches the value
                            const options = refDomainOptions[dynamicCol.refDomain] || [];
                            const option = options.find(opt => {
                                const optionValue = typeof opt === 'object' ? (opt.value || opt.Value) : opt;
                                return optionValue === value;
                            });
                            
                            if (option) {
                                const optionLabel = typeof option === 'object' ? (option.label || option.Label || option.value || option.Value) : option;
                                return <span>{optionLabel}</span>;
                            }
                            
                            // If no matching option found, display the raw value
                            return <span>{value}</span>;
                        };
                    }
                }

                return colDef;
            });
    }, [columns, roles, dynamicColumns]);

    // Convert filteredData to FAWTable rows format (ensure each row has an id)
    const fawTableRows = useMemo(() => {
        const source = Array.isArray(filteredData) ? filteredData : [];
        return source.map((row, index) => ({
            ...row,
            id: row.id || row.Id || row.Row?.id || row.Row?.Id || index,
        }));
    }, [filteredData]);

    // Convert actions to FAWTable format
    const fawTableActions = useMemo(() => {
        return [
            {
                icon: 'edit',
                onClick: (row) => onEdit(row.Row || row),
                tooltip: 'Edit'
            },
            {
                icon: 'delete',
                onClick: (row) => onDelete(row.Row || row),
                tooltip: 'Delete'
            }
        ];
    }, [onEdit, onDelete]);

    // Check if roles should be shown (for filter buttons)
    const showRoleFilters = roles && roles.length > 0;

    return (
        <Box>
            <Box sx={{ mt: 0, width: '100%' }}>
                <FAWTable
                    rows={fawTableRows}
                    columns={fawTableColumns}
                    actions={fawTableActions}
                    showPagination={true}
                    defaultPageSize={10}
                    showSearch={true}
                    searchPlaceholder="Search..."
                    autoHeight={true}
                    showToolbar={true}
                    showExport={true}
                    showColumns={true}
                    showFilter={true}
                    enableMultiSelect={false}
                    emptyStateTitle="No data available"
                    emptyStateNoResultsTitle="No results found"
                    emptyStateNoResultsMessage="Your search didn't match any Key Personnel entries."
                    emptyCellPlaceholder="---"
                    rowHeight={44}
                    columnHeaderHeight={56}
                />
            </Box>
            
            {/* Only show role filters if roles are configured */}
            {showRoleFilters && (
                <Box sx={{ mt: 2, display: 'flex', flexDirection: 'column', gap: 2 }}>
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                        <FAWTypography variant="body1">
                            {findText(displayText.Filters)}
                        </FAWTypography>
                        {filterValue && (
                            <FAWButton variant="text" onClick={clearFilter}>
                                {findText(displayText.ClearFilter)}
                            </FAWButton>
                        )}
                    </Box>
                    
                    <Stack direction="row" spacing={1}>
                        {roles.map(({ label, value }) => (
                            <FAWButton
                                key={label}
                                variant={value === filterValue ? "contained" : "outlined"}
                                color="primary"
                                onClick={() => handleFilterChange(value)}
                            >
                                {label}
                            </FAWButton>
                        ))}
                    </Stack>
                </Box>
            )}
            
            <Box sx={{ mt: 2 }}>
                <FAWTypography variant="body1">
                    {compiledOwnershipTemplate({ totalPercentage: totalPercentage() })}
                </FAWTypography>
            </Box>

            {isBypassEnabled &&
                totalPercentage() < thresholdValue && (
                    <Box sx={{ mt: 2 }}>
                        <FAWCheckbox
                            id="keyPersonnelConfirmation"
                            label={compiledConfirmOwnershipTemplate({ 'bypassValue': bypassValue })}
                            checked={thresholdConfirmation}
                            onChange={handlethresholdConfirmationChange}
                        />
                    </Box>
                )}
        </Box>
    );
}

// Main KeyPersonnelTable component with error boundary
function KeyPersonnelTable(props) {
    return (
        <FAWThemeProvider>
            <KeyPersonnelTableErrorBoundary>
                <KeyPersonnelTableComponent {...props} />
            </KeyPersonnelTableErrorBoundary>
        </FAWThemeProvider>
    );
}

KeyPersonnelTable.propTypes = {};

export default KeyPersonnelTable;
