/**
 * Generates an ID for a form item based on its Name attribute
 * @param {Object} item - The form item object
 * @param {string} prefix - Optional prefix for the ID (default: 'React')
 * @param {number} index - Fallback index if no Name is available
 * @returns {string} Generated ID
 */
export const generateFormItemId = (item, prefix = 'React', index = 0) => {
    // Use Name attribute if available, otherwise fallback to index
    const baseId = item?.Name || item.NameRaw || `item_${index}`;
   
    // Clean the base ID (remove special characters, ensure valid HTML ID)
    const cleanId = baseId.replace(/[^a-zA-Z0-9_-]/g, '_');
   
    // Add prefix if provided
    return prefix ? `${prefix}_${cleanId}` : cleanId;
};
 
