/**
 * Extracts validation attributes from form item (replicates XSLT ItemProperties processing)
 */
const extractValidationAttributes = (item) => {
    const attributes = {};
    
    if (item.Attributes && Array.isArray(item.Attributes)) {
        item.Attributes.forEach(attr => {
            switch (attr.AttributeName) {
                case 'Format':
                    attributes.format = attr.AttributeValue;
                    break;
                case 'Mask':
                    attributes.mask = attr.AttributeValue;
                    break;
                case 'MinValue':
                    attributes.minValue = parseFloat(attr.AttributeValue);
                    break;
                case 'MaxValue':
                    attributes.maxValue = parseFloat(attr.AttributeValue);
                    break;
                case 'MaxLength':
                    attributes.maxLength = parseInt(attr.AttributeValue, 10);
                    break;
                case 'TextMode':
                    attributes.textMode = attr.AttributeValue;
                    break;
                case 'ReadOnly':
                    attributes.readOnly = attr.AttributeValue === 'true';
                    break;
            }
        });
    }
    
    return attributes;
};
 
export const createComponentProps = (item, index, answers, handleAnswerChange, onDependencyChange, fieldErrors = {}, context = {}) => {
    if (!validateFormItem(item)) {
        console.error('Skipping invalid form item at index:', index);
        return null;
    }
 
    try {
        const itemName = item.Name ? item.Name.trim() : `item_${index}`;
       
        // Debug logging
        if (!context.registerValidationMethod) {
            console.error('componentPropsGenerator: registerValidationMethod is undefined for item:', itemName, item.Type, 'context:', context);
        }

        const baseProps = {
            key: `atlas_${item.Type.toLowerCase()}_${index}`,
            'data-field-name': itemName, // data attribute for scroll-to-error functionality
            label: parseHtmlContent(item.Text || item.Name || `Item ${index}`),
            name: itemName,
            error: !!fieldErrors[itemName],
            helperText: fieldErrors[itemName] || '',
            required: item.Required === 'true' || item.Required === true,
            registerValidationMethod: context.registerValidationMethod,
            
            // Add validation attributes for real-time validation
            validationAttributes: extractValidationAttributes(item),
            
            onChange: (event) => {
                let value;
                
                // Handle different event/value formats from various components
                if (event && typeof event === 'object') {
                    if (event.target) {
                        value = event.target.value;
                    } else if (event.target !== undefined) {
                        value = event.target;
                    } else if (event.value !== undefined) {
                        value = event.value;
                    } else if (event.label !== undefined) {
                        // Handle FAWSelect/Autocomplete option objects
                        value = event.value || event.label;
                    } else if (Array.isArray(event)) {
                        // Handle direct array from FAWMultiSelect: onChange(newValueArray)
                        // FAWMultiSelect passes array directly, not wrapped in event object
                        value = event;
                    } else {
                        value = event;
                    }
                } else if (Array.isArray(event)) {
                    // Handle direct array value (FAWMultiSelect passes array directly)
                    value = event;
                } else {
                    value = event;
                }

               
                if (handleAnswerChange) {
                    handleAnswerChange(itemName, value);
                }

                if (onDependencyChange) {
                    try {
                        onDependencyChange(itemName, value);
                    } catch (error) {
                        console.error('🚨 Error in dependency change handler:', {
                            itemName: itemName,
                            event,
                            error: error.message
                        });
                    }
                }
            },
            sx: {
                marginBottom: 1,
                width: '100%', // Ensure all components have consistent width
                ...getAtlasInputStyles() // Apply consistent FAWInput styling
            }
        };
 
        return generateTypeSpecificProps(item, baseProps, answers, context);
       
    } catch (error) {
        console.error('Error generating props for item:', item?.Name || index, error);
        return {
            key: `atlas_error_${index}`,
            name: item?.Name || `error_item_${index}`,
            label: `Error: ${item?.Text || item?.Name || 'Unknown Item'}`,
            sx: { marginBottom: 2 },
            disabled: true,
            error: true,
            helperText: 'Component configuration error'
        };
    }
};
 
const generateTypeSpecificProps = (item, baseProps, answers, context = {}) => {
    switch (item.Type) {
        case 'TextBox':
        case 'SelfIdentification':
        case 'Relationship':
            return generateTextBoxProps(item, baseProps, answers, context);
            
        case 'ScormQuestionEditor':
            return generateScormProps(item, baseProps, answers, context);
           
        case 'Date':
            return generateDateProps(item, baseProps, answers, context);
           
        case 'MultiInput':
            return generateMultiInputProps(item, baseProps, answers, context);
           
        case 'DropDownList':
        case 'CustomValueSelector':
            return generateDropdownProps(item, baseProps, answers, context);
           
        case 'DropDownMultiSelect':
            return generateMultiSelectProps(item, baseProps, answers, context);
           
        case 'RadioButtonList':
        case 'FAWRadioGroup':
            return generateRadioProps(item, baseProps, answers, context);
           
        case 'CheckBoxList':
            return generateCheckboxGroupProps(item, baseProps, answers, context);
        case 'FAWCheckbox':
            return generateCheckboxProps(item, baseProps, answers, context);
           
        case 'Label':
            return generateLabelProps(item, baseProps, answers, context);
           
        case 'DataGridEntry':
        case 'MatrixQuestion':
            return generateDataGridProps(item, baseProps, answers, context);
           
        case 'Attachment':
            return generateFileUploadProps(item, baseProps, answers, context);
           
        case 'KeyPersonnel':
            return generateKeyPersonnelProps(item, baseProps, answers, context);
           
        case 'PSACompany':
            return generatePSACompanyProps(item, baseProps, answers, context);
           
        case 'CountrySelect':
        case 'RegionCountrySelect':
            return generateCountrySelectProps(item, baseProps, answers, context);
           
        case 'Button':
            return generateButtonProps(item, baseProps, answers, context);
           
        case 'ACL':
            return generateACLProps(item, baseProps, answers, context);
           
        case 'FormLogin':
        case 'FormLoginPage':
            return generateLabelProps(item, baseProps, answers, context);
           
        default:
            console.warn(`⚠️ Unsupported form type: ${item.Type}`, {
                item,
                index: baseProps.key,
                availableTypes: ['TextBox', 'Date', 'MultiInput', 'DropDownList', 'RadioButtonList', 'CheckBoxList', 'Label', 'DataGridEntry', 'Attachment', 'KeyPersonnel', 'PSACompany', 'CountrySelect', 'Button', 'ACL']
            });
            return {
                ...baseProps,
                type: 'text',
                placeholder: 'Enter value...',
                defaultText: 'Enter value...',
                defaultValue: safeGetAnswer(item, '', answers)
            };
    }
};
 
