import React from "react";
import { FormControl, FormGroup, FormControlLabel, Checkbox, FormLabel, Box } from "@mui/material";
import FAWTypography from './FAWTypography';
import RequiredIndicator from './RequiredIndicator';
import { colors } from "../../utils/designTokens";

const FAWCheckboxGroup = React.memo(({
  id,
  name,
  label,
  options = [],
  value, // Expects an array of selected values (controlled)
  defaultValue = [], // Expects an array of selected values (uncontrolled)
  onChange,
  row = false,
  sx,
  labelStyle,
  required,
  ...rest
}) => {
  // Determine if component is controlled (value prop provided) or uncontrolled
  const isControlled = value !== undefined;
  const [internalSelectedValues, setInternalSelectedValues] = React.useState(defaultValue);

  // Use controlled value if provided, otherwise use internal state
  const selectedValues = isControlled ? value : internalSelectedValues;

  // Only update internal state if uncontrolled and defaultValue changes
  React.useEffect(() => {
    if (!isControlled && JSON.stringify(defaultValue) !== JSON.stringify(internalSelectedValues)) {
      setInternalSelectedValues(defaultValue);
    }
  }, [defaultValue, isControlled]);

  const handleChange = (event) => {
    const { value: optionValue, checked } = event.target;
    let newSelectedValues;

    if (checked) {
      newSelectedValues = [...selectedValues, optionValue];
    } else {
      newSelectedValues = selectedValues.filter((v) => v !== optionValue);
    }

    // Only update internal state if uncontrolled
    if (!isControlled) {
      setInternalSelectedValues(newSelectedValues);
    }

    if (typeof onChange === "function") {
      // Pass the array of selected values
      onChange(newSelectedValues);
    }
  };

  return (
    <FormControl component="fieldset" sx={sx}>
      {label && (
        <FormLabel component="legend" sx={{ mb: 1, ...labelStyle }}>
          <FAWTypography variant="body2" sx={{ fontSize: '14px', fontWeight: '600' }}>
            <Box component="span" sx={{ display: 'inline-flex', alignItems: 'baseline' }}>
              {label}
              <RequiredIndicator required={required} />
            </Box>
          </FAWTypography>
        </FormLabel>
      )}
      <FormGroup row={row}>
        {options.map((option, index) => {
          const optionId = `${id || name}_${option.OptionId || option.id || index}`;
          const optionValue = option.OptionValue || option.optionValue || option.value;
          const optionText = option.OptionText || option.optionText || option.label;

          return (
            <FormControlLabel
              key={optionId}
              control={
                <Checkbox
                  id={optionId}
                  name={name}
                  value={optionValue}
                  checked={selectedValues.includes(optionValue)}
                  onChange={handleChange}
                  size="small"
                  sx={{
                    width: 16,
                    height: 16,
                    '& svg': { fontSize: 16 },
                    p: 0,
                  }}
                  {...rest}
                />
              }
              label={
                <FAWTypography
                  variant="body2"
                  sx={{
                    marginLeft: '8px',
                    fontSize: '14px',
                    cursor: 'pointer',
                    userSelect: 'none',
                  }}
                >
                  {optionText}
                </FAWTypography>
              }
              sx={{ marginRight: row ? 2 : 0 }}
            />
          );
        })}
      </FormGroup>
    </FormControl>
  );
});

export default FAWCheckboxGroup;
