import React, { useMemo, useEffect, useState } from "react";
import { findIndex, orderBy, template } from "lodash";
import update from "immutability-helper";
import axios from "axios";
import parse from "html-react-parser";
import DOMPurify from "dompurify";
import PSACompanyTable from "./PSACompanyTable";
import { questionIds, defaultQuestionText, defaultGeneralInfo, displayText } from "./constants";
import FAWModal from "../../../component-widget/FAWModal";
import FAWInput from "../../../component-widget/FAWInput";
import FAWSelect from "../../../component-widget/FAWSelect";
import FAWButton from "../../../component-widget/FAWButton";
import FAWTypography from "../../../component-widget/FAWTypography";
import FAWLoader from "../../../component-widget/FAWLoader";
import FAWThemeProvider from "../../../Theme/FAWThemeProvider";
import FAWToast from "../../../component-widget/FAWToast";
import FAWConfirmDialogue from "../../../component-widget/FAWConfirmDialogue";
import FAWSkeleton from "../../../component-widget/FAWSkeleton";
import Box from '@mui/material/Box';
import Stack from '@mui/material/Stack';
import Dialog from '@mui/material/Dialog';
import DialogActions from '@mui/material/DialogActions';
import DialogContent from '@mui/material/DialogContent';
import DialogTitle from '@mui/material/DialogTitle';
import InputAdornment from '@mui/material/InputAdornment';
import AddIcon from '@mui/icons-material/Add';

// Initial form data for reset functionality
const INITIAL_DATA = {
    Name: '',
    Relationship: '',
    Address: '',
    RegCountry: '',
    RegNum: '',
    ContactName: '',
    Phone: '',
    PercentOwnership: 0,
    AdditionalInfo: ''
};

function PSACompany(props) {
    const [data, setData] = useState([]);
    const [trans, setTrans] = useState([]);
    const [show, setShow] = useState(false);
    const [edit, setEdit] = useState(0);
    const [options, setOptions] = useState([]);
    const [formData, setFormData] = useState(INITIAL_DATA);
    const [errors, setErrors] = useState({});
    const [initFetch, setInitFetch] = useState(true);
    const [saving, setSaving] = useState(false);
    const [toast, setToast] = useState({ open: false, message: '', type: 'info' });
    const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
    const [itemToDelete, setItemToDelete] = useState(null);
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        const fetchPSACompanies = async () => {
            try {
                setLoading(true);
                const { data } = await axios.get("/Questionnaire/LoadPSACompanies");

                const { Companies, Translations } = data;
                setData(Companies);
                setTrans(Translations);
                setInitFetch(false);
            } catch (error) {
                console.error('Error loading PSA Companies:', error);
                showToast('Failed to load PSA Companies data. Please try again.', 'error');
            } finally {
                setLoading(false);
            }
        };

        fetchPSACompanies();
    }, []);

    // Register validation method for form validation
    useEffect(() => {
        if (props.registerValidationMethod) {
            props.registerValidationMethod('PSACompany', () => {
                // Only validate if the field is required
                if (props.required && (!data || data.length === 0)) {
                    return {
                        field: 'psaCompany',
                        message: "Parent, Subsidiary & Affiliated Company requires at least one entry. Please add data to continue."
                    };
                }
                // Return null if validation passes (no error)
                return null;
            });
        }
    }, [data, props.registerValidationMethod, props.required]);

    const html = html => {
        return parse(DOMPurify.sanitize(html, { ADD_ATTR: ["target"] }));
    };

    const findGeneralInfo = (id) => {
        if (trans) {
            const question = trans.find(x => x.QuestionId === id);
            return question ? question.GeneralInfo : defaultGeneralInfo[id];
        }

        return defaultGeneralInfo[id];
    }

    const findText = id => {
        if (trans) {
            const question = trans.find(x => x.QuestionId === id);
            return question ? question.LabelText : defaultQuestionText[id];
        }

        return defaultQuestionText[id];
    };

    const resetForm = () => {
        setFormData(INITIAL_DATA);
        setErrors({});
    };

    const showToast = (message, type = 'info') => {
        setToast({ open: true, message, type });
    };

    const handleToastClose = () => {
        setToast(prev => ({ ...prev, open: false }));
    };

    const toggleShow = () => {
        setEdit(0);
        setShow(c => !c);
        // Reset form and clear errors when opening modal
        if (!show) {
            resetForm();
        }
    };

    // Show delete confirmation dialog
    const handleDeleteClick = (rowNumber) => {
        const company = data.find(item => item.Row === rowNumber);
        const companyName = company?.Name || 'this entry';
        
        setItemToDelete({ rowNumber, companyName });
        setDeleteConfirmOpen(true);
    };

    // Confirm delete action
    const handleDeleteConfirm = async () => {
        if (!itemToDelete) return;
        
        setSaving(true);
        try {
            await axios.post("/Questionnaire/DeletePSACompany", { rowNumber: itemToDelete.rowNumber });
            setData(c => c.filter(r => r.Row !== itemToDelete.rowNumber));
            showToast('PSA Company deleted successfully!', 'success');
            setDeleteConfirmOpen(false);
            setItemToDelete(null);
        } catch (error) {
            console.error('Error deleting PSA Company:', error);
            showToast('Failed to delete PSA Company. Please try again.', 'error');
        } finally {
            setSaving(false);
        }
    };

    // Cancel delete action
    const handleDeleteCancel = () => {
        setDeleteConfirmOpen(false);
        setItemToDelete(null);
    };

    const deletePSACompany = async rowNumber => {
        setSaving(true);
        try {
            await axios.post("/Questionnaire/DeletePSACompany", { rowNumber });
            setData(c => c.filter(r => r.Row !== rowNumber));
            showToast('PSA Company deleted successfully!', 'success');
        } catch (error) {
            console.error('Error deleting PSA Company:', error);
            showToast('Failed to delete PSA Company. Please try again.', 'error');
        } finally {
            setSaving(false);
        }
    };

    const validatePercentage = value => {
        // Check if value is empty - for PSACompany, percentage should be required
        if (value === '' || value === null || value === undefined) {
            return "Percentage is required";
        }

        // Check if value is a valid number
        if (isNaN(value)) {
            return "The percentage must be a valid number";
        }

        const numValue = Number(value);
        
        // Check if value is within valid range
        if (numValue < 0 || numValue > 100) {
            return "Percentage must be between 0% and 100%";
        }

        // Calculate total percentage across all entries (excluding current edit)
        let totalPercentage = 0;
        data.forEach(d => {
            if (edit !== d.Row) {
                totalPercentage += Number(d.PercentOwnership) || 0;
            }
        });
        // Add the current value being validated
        totalPercentage += numValue;

        // Check if total exceeds 100%
        if (totalPercentage > 100) {
            let compiledInfo = template(findGeneralInfo(displayText.OwnershipPercentValidation));
            return compiledInfo({ totalPercentage: totalPercentage });
        }
        
        return null; // No validation error
    };

    const validateForm = () => {
        const newErrors = {};
        
        // Required field validations
        if (!formData.Name || !formData.Name.trim()) {
            newErrors.Name = true;
        }
        if (!formData.Relationship || !formData.Relationship.trim()) {
            newErrors.Relationship = true;
        }
        if (!formData.Address || !formData.Address.trim()) {
            newErrors.Address = true;
        }
        if (!formData.RegCountry || !formData.RegCountry.trim()) {
            newErrors.RegCountry = true;
        }
        if (!formData.RegNum || !formData.RegNum.trim()) {
            newErrors.RegNum = true;
        }
        if (!formData.ContactName || !formData.ContactName.trim()) {
            newErrors.ContactName = true;
        }
        if (!formData.Phone || !formData.Phone.trim()) {
            newErrors.Phone = true;
        }
        const percentError = validatePercentage(formData.PercentOwnership);
        if (percentError) {
            newErrors.PercentOwnership = percentError;
        }
        
        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    const handleFieldChange = (field, value) => {
        setFormData(prev => ({ ...prev, [field]: value }));
        
        // Clear error when user starts typing
        if (errors[field]) {
            setErrors(prev => ({ ...prev, [field]: null }));
        }
        
        // Real-time validation for percentage field
        if (field === 'PercentOwnership') {
            const percentError = validatePercentage(value);
            if (percentError) {
                setErrors(prev => ({ ...prev, PercentOwnership: percentError }));
            } else {
                setErrors(prev => ({ ...prev, PercentOwnership: null }));
            }
        }
    };

    const submitModal = async () => {
        if (!validateForm()) {
            return;
        }
        
        setSaving(true);
        try {
            const psaCompany = {
                ...formData,
                Row: edit
            };

            const res = await axios.post("/Questionnaire/AddPSACompany", psaCompany);

            if (edit === 0) {
                setData(c => update(c, { $push: res.data }));
                showToast('PSA Company created successfully!', 'success');
            } else {
                setData(c =>
                    update(c, { [findIndex(c, { Row: edit })]: { $set: psaCompany } })
                );
                showToast('PSA Company updated successfully!', 'success');
            }

            toggleShow();
            resetForm(); // Reset form after successful submission
        } catch (error) {
            console.error('Error saving PSA Company:', error);
            showToast('Failed to save PSA Company. Please try again.', 'error');
        } finally {
            setSaving(false);
        }
    };

    const toggleEdit = rowNumber => {
        setEdit(rowNumber);
        if (rowNumber > 0) {
            // Editing existing record
            const existingData = data.find(d => d.Row === rowNumber);
            if (existingData) {
                setFormData({
                    Name: existingData.Name || '',
                    Relationship: existingData.Relationship || '',
                    Address: existingData.Address || '',
                    RegCountry: existingData.RegCountry || '',
                    RegNum: existingData.RegNum || '',
                    ContactName: existingData.ContactName || '',
                    Phone: existingData.Phone || '',
                    PercentOwnership: existingData.PercentOwnership || 0,
                    AdditionalInfo: existingData.AdditionalInfo || ''
                });
            }
        } else {
            // Adding new record
            resetForm();
        }
        setShow(true);
    };



    useEffect(() => {
        const fetchRefCodes = async () => {
            const { data } = await axios.get(
                `/Questionnaire/GetRefCodes?domain=Country`
            );

            const opts = [{ Code: "", Meaning: "" }, ...data];
            const ordered = orderBy(opts, opt => opt.Meaning);

            setOptions(ordered);
        };

        fetchRefCodes();
    }, []);

    const columns = useMemo(
        () => [
            {
                id: "PSA Companies",
                Header: "",
                sortable: false,
                columns: [
                    {
                        Header: findText(displayText.PSATableHeaderCompany),
                        accessor: "Name"
                    },
                    {
                        Header: findText(displayText.PSATableHeaderRelationship),
                        accessor: "Relationship"
                    },
                    {
                        Header: findText(displayText.PSATableHeaderAddress),
                        accessor: "Address"
                    },
                    {
                        Header: findText(displayText.PSATableHeaderCountry),
                        accessor: "RegCountry"
                    },
                    {
                        Header: findText(displayText.PSATableHeaderRegistration),
                        accessor: "RegNum"
                    },
                    {
                        Header: findText(displayText.PSATableHeaderContact),
                        accessor: "ContactName"
                    },
                    {
                        Header: findText(displayText.PSATableHeaderTelephone),
                        accessor: "Phone"
                    },
                    {
                        Header: findText(displayText.PSATableHeaderOwnership),
                        accessor: "PercentOwnership",
                        Cell: ({ cell: { value } }) => {
                            return `${value}%`;
                        }
                    },
                    {
                        Header: findText(displayText.PSATableHeaderAdditional),
                        accessor: "AdditionalInfo"
                    }
                ]
            }
        ],
        [trans]
    );


    return (
        <FAWThemeProvider>
            <Box sx={{ px: 5, pt: 2, width: '100%', position: 'relative' }}>
                <Dialog open={show} onClose={toggleShow} fullWidth maxWidth="md">
                <DialogTitle>
                    {html(findText(displayText.PSATableParent2Title))}
                </DialogTitle>
                <DialogContent>
                    <Box component="form" id="psa-company-form" sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
                        <FAWInput
                            label={findText(displayText.PSATableHeaderCompany)}
                            placeholder={findText(displayText.PSATableHeaderCompany)}
                            value={formData.Name}
                            onChange={(e) => handleFieldChange("Name", e.target.value)}
                            error={!!errors.Name}
                            helperText={errors.Name && findText(displayText.RequiredFieldMessage)}
                            required={true}
                            fullWidth
                        />
                        <FAWInput
                            label={findText(displayText.PSATableHeaderRelationship)}
                            placeholder={findText(displayText.PSATableHeaderRelationship)}
                            value={formData.Relationship}
                            onChange={(e) => handleFieldChange("Relationship", e.target.value)}
                            error={!!errors.Relationship}
                            helperText={errors.Relationship && findText(displayText.RequiredFieldMessage)}
                            required={true}
                            fullWidth
                        />
                        <FAWInput
                            label={findText(displayText.PSATableHeaderAddress)}
                            placeholder={findText(displayText.PSATableHeaderAddress)}
                            value={formData.Address}
                            onChange={(e) => handleFieldChange("Address", e.target.value)}
                            error={!!errors.Address}
                            helperText={errors.Address && findText(displayText.RequiredFieldMessage)}
                            fullWidth
                        />
                        <FAWSelect
                            label={findText(displayText.PSATableHeaderCountry)}
                            value={formData.RegCountry}
                            onChange={(selectedOption, event) => handleFieldChange("RegCountry", selectedOption?.value || "")}
                            error={!!errors.RegCountry}
                            helperText={errors.RegCountry && findText(displayText.RequiredFieldMessage)}
                            options={options.map(refCode => ({
                                value: refCode.Code,
                                label: refCode.Meaning
                            }))}
                            fullWidth
                        />
                        <FAWInput
                            label={findText(displayText.PSATableHeaderRegistration)}
                            placeholder={findText(displayText.PSATableHeaderRegistration)}
                            value={formData.RegNum}
                            onChange={(e) => handleFieldChange("RegNum", e.target.value)}
                            error={!!errors.RegNum}
                            helperText={errors.RegNum && findText(displayText.RequiredFieldMessage)}
                            fullWidth
                        />
                        <FAWInput
                            label={findText(displayText.PSATableHeaderContact)}
                            placeholder={findText(displayText.PSATableHeaderContact)}
                            value={formData.ContactName}
                            onChange={(e) => handleFieldChange("ContactName", e.target.value)}
                            error={!!errors.ContactName}
                            helperText={errors.ContactName && findText(displayText.RequiredFieldMessage)}
                            fullWidth
                        />
                        <FAWInput
                            label={findText(displayText.PSATableHeaderTelephone)}
                            placeholder={findText(displayText.PSATableHeaderTelephone)}
                            value={formData.Phone}
                            onChange={(e) => handleFieldChange("Phone", e.target.value)}
                            error={!!errors.Phone}
                            helperText={errors.Phone && findText(displayText.RequiredFieldMessage)}
                            fullWidth
                        />
                        <FAWInput
                            label={findText(displayText.PSATableHeaderPercentage)}
                            type="number"
                            placeholder={findText(displayText.PSATableHeaderPercentage)}
                            value={formData.PercentOwnership}
                            onChange={(e) => {
                                const inputValue = e.target.value;
                                // Allow empty string for user to clear field
                                if (inputValue === '') {
                                    handleFieldChange("PercentOwnership", '');
                                } else {
                                    const numValue = parseFloat(inputValue);
                                    // Only update if it's a valid number or empty
                                    if (!isNaN(numValue) || inputValue === '') {
                                        handleFieldChange("PercentOwnership", numValue);
                                    }
                                }
                            }}
                            error={!!errors.PercentOwnership}
                            helperText={errors.PercentOwnership}
                            InputProps={{
                                endAdornment: <InputAdornment position="end">%</InputAdornment>,
                                inputProps: {
                                    min: 0,
                                    max: 100,
                                    step: 0.01
                                }
                            }}
                            fullWidth
                        />
                        <FAWInput
                            label={findText(displayText.PSATableHeaderAdditional)}
                            placeholder={findText(displayText.PSATableHeaderAdditional)}
                            value={formData.AdditionalInfo || ''}
                            onChange={(e) => handleFieldChange("AdditionalInfo", e.target.value)}
                            error={!!errors.AdditionalInfo}
                            helperText={errors.AdditionalInfo && findText(displayText.RequiredFieldMessage)}
                            fullWidth
                        />
                    </Box>
                </DialogContent>
                <DialogActions sx={{ justifyContent: 'space-between', px: 3, py: 2 }}>
                    <FAWButton variant="outlined" color="inherit" onClick={toggleShow}>
                        {findText(displayText.Close)}
                    </FAWButton>
                    <FAWButton 
                        variant="contained" 
                        color="primary" 
                        onClick={submitModal}
                        disabled={saving}
                    >
                        {saving ? (
                            <FAWLoader size={20} />
                        ) : (
                            findText(displayText.Save)
                        )}
                    </FAWButton>
                </DialogActions>
            </Dialog>
            <Box sx={{ 
                display: 'flex', 
                justifyContent: 'space-between', 
                alignItems: 'center', 
                mb: 2,
                p: 2,
                border: '1px solid #e0e0e0',
                borderRadius: 1,
                backgroundColor: '#fafafa'
            }}>
                <FAWTypography 
                    variant="h6"
                    sx={{ 
                        color: 'rgb(37, 68, 96)', 
                        fontSize: '18px',
                        fontWeight: 600
                    }}
                >
                    {html(findText(displayText.PSATableTitle))}
                </FAWTypography>
                <FAWButton variant="contained" color="primary" onClick={toggleShow} startIcon={<AddIcon size="small" />}>
                    {findText(displayText.PSATableClickHereButton)}
                </FAWButton>
            </Box>
            
            {loading ? (
                <FAWSkeleton variant="table" />
            ) : columns && (
                <div style={{ width: '100%', marginBottom: '24px' }}>
                    <PSACompanyTable
                        data={data}
                        columns={columns}
                        onEdit={toggleEdit}
                        onDelete={handleDeleteClick}
                    />
                </div>
            )}
        </Box>
        
        {/* Toast notifications */}
        <FAWToast
            open={toast.open}
            message={toast.message}
            type={toast.type}
            onClose={handleToastClose}
        />

        {/* Delete Confirmation Dialog */}
        <FAWConfirmDialogue
            open={deleteConfirmOpen}
            onClose={handleDeleteCancel}
            onConfirm={handleDeleteConfirm}
            variant="delete"
            title="Confirm Delete"
            message={`Are you sure you want to delete this PSA Company entry ${itemToDelete?.companyName || ''}?`}
            description=""
        />
        </FAWThemeProvider>
    );
}

PSACompany.propTypes = {};

export default PSACompany;